INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Estructura Atómica Tarea', '<p><strong style=\"text-align: initial;\" data-start=\"144\" data-end=\"168\">Lección 1: Estructura Atómica</strong></p>\r\n<p>En esta sección exploraremos los fundamentos de la estructura atómica, incluyendo las partículas subatómicas, el número atómico y másico, así como los conceptos de isótopos e iones. También analizaremos los diferentes modelos atómicos a lo largo de la historia.</p>\r\n<p><strong>Investigar Estas Preguntas:</strong></p>\r\n<ul>\r\n<li> ¿Qué características tienen los protones, neutrones y electrones?</li>\r\n<li>¿Cómo se calcula el número atómico y el número másico?</li>\r\n<li>¿Qué diferencia hay entre un isótopo y un ion?</li>\r\n<li>¿Cuáles son los principales modelos atómicos y cómo han evolucionado?</li>\r\n</ul>\r\n<p>Valor: 2 Puntos</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Enviar Capturas de Pantalla', '<p><strong>Construye tu propio átomo:</strong></p>\r\n<p>Utilizando el simulador de <strong data-start=\"192\" data-end=\"200\">PhET</strong>, crea al menos <strong data-start=\"216\" data-end=\"243\">cinco átomos diferentes</strong>, asegurándote de asignar correctamente el número de <strong data-start=\"296\" data-end=\"332\">protones, neutrones y electrones</strong>. Además, explica la composición de cada uno y justifica tus elecciones.</p>\r\n<p><strong>A terminar Sus Practicas Enviar:</strong></p>\r\n<p>✅ Capturas de pantalla de cada átomo creado en el simulador.<br data-start=\"469\" data-end=\"472\">✅ Un breve documento explicativo donde describas la estructura de cada átomo y razones tus elecciones.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Ley Universal de Conservación de Energía:', '<p data-start=\"436\" data-end=\"493\"><strong data-start=\"436\" data-end=\"491\">Para profundizar en estos temas, puedes investigar:</strong></p>\r\n<ul data-start=\"494\" data-end=\"747\">\r\n<li class=\"\" data-start=\"417\" data-end=\"474\">\r\n<p data-start=\"420\" data-end=\"474\" class=\"\">¿En qué consiste la Ley de Conservación de la Energía?</p>\r\n</li>\r\n<li class=\"\" data-start=\"475\" data-end=\"520\">\r\n<p data-start=\"478\" data-end=\"520\" class=\"\">¿Por qué se considera una \"ley universal\"?</p>\r\n</li>\r\n<li class=\"\" data-start=\"521\" data-end=\"594\">\r\n<p data-start=\"524\" data-end=\"594\" class=\"\">¿Quiénes fueron los científicos que contribuyeron a formular esta ley?</p>\r\n</li>\r\n<li class=\"\" data-start=\"2018\" data-end=\"2042\">\r\n<p data-start=\"2020\" data-end=\"2042\" class=\"\">Ejemplos cotidianos.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2043\" data-end=\"2064\">\r\n<p data-start=\"2045\" data-end=\"2064\" class=\"\">Tipos de energía.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Concepto de Iones y Ley de Cargas', '<h4><strong data-start=\"130\" data-end=\"160\">Para profundizar en estos temas, puedes investigar:</strong></h4>\r\n<ul>\r\n<li data-start=\"127\" data-end=\"160\">¿Cómo se forman los iones?</li>\r\n<li data-start=\"161\" data-end=\"197\">¿Qué es un catión y un anión?</li>\r\n<li data-start=\"198\" data-end=\"243\">¿Qué dice la Ley de Cargas Eléctricas?</li>\r\n<li data-start=\"244\" data-end=\"295\">¿Cómo interactúan las cargas de igual signo?</li>\r\n<li data-start=\"296\" data-end=\"349\">¿Cómo interactúan las cargas de signo opuesto?</li>\r\n<li data-start=\"350\" data-end=\"413\">¿Qué es la conductividad iónica y por qué es importante?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Lección 6: Conductores Eléctricos', '<h4><strong>Investigar Las Siguientes Preguntas:</strong></h4>\r\n<ul>\r\n<li data-start=\"106\" data-end=\"146\">¿Qué es un conductor eléctrico?</li>\r\n<li data-start=\"147\" data-end=\"230\">¿Cuáles son las principales características de los conductores eléctricos?</li>\r\n<li data-start=\"231\" data-end=\"318\">¿Qué relación existe entre la estructura cristalina y la conducción eléctrica?</li>\r\n<li data-start=\"319\" data-end=\"397\">¿Qué son los electrones libres y qué papel juegan en los conductores?</li>\r\n<li data-start=\"398\" data-end=\"474\">¿Cuáles son los metales más utilizados como conductores eléctricos?</li>\r\n<li data-start=\"475\" data-end=\"571\">¿Qué ventajas tienen las aleaciones sobre los metales puros en aplicaciones eléctricas?</li>\r\n<li data-start=\"572\" data-end=\"653\">¿Qué es la resistividad y cómo influye en la eficiencia de un conductor?</li>\r\n<li data-start=\"654\" data-end=\"726\">Menciona una aplicación práctica de los conductores eléctricos.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea de Sistemas de Unidades de Medida', '<ul>\r\n<li data-start=\"77\" data-end=\"151\">¿Qué es un sistema de unidades de medida y por qué es importante?</li>\r\n<li data-start=\"152\" data-end=\"229\">¿Cuáles son las principales unidades del Sistema Internacional (SI)?</li>\r\n<li data-start=\"230\" data-end=\"305\">¿En qué se diferencian los sistemas MKS, CGS y el sistema técnico?</li>\r\n<li data-start=\"306\" data-end=\"384\">¿Cómo se realizan conversiones entre diferentes sistemas de unidades?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 1: Conversiones de Unidades', '<p><strong>Objetivo:</strong> Resolver ejercicios de conversión entre sistemas y múltiplos/submúltiplos.</p>\r\n<p><strong>Entregable:</strong> Documento con soluciones detalladas.<br> </p>\r\n<p><strong>Ejercicios Actualizados:</strong></p>\r\n<ol>\r\n<li> Convertir 2.5 mA a μA.</li>\r\n<li>Expresar 4700 Ω en kΩ.</li>\r\n<li>Convertir 0.025 MV a V.</li>\r\n<li> Calcular la energía (en Joules) que consume una resistencia disipada a 0.5 W durante 2 horas.</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 2: Instrumentos de Medición', '<p><strong>Objetivo:</strong> Analizar y comparar diferentes instrumentos de medición eléctrica y<br>sus aplicaciones.</p>\r\n<p><strong>Entregable:</strong> Informe técnico (3–5 páginas).<br> </p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Actividad Colaborativa-Grupal 3: Mapa Mental', '<p><strong>Objetivo: </strong>Crear un mapa mental (usando Mindomo) sobre las magnitudes eléctricas y sus interrelaciones.</p>\r\n<p><strong>Entregable:</strong> Enlace al mapa mental y documento explicativo.</p>\r\n<ul>\r\n<li><strong>Evaluación:</strong> Estructura (25%), contenido técnico (35%), conexiones (25%) y diseño visual (15%).</li>\r\n<li><strong>Valor:</strong> 40% del módulo.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: 5: Análisis de Circuitos', '<p><strong>Objetivo:</strong> Resolver problemas de circuitos en serie, paralelo y mixtos.</p>\r\n<p><strong>Entregable:</strong> Documento con diagramas, cálculos y explicaciones.</p>\r\n<p></p>\r\n<p><strong>Ejemplos Actualizados:</strong></p>\r\n<p><br>1. Calcular la resistencia equivalente de tres resistencias en serie:<br>220 Ω, 470 Ω y 1 kΩ.<br>2. En un circuito paralelo con resistencias de 100 Ω, 200 Ω y 300 Ω,<br>determinar la corriente para 12 V.<br>3. Simplificar un circuito mixto y calcular la corriente total.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 1: Análisis de Circuitos con Condensadores', '<p><strong>Objetivo:</strong> Resolver ejercicios de carga/descarga y cálculos en circuitos RC.</p>\r\n<p></p>\r\n<p><strong>Entregable:</strong> Informe técnico con simulaciones y cálculos.</p>\r\n<p></p>\r\n<p><strong>Ejercicios Actualizados:</strong></p>\r\n<ol>\r\n<li> Calcular la constante de tiempo (τ) de un condensador de 100 μF con<br>una resistencia de 10 kΩ.</li>\r\n<li>Determinar la capacidad equivalente de tres condensadores (10 μF, 22<br>μF y 47 μF) en serie.<br>3. Diseñar un circuito RC que genere un retardo de 1 segundo.</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Examen Final (PRESENCIAL) no hacer', '<p><strong>Opciones de Proyecto:</strong></p>\r\n<p><strong>Fuente de alimentación regulada.<br>■ Sistema de iluminación automatizado.<br>■ Detector de nivel con alarma.<br>■ Temporizador electrónico.<br>■ Proyecto alternativo (previa aprobación).</strong></p>\r\n<p><strong>Entregables:<br>■ Memoria técnica (documento PDF).<br>■ Esquema del circuito.<br>■ Simulación (Proteus o Tinkercad).<br>■ Video demostrativo (5–7 minutos).<br>■ Presentación final.</strong></p>\r\n<p><strong>Evaluación:<br>■ Funcionamiento (30%),<br>■ Diseño y construcción (25%),<br>■ Documentación técnica (20%),<br>■ Presentación y video (15%),<br>■ Originalidad e innovación (10%).<br></strong></p>\r\n<p><strong>Valor: 70% del módulo.</strong></p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 2: Clasificación de los Diodos', '<p><strong>Objetivo:</strong> Investigar y clasificar al menos 6 tipos de diodos, detallando características y aplicaciones.</p>\r\n<p></p>\r\n<p><strong>Entregable</strong>: Informe técnic</p>\r\n<p></p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Aislantes Eléctricos', '<h4><strong>Investigar Las Siguientes Preguntas:</strong></h4>\r\n<ul>\r\n<li data-start=\"145\" data-end=\"229\">¿Qué es un aislante eléctrico y cuáles son sus principales características?</li>\r\n<li data-start=\"230\" data-end=\"305\">¿Cómo funcionan las bandas de energía en los materiales aislantes?</li>\r\n<li data-start=\"306\" data-end=\"388\">¿Cuáles son los materiales aislantes más comunes y en qué se diferencian?</li>\r\n<li data-start=\"389\" data-end=\"503\">¿Cuáles son las principales aplicaciones de los materiales aislantes en la industria y la vida cotidiana?</li>\r\n<li data-start=\"504\" data-end=\"600\">¿Qué es la rigidez dieléctrica y cómo influye en el desempeño de un aislante eléctrico?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Semiconductores', '<h3><strong>Investigar Las Siguientes Preguntas:</strong></h3>\r\n<ul data-start=\"715\" data-end=\"903\">\r\n<li data-start=\"86\" data-end=\"175\">¿Qué son los semiconductores intrínsecos y extrínsecos, y en qué se diferencian?</li>\r\n<li data-start=\"176\" data-end=\"246\">¿Cómo funcionan las bandas de energía en los semiconductores?</li>\r\n<li data-start=\"247\" data-end=\"343\">¿Qué es el dopaje en los semiconductores y cuál es la diferencia entre los tipos N y P?</li>\r\n<li data-start=\"344\" data-end=\"443\">¿Cuáles son las principales aplicaciones de los semiconductores en la electrónica moderna?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Estructura y Resistividad de los Materiales', '<h3><strong>Investigar Las Siguientes Preguntas:</strong></h3>\r\n<ul data-start=\"715\" data-end=\"903\">\r\n<li data-start=\"106\" data-end=\"196\">¿Cómo influye la estructura atómica en las propiedades eléctricas de un material?</li>\r\n<li data-start=\"197\" data-end=\"306\">¿Cuáles son los factores que afectan la resistividad eléctrica, como la temperatura y las impurezas?</li>\r\n<li data-start=\"307\" data-end=\"391\">¿Qué son los superconductores y cuáles son sus principales características?</li>\r\n<li data-start=\"392\" data-end=\"472\">¿Qué técnicas se utilizan para medir la resistividad de los materiales?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Magnitudes Eléctricas Fundamentales', '<ul>\r\n<li data-start=\"91\" data-end=\"220\">¿Qué es un multímetro digital y cómo se utiliza en la medición de corriente (amperio), tensión (voltio) y resistencia (ohmio)?</li>\r\n<li data-start=\"221\" data-end=\"343\">¿Cómo funciona un osciloscopio y qué tipo de señales permite analizar en relación con corriente, tensión y resistencia?</li>\r\n<li data-start=\"344\" data-end=\"440\">¿Cuál es la función de un vatímetro y cómo mide la potencia eléctrica (vatio) en un circuito?</li>\r\n<li data-start=\"441\" data-end=\"554\">¿Para qué se utiliza un medidor de energía (joule, kWh) y cómo determina el consumo energético en un circuito?</li>\r\n<li data-start=\"555\" data-end=\"688\">¿Qué mide un medidor LCR y cuál es su importancia en la caracterización de componentes eléctricos como capacitancia e inductancia?</li>\r\n<li data-start=\"689\" data-end=\"874\">¿Cuáles son las principales técnicas de medición en circuitos eléctricos y cómo se pueden minimizar los errores en la medición de corriente, tensión, resistencia, potencia y energía?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Múltiplos y Submúltiplos', '<ul>\r\n<li data-start=\"68\" data-end=\"152\">¿Qué son los prefijos del Sistema Internacional (SI) y por qué se utilizan?</li>\r\n<li data-start=\"153\" data-end=\"256\">¿Cuáles son los principales prefijos del SI, desde nano hasta giga, y qué valores representan?</li>\r\n<li data-start=\"257\" data-end=\"369\">¿Qué es la notación científica y cómo facilita la representación de números muy grandes o muy pequeños?</li>\r\n<li data-start=\"370\" data-end=\"465\">¿Cómo se realizan conversiones entre diferentes prefijos del SI y notación científica?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: Ley de Ohm', '<ul>\r\n<li data-start=\"61\" data-end=\"181\">¿Qué establece la Ley de Ohm y cómo se relacionan la corriente, el voltaje y la resistencia en un circuito eléctrico?</li>\r\n<li data-start=\"182\" data-end=\"298\">¿Cómo varía la corriente en un circuito si se aumenta el voltaje o se cambia la resistencia, según la Ley de Ohm?</li>\r\n<li data-start=\"299\" data-end=\"400\">¿Cuáles son las aplicaciones prácticas de la Ley de Ohm en dispositivos eléctricos y electrónicos?</li>\r\n<li data-start=\"401\" data-end=\"523\">¿Qué limitaciones tiene la Ley de Ohm cuando se trata de materiales no ohmicos o circuitos con componentes no lineales?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Práctica: Mediciones con Multímetro', '<p><strong>Laboratorio Virtual: \"Mediciones con Multímetro\"</strong></p>\r\n<ul>\r\n<li>Realización de mediciones virtuales (voltaje,corriente y resistencia) en circuitos simulados.</li>\r\n</ul>\r\n<p></p>\r\n<p><strong>Entregable</strong>: Informe de laboratorio con resultados, cálculos y análisis.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: Circuitos en Serie y Paralelo', '<ul>\r\n<li data-start=\"120\" data-end=\"215\">¿Qué son los circuitos en serie y en paralelo, y cuáles son sus principales características?</li>\r\n<li data-start=\"216\" data-end=\"298\">¿Cómo se dividen la tensión y la corriente en circuitos en serie y en paralelo?</li>\r\n<li data-start=\"299\" data-end=\"381\">¿Cuáles son las ventajas y desventajas de los circuitos en serie y en paralelo?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Resistencia Equivalente', '<ul>\r\n<li data-start=\"429\" data-end=\"514\">¿Cómo se calcula la resistencia equivalente en un circuito en serie y en paralelo?</li>\r\n<li data-start=\"515\" data-end=\"601\">¿Cómo se analiza un circuito mixto que combina resistencias en serie y en paralelo?</li>\r\n<li data-start=\"602\" data-end=\"710\">¿Qué técnicas de simplificación se utilizan para resolver circuitos con resistencias en serie y paralelo?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Circuitos Mixtos Eléctricos', '<ul>\r\n<li data-start=\"1109\" data-end=\"1209\">¿Cómo se realiza el análisis de circuitos mixtos que combinan componentes en serie y en paralelo?</li>\r\n<li data-start=\"1210\" data-end=\"1301\">¿Cuáles son las técnicas de simplificación y resolución paso a paso de circuitos mixtos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Instrumentos de Medida Eléctrica', '<ul>\r\n<li data-start=\"46\" data-end=\"154\">¿Qué es un multímetro digital y cómo se utiliza en la medición de voltaje, corriente y resistencia?</li>\r\n<li data-start=\"155\" data-end=\"234\">¿Cómo funciona un osciloscopio y qué tipo de señales permite analizar?</li>\r\n<li data-start=\"235\" data-end=\"329\">¿Cuál es la función de un vatímetro y cómo mide la potencia eléctrica en un circuito?</li>\r\n<li data-start=\"330\" data-end=\"422\">¿Para qué se utiliza un frecuencímetro y cómo determina la frecuencia de una señal?</li>\r\n<li data-start=\"423\" data-end=\"530\">¿Qué mide un medidor LCR y cuál es su importancia en la caracterización de componentes eléctricos?</li>\r\n<li data-start=\"531\" data-end=\"646\">¿Cuáles son las principales técnicas de medición y cómo se pueden minimizar los errores en los resultados?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: Código de Colores de Resistencias', '<ul>\r\n<li data-start=\"768\" data-end=\"843\">¿Cómo funciona el sistema de codificación por colores para resistencias?</li>\r\n<li data-start=\"844\" data-end=\"936\">¿Cuál es la diferencia entre resistencias de 4, 5 y 6 bandas en cuanto a su codificación?</li>\r\n<li data-start=\"937\" data-end=\"1057\">¿Cómo se determina la tolerancia y el coeficiente de temperatura de una resistencia a partir de su código de colores?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Dispositivos Electrónicos', '<ul>\r\n<li data-start=\"1824\" data-end=\"1899\">¿Cómo se clasifican los dispositivos electrónicos en términos generales?</li>\r\n<li data-start=\"1900\" data-end=\"2024\">¿Cuáles son los circuitos integrados, la optoelectrónica, los sensores y los actuadores, y cómo funcionan en un circuito?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: Elementos Activos', '<ul>\r\n<li>¿Qué son los elementos activos en un circuito eléctrico, como las fuentes de tensión y corriente, generadores y amplificadores?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Elementos Pasivos', '<ul>\r\n<li data-start=\"1567\" data-end=\"1684\">¿Qué son los elementos pasivos en un circuito, como las resistencias, condensadores, inductores y transformadores?</li>\r\n<li data-start=\"1685\" data-end=\"1774\">¿Cómo se comportan los elementos pasivos en circuitos de corriente continua y alterna?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: Los Diodos y sus Aplicaciones', '<ul>\r\n<li data-start=\"2078\" data-end=\"2153\">¿Cómo funcionan los diodos y cómo se representa su curva característica?</li>\r\n<li data-start=\"2154\" data-end=\"2243\">¿Cuál es la diferencia entre los diodos rectificadores y sus aplicaciones más comunes?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Construcción de una Fuente de Alimentación', '<ul>\r\n<li data-start=\"2310\" data-end=\"2447\">¿Cuáles son los componentes esenciales para construir una fuente de alimentación (transformador, rectificador, filtrado y regulación)?</li>\r\n<li data-start=\"2448\" data-end=\"2506\">¿Cómo se diseña paso a paso una fuente de alimentación?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: Los Diodos LED y sus Aplicaciones', '<ul>\r\n<li data-start=\"2564\" data-end=\"2677\">¿Cómo funcionan los diodos LED y qué características deben considerarse al calcular la resistencia limitadora?</li>\r\n<li data-start=\"2678\" data-end=\"2757\">¿Cómo se diseñan y utilizan circuitos con LEDs en aplicaciones electrónicas?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: Los Condensadores-Capacitores y sus Aplicaciones', '<ul>\r\n<li data-start=\"392\" data-end=\"485\">¿Cuál es el principio de funcionamiento de un condensador o capacitor y qué tipos existen?</li>\r\n<li data-start=\"486\" data-end=\"606\">¿Cómo se realiza el proceso de carga y descarga en un condensador, y cómo se aplican estos conceptos en circuitos RC?</li>\r\n<li data-start=\"607\" data-end=\"681\">¿Cómo se calculan las propiedades de los condensadores en circuitos RC?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Los Diodos Zener y sus Aplicaciones', '<ul>\r\n<li data-start=\"139\" data-end=\"217\">¿Cómo funciona un diodo Zener y cómo se representa su curva característica?</li>\r\n<li data-start=\"218\" data-end=\"319\">¿De qué manera los diodos Zener se utilizan en la regulación de tensión en circuitos electrónicos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea:  Interruptores, Conmutadores y Pulsadores', '<ul>\r\n<li data-start=\"808\" data-end=\"924\">¿Cuáles son los tipos de interruptores, conmutadores y pulsadores, y cuáles son sus principios de funcionamiento?</li>\r\n<li data-start=\"925\" data-end=\"1056\">¿Cómo se representa la simbología de interruptores, conmutadores y pulsadores, y qué aplicaciones prácticas tienen en circuitos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Relé o Relevador', '<ul>\r\n<li data-start=\"1097\" data-end=\"1156\">¿Cómo funciona un relé o relevador, y qué tipos existen?</li>\r\n<li data-start=\"1157\" data-end=\"1255\">¿Cuáles son las características eléctricas de un relé y cómo se aplica en circuitos de control?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: De los  Transformadores', '<ul>\r\n<li data-start=\"1332\" data-end=\"1428\">¿Cuál es el principio de inducción electromagnética en el funcionamiento de un transformador?</li>\r\n<li data-start=\"1429\" data-end=\"1550\">¿Cómo se estructura un transformador, y cuál es la relación de transformación entre sus bobinas primaria y secundaria?</li>\r\n<li data-start=\"1551\" data-end=\"1659\">¿Qué tipos de transformadores existen, y cómo afectan las pérdidas y el rendimiento en su funcionamiento?</li>\r\n<li data-start=\"1660\" data-end=\"1748\">¿Cuáles son las aplicaciones prácticas de los transformadores en sistemas eléctricos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 2.1:  Preparación del Substrato Construcción', '<p></p>\r\n<p>Descripción detallada de los materiales semiconductores utilizados y el proceso de fabricación de los transistores.<br><br></p>\r\n<p>Explicación de la estructura de capas de los transistores NPN y PNP.<br><br></p>\r\n<p>Representación gráfica con símbolos y convenciones estándar para los transistores NPN y PNP.<br><br></p>\r\n<p>Esquemas o diagramas ilustrando las distintas etapas del proceso de fabricación y la estructura interna de los transistores.</p>\r\n<p></p>\r\n<p style=\"font-weight: bold;\"><strong>Producto Esperado :</strong></p>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 3.4: Comparación con BJT', '<h3 dir=\"ltr\">Producto Esperado :</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis detallado de las ventajas y desventajas de JFET y MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de las aplicaciones, costos y disponibilidad de ambos tipos de transistores.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre JFET y MOSFET, destacando sus características, aplicaciones y costos.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Campos de Aplicación de la Electrónica', '<p></p>\r\n<p data-start=\"0\" data-end=\"990\" class=\"\">La electrónica es una disciplina fundamental que abarca una amplia gama de aplicaciones que transforman la tecnología y la vida cotidiana. La <strong data-start=\"142\" data-end=\"177\">electrónica analógica y digital</strong> son las bases sobre las cuales se desarrollan los sistemas modernos, desde circuitos básicos hasta complejos procesadores. Por otro lado, la <strong data-start=\"319\" data-end=\"339\">microelectrónica</strong> se enfoca en la fabricación de componentes diminutos que permiten dispositivos de alto rendimiento en áreas como <strong data-start=\"453\" data-end=\"465\">potencia</strong> y <strong data-start=\"468\" data-end=\"487\">optoelectrónica</strong>, esenciales en la creación de productos de consumo y sistemas de comunicación avanzados. En el campo de la <strong data-start=\"595\" data-end=\"607\">robótica</strong>, la electrónica es clave para el diseño de máquinas inteligentes, mientras que en <strong data-start=\"690\" data-end=\"712\">telecomunicaciones</strong> es responsable de la transmisión y recepción de señales a través de diversos medios. Finalmente, la <strong data-start=\"813\" data-end=\"831\">bioelectrónica</strong> ha revolucionado el sector de la salud, desarrollando dispositivos médicos que interactúan con el cuerpo humano para diagnósticos y tratamientos más precisos.</p>\r\n<p data-start=\"992\" data-end=\"1268\" class=\"\">Para profundizar en estos temas, investiga cómo la <strong data-start=\"1043\" data-end=\"1063\">microelectrónica</strong> ha influido en el avance de los teléfonos móviles y dispositivos portátiles, y cómo la <strong data-start=\"1151\" data-end=\"1169\">bioelectrónica</strong> está transformando la medicina moderna a través de nuevos dispositivos de monitoreo y tratamiento.</p>\r\n<p data-start=\"109\" data-end=\"145\" class=\"\"><strong data-start=\"109\" data-end=\"145\">Instrucciones para la Actividad:</strong></p>\r\n<ol data-start=\"147\" data-end=\"2311\">\r\n<li class=\"\" data-start=\"147\" data-end=\"499\">\r\n<p data-start=\"150\" data-end=\"499\" class=\"\"><strong data-start=\"150\" data-end=\"175\">Introducción al Tema:</strong> Lee atentamente el párrafo introductorio sobre los diferentes campos de la electrónica, incluyendo la electrónica analógica y digital, la microelectrónica, la robótica, las telecomunicaciones y la bioelectrónica. Este conocimiento te ayudará a comprender cómo estas disciplinas se aplican en diversas áreas tecnológicas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"501\" data-end=\"1521\">\r\n<p data-start=\"504\" data-end=\"613\" class=\"\"><strong data-start=\"504\" data-end=\"536\">Investigación Personalizada:</strong> Elige uno de los siguientes temas de interés para investigar más a fondo:</p>\r\n<ul data-start=\"621\" data-end=\"1521\">\r\n<li class=\"\" data-start=\"621\" data-end=\"806\">\r\n<p data-start=\"623\" data-end=\"806\" class=\"\"><strong data-start=\"623\" data-end=\"659\">Electrónica Analógica y Digital:</strong> Investiga las diferencias entre ambos tipos de circuitos y cómo se aplican en dispositivos comunes (como radios, televisores, computadoras, etc.).</p>\r\n</li>\r\n<li class=\"\" data-start=\"810\" data-end=\"1029\">\r\n<p data-start=\"812\" data-end=\"1029\" class=\"\"><strong data-start=\"812\" data-end=\"851\">Microelectrónica y Optoelectrónica:</strong> Investiga cómo los avances en microelectrónica han permitido el desarrollo de dispositivos portátiles y qué aplicaciones tiene la optoelectrónica en las comunicaciones modernas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1033\" data-end=\"1156\">\r\n<p data-start=\"1035\" data-end=\"1156\" class=\"\"><strong data-start=\"1035\" data-end=\"1048\">Robótica:</strong> Investiga cómo los circuitos electrónicos se utilizan en la creación de robots y automatización industrial.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1160\" data-end=\"1337\">\r\n<p data-start=\"1162\" data-end=\"1337\" class=\"\"><strong data-start=\"1162\" data-end=\"1185\">Telecomunicaciones:</strong> Investiga cómo la electrónica permite la transmisión de señales de voz y datos a través de diferentes tecnologías (como redes móviles, internet, etc.).</p>\r\n</li>\r\n<li class=\"\" data-start=\"1341\" data-end=\"1521\">\r\n<p data-start=\"1343\" data-end=\"1521\" class=\"\"><strong data-start=\"1343\" data-end=\"1362\">Bioelectrónica:</strong> Investiga cómo los dispositivos electrónicos interactúan con el cuerpo humano en el campo de la medicina, tales como marcapasos o dispositivos de diagnóstico.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1523\" data-end=\"1817\">\r\n<p data-start=\"1526\" data-end=\"1638\" class=\"\"><strong data-start=\"1526\" data-end=\"1550\">Entrega del Informe:</strong> Una vez hayas seleccionado tu tema de investigación, escribe un informe que incluya:</p>\r\n<ul data-start=\"1646\" data-end=\"1817\">\r\n<li class=\"\" data-start=\"1646\" data-end=\"1699\">\r\n<p data-start=\"1648\" data-end=\"1699\" class=\"\">Una breve descripción del tema que has investigado.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1703\" data-end=\"1765\">\r\n<p data-start=\"1705\" data-end=\"1765\" class=\"\">Ejemplos de aplicaciones prácticas actuales en la vida real.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1769\" data-end=\"1813\">\r\n<p data-start=\"1771\" data-end=\"1813\" class=\"\">Avances o tendencias futuras en ese campo.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1818\" data-end=\"2041\">\r\n<p data-start=\"1821\" data-end=\"2041\" class=\"\"><strong data-start=\"1821\" data-end=\"1850\">Presentación de documento:</strong> Prepara un documento donde resumas tu investigación. Incluye imágenes, gráficos o videos relevantes para hacer la presentación más dinámica.</p>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 4.5: Modelos de Operación', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de los modelos de operación del MOSFET (Nivel 1, BSIM, PSP).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de las ecuaciones utilizadas en cada modelo y sus limitaciones.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p><strong id=\"docs-internal-guid-fa8c9657-7fff-46cf-0a09-05925e7efffa\">Análisis de los efectos cuánticos y de alta frecuencia en los modelos avanzados.<br></strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea: 4.6 Comparación con BJT', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación detallada entre MOSFET y BJT en términos de potencia, eficiencia energética, velocidad de conmutación, costos, y aplicaciones específicas.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre MOSFET y BJT, destacando sus principales diferencias y ventajas.<br><br></p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Enviar Capturas de Pantalla', '<p><strong>Construye tu propio átomo:</strong></p>\r\n<p>Utilizando el simulador de <strong data-start=\"192\" data-end=\"200\">PhET</strong>, crea al menos <strong data-start=\"216\" data-end=\"243\">cinco átomos diferentes</strong>, asegurándote de asignar correctamente el número de <strong data-start=\"296\" data-end=\"332\">protones, neutrones y electrones</strong>. Además, explica la composición de cada uno y justifica tus elecciones.</p>\r\n<p><strong>A terminar Sus Practicas Enviar:</strong></p>\r\n<p>✅ Capturas de pantalla de cada átomo creado en el simulador.<br data-start=\"469\" data-end=\"472\">✅ Un breve documento explicativo donde describas la estructura de cada átomo y razones tus elecciones.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 1.1: Historia y Evolución de los Transistores', '<p data-pm-slice=\"1 1 []\"><strong>Introducción</strong></p>\r\n<p>El transistor es uno de los inventos más revolucionarios del siglo XX, cuya aparición en 1947 marcó el inicio de la era de la electrónica moderna. Su descubrimiento surgió como resultado de la necesidad de encontrar un reemplazo eficiente para las voluminosas y poco confiables válvulas de vacío utilizadas en circuitos electrónicos. Gracias al trabajo pionero de John Bardeen, William Shockley y Walter Brattain en los laboratorios Bell, el transistor se convirtió en la base del desarrollo tecnológico que dio origen a la computación moderna, las telecomunicaciones y numerosos dispositivos electrónicos.</p>\r\n<p>Desde su invención, los transistores han experimentado una evolución significativa a lo largo de cuatro generaciones, cada una caracterizada por avances en materiales, diseño y aplicaciones. En la Primera Generación (1947-1950), los transistores de contacto puntual marcaron el inicio de esta tecnología. La Segunda Generación (1950-1960) introdujo los semiconductores y permitió la fabricación de transistores de mayor confiabilidad y menor consumo de energía. La Tercera Generación (1960-1970) trajo consigo el desarrollo de los circuitos integrados, que permitieron la miniaturización y la mejora en el rendimiento de los dispositivos electrónicos. Finalmente, la Cuarta Generación (1970-presente) ha sido testigo de una miniaturización extrema y la creación de transistores de tamaño nanométrico, los cuales son esenciales en la fabricación de microprocesadores y tecnologías avanzadas.</p>\r\n<p>El impacto de los transistores en la revolución electrónica es innegable. Sin ellos, el desarrollo de computadoras, teléfonos inteligentes, redes de comunicación y sistemas de automatización no habría sido posible. Su evolución ha permitido la creación de dispositivos cada vez más potentes y eficientes, transformando la vida cotidiana y la manera en que interactuamos con la tecnología.</p>\r\n<p>Esta tarea explorará en detalle el descubrimiento del transistor, las contribuciones de sus inventores, la evolución histórica a través de sus cuatro generaciones y el impacto que ha tenido en la revolución electrónica. Además, se presentará una línea de tiempo con los principales hitos de su desarrollo, proporcionando una visión clara y estructurada de su importancia en el mundo actual.</p>\r\n<p></p>\r\n<p></p>\r\n<ul>\r\n<li class=\"\" data-start=\"300\" data-end=\"1030\">\r\n<p data-start=\"303\" data-end=\"323\" class=\"\"><strong data-start=\"303\" data-end=\"321\">Investigación:</strong></p>\r\n<ul data-start=\"327\" data-end=\"1030\">\r\n<li class=\"\" data-start=\"327\" data-end=\"414\">\r\n<p data-start=\"329\" data-end=\"414\" class=\"\">Investiga sobre el <strong data-start=\"348\" data-end=\"389\">descubrimiento del transistor en 1947</strong> y explica cómo surgió.</p>\r\n</li>\r\n<li class=\"\" data-start=\"418\" data-end=\"523\">\r\n<p data-start=\"420\" data-end=\"523\" class=\"\">Describe las <strong data-start=\"433\" data-end=\"469\">contribuciones de los inventores</strong> (John Bardeen, William Shockley y Walter Brattain).</p>\r\n</li>\r\n<li class=\"\" data-start=\"527\" data-end=\"950\">\r\n<p data-start=\"529\" data-end=\"613\" class=\"\">Explica la <strong data-start=\"540\" data-end=\"563\">evolución histórica</strong> de los transistores en sus cuatro generaciones:</p>\r\n<ol data-start=\"619\" data-end=\"950\">\r\n<li class=\"\" data-start=\"619\" data-end=\"686\">\r\n<p data-start=\"622\" data-end=\"686\" class=\"\"><strong data-start=\"622\" data-end=\"657\">Primera Generación (1947-1950):</strong> Características y avances.</p>\r\n</li>\r\n<li class=\"\" data-start=\"692\" data-end=\"771\">\r\n<p data-start=\"695\" data-end=\"771\" class=\"\"><strong data-start=\"695\" data-end=\"730\">Segunda Generación (1950-1960):</strong> Uso de semiconductores y aplicaciones.</p>\r\n</li>\r\n<li class=\"\" data-start=\"777\" data-end=\"852\">\r\n<p data-start=\"780\" data-end=\"852\" class=\"\"><strong data-start=\"780\" data-end=\"815\">Tercera Generación (1960-1970):</strong> Avance hacia circuitos integrados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"858\" data-end=\"950\">\r\n<p data-start=\"861\" data-end=\"950\" class=\"\"><strong data-start=\"861\" data-end=\"899\">Cuarta Generación (1970-presente):</strong> Miniaturización y transistores en la actualidad.</p>\r\n</li>\r\n</ol>\r\n</li>\r\n<li class=\"\" data-start=\"954\" data-end=\"1030\">\r\n<p data-start=\"956\" data-end=\"1030\" class=\"\">Analiza el <strong data-start=\"967\" data-end=\"1027\">impacto de los transistores en la revolución electrónica</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1032\" data-end=\"1303\">\r\n<p data-start=\"1035\" data-end=\"1059\" class=\"\"><strong data-start=\"1035\" data-end=\"1057\">Producto esperado:</strong></p>\r\n<ul data-start=\"1063\" data-end=\"1303\">\r\n<li class=\"\" data-start=\"1063\" data-end=\"1157\">\r\n<p data-start=\"1065\" data-end=\"1157\" class=\"\"><strong data-start=\"1065\" data-end=\"1086\">Documento escrito</strong> (PDF o Word) de <strong data-start=\"1103\" data-end=\"1123\">mínimo 2 páginas</strong> con la información investigada.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1161\" data-end=\"1303\">\r\n<p data-start=\"1163\" data-end=\"1303\" class=\"\"><strong data-start=\"1163\" data-end=\"1182\">Línea de tiempo</strong> con los principales hitos de la evolución del transistor. (Puede ser en PowerPoint, Word, Canva o a mano y escaneado).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Concepto de Iones y Ley de Cargas', '<h4><strong data-start=\"130\" data-end=\"160\">Para profundizar en estos temas, puedes investigar:</strong></h4>\r\n<ul>\r\n<li data-start=\"127\" data-end=\"160\">¿Cómo se forman los iones?</li>\r\n<li data-start=\"161\" data-end=\"197\">¿Qué es un catión y un anión?</li>\r\n<li data-start=\"198\" data-end=\"243\">¿Qué dice la Ley de Cargas Eléctricas?</li>\r\n<li data-start=\"244\" data-end=\"295\">¿Cómo interactúan las cargas de igual signo?</li>\r\n<li data-start=\"296\" data-end=\"349\">¿Cómo interactúan las cargas de signo opuesto?</li>\r\n<li data-start=\"350\" data-end=\"413\">¿Qué es la conductividad iónica y por qué es importante?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Aislantes Eléctricos', '<h4><strong>Investigar Las Siguientes Preguntas:</strong></h4>\r\n<ul>\r\n<li data-start=\"145\" data-end=\"229\">¿Qué es un aislante eléctrico y cuáles son sus principales características?</li>\r\n<li data-start=\"230\" data-end=\"305\">¿Cómo funcionan las bandas de energía en los materiales aislantes?</li>\r\n<li data-start=\"306\" data-end=\"388\">¿Cuáles son los materiales aislantes más comunes y en qué se diferencian?</li>\r\n<li data-start=\"389\" data-end=\"503\">¿Cuáles son las principales aplicaciones de los materiales aislantes en la industria y la vida cotidiana?</li>\r\n<li data-start=\"504\" data-end=\"600\">¿Qué es la rigidez dieléctrica y cómo influye en el desempeño de un aislante eléctrico?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Semiconductores', '<h3><strong>Investigar Las Siguientes Preguntas:</strong></h3>\r\n<ul data-start=\"715\" data-end=\"903\">\r\n<li data-start=\"86\" data-end=\"175\">¿Qué son los semiconductores intrínsecos y extrínsecos, y en qué se diferencian?</li>\r\n<li data-start=\"176\" data-end=\"246\">¿Cómo funcionan las bandas de energía en los semiconductores?</li>\r\n<li data-start=\"247\" data-end=\"343\">¿Qué es el dopaje en los semiconductores y cuál es la diferencia entre los tipos N y P?</li>\r\n<li data-start=\"344\" data-end=\"443\">¿Cuáles son las principales aplicaciones de los semiconductores en la electrónica moderna?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 1.2: Funcionalidad General de los Transistores', '<p dir=\"ltr\">Investigación sobre la funcionalidad general de los transistores:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Concepto de Amplificación</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Principio de Conmutación</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Control de Corriente y Voltaje</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Funcionamiento como Interruptor Electrónico</p>\r\n</li>\r\n</ul>\r\n<p></p>\r\n<p dir=\"ltr\"><strong>Producto Esperado:</strong></p>\r\n<ul id=\"yui_3_18_1_1_1742941190269_193\" data-start=\"1063\" data-end=\"1303\">\r\n<li id=\"yui_3_18_1_1_1742941190269_201\" class=\"\" data-start=\"1063\" data-end=\"1157\">\r\n<p data-start=\"1065\" data-end=\"1157\" class=\"\" id=\"yui_3_18_1_1_1742941190269_200\"><strong id=\"yui_3_18_1_1_1742941190269_199\" data-start=\"1065\" data-end=\"1086\">Documento escrito</strong> (PDF o Word) de <strong data-start=\"1103\" data-end=\"1123\">mínimo 3 páginas</strong> con la información investigada.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 2.2: Principio de Operación', '<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Descripción detallada del principio de operación del transistor BJT.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicación sobre el mecanismo de conducción y control de corriente.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Representación gráfica de las curvas características (IC vs VBE, IC vs VCE, etc.).</li>\r\n<li dir=\"ltr\" role=\"presentation\">Cálculos y ecuaciones ilustrando el control de corriente y las características de transferencia del transistor BJT.</li>\r\n</ul>\r\n<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 2.3: Modos de Funcionamiento', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada sobre los modos de funcionamiento del transistor BJT (Corte, Saturación, Activa).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de las condiciones de operación y características de cada región.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Aplicaciones prácticas de cada modo de funcionamiento en circuitos electrónicos.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gráficos mostrando las curvas de salida y transferencia de un transistor en diferentes modos de funcionamiento.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 2.4: Configuraciones', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada de las configuraciones de transistores (Emisor Común, Base Común, Colector Común).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de sus características, ventajas y aplicaciones típicas.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa de las configuraciones, destacando sus principales diferencias y usos en la práctica.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 3.1: Tipos de FET', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada de las características, estructura y funcionamiento de JFET y MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación de las aplicaciones de ambos tipos de transistores.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre JFET y MOSFET, destacando sus principales características y aplicaciones</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 3.2: Construcción y Estructura Interna', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada del proceso de fabricación, materiales utilizados y la estructura interna de los transistores FET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Diagramas representativos de la estructura interna de JFET y MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Esquemas de los procesos de fabricación y las capas utilizadas en JFET y MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Estructura y Resistividad de los Materiales', '<h3><strong>Investigar Las Siguientes Preguntas:</strong></h3>\r\n<ul data-start=\"715\" data-end=\"903\">\r\n<li data-start=\"106\" data-end=\"196\">¿Cómo influye la estructura atómica en las propiedades eléctricas de un material?</li>\r\n<li data-start=\"197\" data-end=\"306\">¿Cuáles son los factores que afectan la resistividad eléctrica, como la temperatura y las impurezas?</li>\r\n<li data-start=\"307\" data-end=\"391\">¿Qué son los superconductores y cuáles son sus principales características?</li>\r\n<li data-start=\"392\" data-end=\"472\">¿Qué técnicas se utilizan para medir la resistividad de los materiales?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea de Sistemas de Unidades de Medida', '<ul>\r\n<li data-start=\"77\" data-end=\"151\">¿Qué es un sistema de unidades de medida y por qué es importante?</li>\r\n<li data-start=\"152\" data-end=\"229\">¿Cuáles son las principales unidades del Sistema Internacional (SI)?</li>\r\n<li data-start=\"230\" data-end=\"305\">¿En qué se diferencian los sistemas MKS, CGS y el sistema técnico?</li>\r\n<li data-start=\"306\" data-end=\"384\">¿Cómo se realizan conversiones entre diferentes sistemas de unidades?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Múltiplos y Submúltiplos', '<ul>\r\n<li data-start=\"68\" data-end=\"152\">¿Qué son los prefijos del Sistema Internacional (SI) y por qué se utilizan?</li>\r\n<li data-start=\"153\" data-end=\"256\">¿Cuáles son los principales prefijos del SI, desde nano hasta giga, y qué valores representan?</li>\r\n<li data-start=\"257\" data-end=\"369\">¿Qué es la notación científica y cómo facilita la representación de números muy grandes o muy pequeños?</li>\r\n<li data-start=\"370\" data-end=\"465\">¿Cómo se realizan conversiones entre diferentes prefijos del SI y notación científica?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 1.3: Tipos de Transistores y Clasificación', '<h3 class=\"\" data-start=\"71\" data-end=\"178\"><strong data-start=\"75\" data-end=\"178\">Tarea: Tipos de Transistores y su Clasificación según Estructura, Material Semiconductor y Potencia</strong></h3>\r\n<p data-start=\"180\" data-end=\"455\" class=\"\"><strong data-start=\"180\" data-end=\"193\">Objetivo:</strong> Investigar los diferentes tipos de transistores, clasificarlos según su estructura, material semiconductor y potencia, y comparar sus aplicaciones específicas. Esto permitirá entender sus funciones, ventajas y limitaciones en diversas aplicaciones tecnológicas.</p>\r\n<hr class=\"\" data-start=\"457\" data-end=\"460\">\r\n<h3 class=\"\" data-start=\"462\" data-end=\"484\"><strong data-start=\"466\" data-end=\"484\">Instrucciones:</strong></h3>\r\n<ol data-start=\"486\" data-end=\"2842\">\r\n<li class=\"\" data-start=\"486\" data-end=\"1487\">\r\n<p data-start=\"489\" data-end=\"519\" class=\"\"><strong data-start=\"489\" data-end=\"519\">Investigación y Redacción:</strong></p>\r\n<ul data-start=\"523\" data-end=\"1487\">\r\n<li class=\"\" data-start=\"523\" data-end=\"849\">\r\n<p data-start=\"525\" data-end=\"849\" class=\"\"><strong data-start=\"525\" data-end=\"571\">Tipos de Transistores según su Estructura:</strong> Investiga los transistores bipolares (BJT) y los transistores de efecto de campo (FET), detallando las diferencias en sus estructuras, como la disposición de las capas de material semiconductor (NPN, PNP en los BJTs y las características de los MOSFET y JFET en los FETs).</p>\r\n</li>\r\n<li class=\"\" data-start=\"859\" data-end=\"1141\">\r\n<p data-start=\"861\" data-end=\"1141\" class=\"\"><strong data-start=\"861\" data-end=\"888\">Material Semiconductor:</strong> Investiga los diferentes materiales semiconductores utilizados en la fabricación de transistores, tales como <strong data-start=\"1003\" data-end=\"1014\">silicio</strong>, <strong data-start=\"1016\" data-end=\"1028\">germanio</strong> y <strong data-start=\"1031\" data-end=\"1053\">arseniuro de galio</strong>, y cómo influye cada material en el rendimiento y las aplicaciones de los transistores.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1151\" data-end=\"1481\">\r\n<p data-start=\"1153\" data-end=\"1481\" class=\"\"><strong data-start=\"1153\" data-end=\"1186\">Clasificación según Potencia:</strong> Compara los transistores de <strong data-start=\"1220\" data-end=\"1237\">baja potencia</strong> (utilizados en circuitos integrados y pequeños dispositivos electrónicos) y los de <strong data-start=\"1321\" data-end=\"1338\">alta potencia</strong> (empleados en aplicaciones que requieren manejar grandes corrientes y voltajes, como en fuentes de alimentación y amplificadores de potencia).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1488\" data-end=\"1914\">\r\n<p data-start=\"1491\" data-end=\"1539\" class=\"\"><strong data-start=\"1491\" data-end=\"1539\">Comparación entre los Tipos de Transistores:</strong></p>\r\n<ul data-start=\"1543\" data-end=\"1914\">\r\n<li class=\"\" data-start=\"1543\" data-end=\"1728\">\r\n<p data-start=\"1545\" data-end=\"1728\" class=\"\">Elabora una tabla comparativa entre los diferentes tipos de transistores (BJT, MOSFET, JFET, etc.), que incluya sus ventajas, desventajas y las aplicaciones específicas para cada uno.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1732\" data-end=\"1910\">\r\n<p data-start=\"1734\" data-end=\"1910\" class=\"\">Destaca las principales diferencias en términos de <strong data-start=\"1785\" data-end=\"1799\">eficiencia</strong>, <strong data-start=\"1801\" data-end=\"1828\">respuesta de frecuencia</strong>, <strong data-start=\"1830\" data-end=\"1852\">consumo de energía</strong> y <strong data-start=\"1855\" data-end=\"1909\">facilidad de integración en circuitos electrónicos</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1915\" data-end=\"2509\">\r\n<p data-start=\"1918\" data-end=\"1940\" class=\"\"><strong data-start=\"1918\" data-end=\"1940\">Producto Esperado:</strong></p>\r\n<ul data-start=\"1944\" data-end=\"2509\">\r\n<li class=\"\" data-start=\"1944\" data-end=\"2509\">\r\n<p data-start=\"1946\" data-end=\"2039\" class=\"\"><strong data-start=\"1946\" data-end=\"1967\">Documento escrito</strong> (PDF o Word) con la información investigada. El documento debe incluir:</p>\r\n<ul data-start=\"2045\" data-end=\"2509\">\r\n<li class=\"\" data-start=\"2045\" data-end=\"2132\">\r\n<p data-start=\"2047\" data-end=\"2132\" class=\"\">Una introducción breve sobre qué es un transistor y su importancia en la electrónica.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2138\" data-end=\"2258\">\r\n<p data-start=\"2140\" data-end=\"2258\" class=\"\">Descripción detallada de los tipos de transistores según su <strong data-start=\"2200\" data-end=\"2214\">estructura</strong>, <strong data-start=\"2216\" data-end=\"2242\">material semiconductor</strong> y <strong data-start=\"2245\" data-end=\"2257\">potencia</strong>.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2264\" data-end=\"2341\">\r\n<p data-start=\"2266\" data-end=\"2341\" class=\"\">Comparación entre los tipos de transistores y sus aplicaciones específicas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2347\" data-end=\"2509\">\r\n<p data-start=\"2349\" data-end=\"2509\" class=\"\">Conclusiones sobre qué tipo de transistor sería el más adecuado para diferentes escenarios (por ejemplo, uso en amplificadores, circuitos de conmutación, etc.).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"2511\" data-end=\"2797\">\r\n<p data-start=\"2514\" data-end=\"2538\" class=\"\"><strong data-start=\"2514\" data-end=\"2538\">Formato y Extensión:</strong></p>\r\n<ul data-start=\"2542\" data-end=\"2797\">\r\n<li class=\"\" data-start=\"2542\" data-end=\"2591\">\r\n<p data-start=\"2544\" data-end=\"2591\" class=\"\">El documento debe tener un mínimo de 2 páginas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2595\" data-end=\"2685\">\r\n<p data-start=\"2597\" data-end=\"2685\" class=\"\">Usa un formato de texto claro, bien estructurado, con subtítulos y párrafos organizados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2689\" data-end=\"2797\">\r\n<p data-start=\"2691\" data-end=\"2797\" class=\"\">Incluye imágenes o diagramas que ayuden a ilustrar las estructuras de los transistores y sus aplicaciones.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Práctica: Mediciones con Multímetro', '<p><strong>Laboratorio Virtual: \"Mediciones con Multímetro\"</strong></p>\r\n<ul>\r\n<li>Realización de mediciones virtuales (voltaje,corriente y resistencia) en circuitos simulados.</li>\r\n</ul>\r\n<p></p>\r\n<p><strong>Entregable</strong>: Informe de laboratorio con resultados, cálculos y análisis.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 1: Conversiones de Unidades', '<p><strong>Objetivo:</strong> Resolver ejercicios de conversión entre sistemas y múltiplos/submúltiplos.</p>\r\n<p><strong>Entregable:</strong> Documento con soluciones detalladas.<br> </p>\r\n<p><strong>Ejercicios Actualizados:</strong></p>\r\n<ol>\r\n<li> Convertir 2.5 mA a μA.</li>\r\n<li>Expresar 4700 Ω en kΩ.</li>\r\n<li>Convertir 0.025 MV a V.</li>\r\n<li> Calcular la energía (en Joules) que consume una resistencia disipada a 0.5 W durante 2 horas.</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 2: Instrumentos de Medición', '<p><strong>Objetivo:</strong> Analizar y comparar diferentes instrumentos de medición eléctrica y<br>sus aplicaciones.</p>\r\n<p><strong>Entregable:</strong> Informe técnico (3–5 páginas).<br> </p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 1.4: Comparación con Válvulas de Vacío', '<h3 class=\"\" data-start=\"123\" data-end=\"196\"><strong data-start=\"127\" data-end=\"196\">Tarea: Comparación entre los Transistores y las Válvulas de Vacío</strong></h3>\r\n<p data-start=\"198\" data-end=\"522\" class=\"\"><strong data-start=\"198\" data-end=\"211\">Objetivo:</strong> Investigar las características fundamentales de los transistores y las válvulas de vacío, y realizar una comparación detallada entre ambos en términos de funcionamiento, aplicaciones y ventajas/desventajas. Esto permitirá entender cómo estas tecnologías han influido en el desarrollo de la electrónica moderna.</p>\r\n<hr class=\"\" data-start=\"524\" data-end=\"527\">\r\n<h3 class=\"\" data-start=\"529\" data-end=\"551\"><strong data-start=\"533\" data-end=\"551\">Instrucciones:</strong></h3>\r\n<ol data-start=\"553\" data-end=\"2691\">\r\n<li class=\"\" data-start=\"553\" data-end=\"1050\">\r\n<p data-start=\"556\" data-end=\"586\" class=\"\"><strong data-start=\"556\" data-end=\"586\">Investigación y Redacción:</strong></p>\r\n<ul data-start=\"590\" data-end=\"1050\">\r\n<li class=\"\" data-start=\"590\" data-end=\"826\">\r\n<p data-start=\"592\" data-end=\"826\" class=\"\"><strong data-start=\"592\" data-end=\"614\">Válvulas de Vacío:</strong> Investiga qué son las válvulas de vacío, su estructura y cómo funcionan. Incluye detalles sobre su historia, sus aplicaciones iniciales y sus limitaciones (por ejemplo, tamaño, consumo de energía y durabilidad).</p>\r\n</li>\r\n<li class=\"\" data-start=\"834\" data-end=\"1050\">\r\n<p data-start=\"836\" data-end=\"1050\" class=\"\"><strong data-start=\"836\" data-end=\"853\">Transistores:</strong> Investiga cómo los transistores funcionan como reemplazo de las válvulas de vacío en muchas aplicaciones. Describa los diferentes tipos de transistores, su funcionamiento, ventajas y aplicaciones.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1052\" data-end=\"1794\">\r\n<p data-start=\"1055\" data-end=\"1081\" class=\"\"><strong data-start=\"1055\" data-end=\"1081\">Comparación Detallada:</strong></p>\r\n<ul data-start=\"1085\" data-end=\"1794\">\r\n<li class=\"\" data-start=\"1085\" data-end=\"1794\">\r\n<p data-start=\"1087\" data-end=\"1149\" class=\"\">Elabora una tabla comparativa que incluya aspectos clave como:</p>\r\n<ul data-start=\"1155\" data-end=\"1794\">\r\n<li class=\"\" data-start=\"1155\" data-end=\"1261\">\r\n<p data-start=\"1157\" data-end=\"1261\" class=\"\"><strong data-start=\"1157\" data-end=\"1174\">Tamaño y peso</strong>: ¿Cómo afectan las dimensiones de cada tecnología a su uso en diferentes dispositivos?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1267\" data-end=\"1376\">\r\n<p data-start=\"1269\" data-end=\"1376\" class=\"\"><strong data-start=\"1269\" data-end=\"1294\">Eficiencia energética</strong>: ¿Cuál de las dos tecnologías es más eficiente en términos de consumo de energía?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1382\" data-end=\"1472\">\r\n<p data-start=\"1384\" data-end=\"1472\" class=\"\"><strong data-start=\"1384\" data-end=\"1399\">Durabilidad</strong>: ¿Qué tan duraderas son las válvulas de vacío frente a los transistores?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1478\" data-end=\"1560\">\r\n<p data-start=\"1480\" data-end=\"1560\" class=\"\"><strong data-start=\"1480\" data-end=\"1489\">Costo</strong>: ¿Cuál de las dos tecnologías es más económica de producir y mantener?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1566\" data-end=\"1662\">\r\n<p data-start=\"1568\" data-end=\"1662\" class=\"\"><strong data-start=\"1568\" data-end=\"1596\">Aplicaciones específicas</strong>: ¿En qué tipo de dispositivos o contextos se usa cada tecnología?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1668\" data-end=\"1794\">\r\n<p data-start=\"1670\" data-end=\"1794\" class=\"\"><strong data-start=\"1670\" data-end=\"1697\">Rendimiento y velocidad</strong>: Compara la capacidad de procesamiento, la velocidad de conmutación y la fiabilidad de cada una.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1796\" data-end=\"2346\">\r\n<p data-start=\"1799\" data-end=\"1821\" class=\"\"><strong data-start=\"1799\" data-end=\"1821\">Producto Esperado:</strong></p>\r\n<ul data-start=\"1825\" data-end=\"2346\">\r\n<li class=\"\" data-start=\"1825\" data-end=\"2346\">\r\n<p data-start=\"1827\" data-end=\"1920\" class=\"\"><strong data-start=\"1827\" data-end=\"1848\">Documento escrito</strong> (PDF o Word) con la información investigada. El documento debe incluir:</p>\r\n<ul data-start=\"1926\" data-end=\"2346\">\r\n<li class=\"\" data-start=\"1926\" data-end=\"2070\">\r\n<p data-start=\"1928\" data-end=\"2070\" class=\"\">Una introducción breve sobre qué son las válvulas de vacío y los transistores, y cómo cada uno ha influido en el desarrollo de la electrónica.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2076\" data-end=\"2199\">\r\n<p data-start=\"2078\" data-end=\"2199\" class=\"\">Descripción detallada de cómo funcionan las válvulas de vacío y los transistores, sus aplicaciones y sus características.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2205\" data-end=\"2256\">\r\n<p data-start=\"2207\" data-end=\"2256\" class=\"\">Comparación detallada entre los dos dispositivos.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2262\" data-end=\"2346\">\r\n<p data-start=\"2264\" data-end=\"2346\" class=\"\">Conclusiones sobre en qué situaciones podría ser ventajoso usar uno sobre el otro.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"2348\" data-end=\"2646\">\r\n<p data-start=\"2351\" data-end=\"2375\" class=\"\"><strong data-start=\"2351\" data-end=\"2375\">Formato y Extensión:</strong></p>\r\n<ul data-start=\"2379\" data-end=\"2646\">\r\n<li class=\"\" data-start=\"2379\" data-end=\"2428\">\r\n<p data-start=\"2381\" data-end=\"2428\" class=\"\">El documento debe tener un mínimo de 2 páginas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2432\" data-end=\"2523\">\r\n<p data-start=\"2434\" data-end=\"2523\" class=\"\">Usa un formato de texto claro y bien estructurado, con subtítulos y párrafos organizados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2527\" data-end=\"2646\">\r\n<p data-start=\"2529\" data-end=\"2646\" class=\"\">Incluye imágenes, diagramas o gráficos que ayuden a ilustrar cómo funcionan las válvulas de vacío y los transistores.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Actividad Colaborativa-Grupal 3: Mapa Mental', '<p><strong>Objetivo: </strong>Crear un mapa mental (usando Mindomo) sobre las magnitudes eléctricas y sus interrelaciones.</p>\r\n<p><strong>Entregable:</strong> Enlace al mapa mental y documento explicativo.</p>\r\n<ul>\r\n<li><strong>Evaluación:</strong> Estructura (25%), contenido técnico (35%), conexiones (25%) y diseño visual (15%).</li>\r\n<li><strong>Valor:</strong> 40% del módulo.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: Ley de Ohm', '<ul>\r\n<li data-start=\"61\" data-end=\"181\">¿Qué establece la Ley de Ohm y cómo se relacionan la corriente, el voltaje y la resistencia en un circuito eléctrico?</li>\r\n<li data-start=\"182\" data-end=\"298\">¿Cómo varía la corriente en un circuito si se aumenta el voltaje o se cambia la resistencia, según la Ley de Ohm?</li>\r\n<li data-start=\"299\" data-end=\"400\">¿Cuáles son las aplicaciones prácticas de la Ley de Ohm en dispositivos eléctricos y electrónicos?</li>\r\n<li data-start=\"401\" data-end=\"523\">¿Qué limitaciones tiene la Ley de Ohm cuando se trata de materiales no ohmicos o circuitos con componentes no lineales?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: Circuitos en Serie y Paralelo', '<ul>\r\n<li data-start=\"120\" data-end=\"215\">¿Qué son los circuitos en serie y en paralelo, y cuáles son sus principales características?</li>\r\n<li data-start=\"216\" data-end=\"298\">¿Cómo se dividen la tensión y la corriente en circuitos en serie y en paralelo?</li>\r\n<li data-start=\"299\" data-end=\"381\">¿Cuáles son las ventajas y desventajas de los circuitos en serie y en paralelo?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 3.3: Principio de Operación', '<h3 dir=\"ltr\">Producto Esperado :</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada del principio de operación de los transistores FET, con énfasis en el control por voltaje y el efecto de campo.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Cálculos matemáticos y gráficos de las características de transferencia (ID vs VGS, gm vs VGS, etc.).<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gráficos que muestran las curvas de salida de JFET y MOSFET en diferentes regiones de operación.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 4.1: Proceso de Fabricación CMOS', '<p><strong>Preparación del Substrato. Explica:</strong><br><br></p>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Limpieza química<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Oxidación térmica<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Recubrimiento de fotoresist<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Litografía<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Formación de Capas<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Deposición de óxido de compuerta (SiO₂, HfO₂)<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Implantación iónica<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Recocido térmico<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Procesos de Grabado<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Grabado húmedo<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Grabado en seco<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Limpieza<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Pasivación</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 4.2: Estructura de Capas', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción del proceso de fabricación de los MOSFET, desde la preparación del substrato hasta los procesos de grabado.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Detalles sobre la estructura de capas de los MOSFET, incluyendo el substrato, óxido de compuerta, compuerta, drenaje y fuente.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Diagramas y esquemas mostrando la estructura interna del MOSFET y los procesos de fabricación.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 4.3: Mecanismo de Conducción', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada sobre el mecanismo de conducción del MOSFET, incluida la formación del canal y el control de corriente.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Representación matemática de la ecuación de corriente y el factor K.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis de los efectos secundarios que afectan el rendimiento del MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Tarea (Assignment)', 'Tarea 4.4: Características Eléctricas', '<ol>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Parámetros Estáticos<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">VTH: 0.5-3V<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">IDSS: 0.1-100 mA<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">gm: 1-100 mS<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">ro: 10-100 kΩ<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Parámetros Dinámicos<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Ciss: 1-100 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Coss: 0.1-10 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Crss: 0.01-1 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">tr/tf: 1-100 ns<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Límites de Operación<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">VDSmax: 5-1000V<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">IDmax: 0.1-100A<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">PDmax: 0.1-1000W<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Tjmax: 150-200°C<br><br></p>\r\n</li>\r\n</ul>\r\n</ol>\r\n<p dir=\"ltr\"></p>\r\n<hr>\r\n<p></p>\r\n<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de los parámetros estáticos y dinámicos del MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación de los límites de operación y sus implicaciones en el diseño de circuitos.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p><strong id=\"docs-internal-guid-98c38875-7fff-3772-89fd-baac19aea7f3\">Gráficos que muestren las características eléctricas del MOSFET en diferentes condiciones.<br></strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Resistencia Equivalente', '<ul>\r\n<li data-start=\"429\" data-end=\"514\">¿Cómo se calcula la resistencia equivalente en un circuito en serie y en paralelo?</li>\r\n<li data-start=\"515\" data-end=\"601\">¿Cómo se analiza un circuito mixto que combina resistencias en serie y en paralelo?</li>\r\n<li data-start=\"602\" data-end=\"710\">¿Qué técnicas de simplificación se utilizan para resolver circuitos con resistencias en serie y paralelo?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: Código de Colores de Resistencias', '<ul>\r\n<li data-start=\"768\" data-end=\"843\">¿Cómo funciona el sistema de codificación por colores para resistencias?</li>\r\n<li data-start=\"844\" data-end=\"936\">¿Cuál es la diferencia entre resistencias de 4, 5 y 6 bandas en cuanto a su codificación?</li>\r\n<li data-start=\"937\" data-end=\"1057\">¿Cómo se determina la tolerancia y el coeficiente de temperatura de una resistencia a partir de su código de colores?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Circuitos Mixtos Eléctricos', '<ul>\r\n<li data-start=\"1109\" data-end=\"1209\">¿Cómo se realiza el análisis de circuitos mixtos que combinan componentes en serie y en paralelo?</li>\r\n<li data-start=\"1210\" data-end=\"1301\">¿Cuáles son las técnicas de simplificación y resolución paso a paso de circuitos mixtos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Curso Basico', 'Tarea (Assignment)', 'Explorando la Electricidad', '<p data-start=\"149\" data-end=\"260\" class=\"\"><strong data-start=\"149\" data-end=\"162\">Objetivo:</strong> Comprender qué es la electricidad, sus conceptos básicos y su importancia en la vida cotidiana.</p>\r\n<p data-start=\"262\" data-end=\"374\" class=\"\"><strong data-start=\"262\" data-end=\"280\">Instrucciones:</strong><br data-start=\"280\" data-end=\"283\">1️⃣ Investiga y responde las siguientes preguntas en un documento o en el foro del curso:</p>\r\n<ul data-start=\"378\" data-end=\"642\">\r\n<li class=\"\" data-start=\"378\" data-end=\"423\">\r\n<p data-start=\"380\" data-end=\"423\" class=\"\">¿Qué es la electricidad y cómo se genera?</p>\r\n</li>\r\n<li class=\"\" data-start=\"427\" data-end=\"492\">\r\n<p data-start=\"429\" data-end=\"492\" class=\"\">¿Cuál es la diferencia entre carga positiva y carga negativa?</p>\r\n</li>\r\n<li class=\"\" data-start=\"496\" data-end=\"561\">\r\n<p data-start=\"498\" data-end=\"561\" class=\"\">¿Qué es un conductor y qué es un aislante? Menciona ejemplos.</p>\r\n</li>\r\n<li class=\"\" data-start=\"565\" data-end=\"642\">\r\n<p data-start=\"567\" data-end=\"642\" class=\"\">¿Qué aplicaciones prácticas tiene la electricidad en nuestra vida diaria?</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Estructura Atómica Tarea', '<p><strong style=\"text-align: initial;\" data-start=\"144\" data-end=\"168\">Lección 1: Estructura Atómica</strong></p>\r\n<p>En esta sección exploraremos los fundamentos de la estructura atómica, incluyendo las partículas subatómicas, el número atómico y másico, así como los conceptos de isótopos e iones. También analizaremos los diferentes modelos atómicos a lo largo de la historia.</p>\r\n<p><strong>Investigar Estas Preguntas:</strong></p>\r\n<ul>\r\n<li> ¿Qué características tienen los protones, neutrones y electrones?</li>\r\n<li>¿Cómo se calcula el número atómico y el número másico?</li>\r\n<li>¿Qué diferencia hay entre un isótopo y un ion?</li>\r\n<li>¿Cuáles son los principales modelos atómicos y cómo han evolucionado?</li>\r\n</ul>\r\n<p>Valor: 2 Puntos</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Ley Universal de Conservación de Energía:', '<p data-start=\"436\" data-end=\"493\"><strong data-start=\"436\" data-end=\"491\">Para profundizar en estos temas, puedes investigar:</strong></p>\r\n<ul data-start=\"494\" data-end=\"747\">\r\n<li class=\"\" data-start=\"417\" data-end=\"474\">\r\n<p data-start=\"420\" data-end=\"474\" class=\"\">¿En qué consiste la <a class=\"autolink\" title=\"Ley de Conservación de la Energía\" href=\"https://lasaedu.t-ecogroup.net/mod/url/view.php?id=227\">Ley de Conservación de la Energía</a>?</p>\r\n</li>\r\n<li class=\"\" data-start=\"475\" data-end=\"520\">\r\n<p data-start=\"478\" data-end=\"520\" class=\"\">¿Por qué se considera una \"ley universal\"?</p>\r\n</li>\r\n<li class=\"\" data-start=\"521\" data-end=\"594\">\r\n<p data-start=\"524\" data-end=\"594\" class=\"\">¿Quiénes fueron los científicos que contribuyeron a formular esta ley?</p>\r\n</li>\r\n<li class=\"\" data-start=\"2018\" data-end=\"2042\">\r\n<p data-start=\"2020\" data-end=\"2042\" class=\"\">Ejemplos cotidianos.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2043\" data-end=\"2064\">\r\n<p data-start=\"2045\" data-end=\"2064\" class=\"\">Tipos de energía.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Lección 6: Conductores Eléctricos', '<h4><strong>Investigar Las Siguientes Preguntas:</strong></h4>\r\n<ul>\r\n<li data-start=\"106\" data-end=\"146\">¿Qué es un conductor eléctrico?</li>\r\n<li data-start=\"147\" data-end=\"230\">¿Cuáles son las principales características de los conductores eléctricos?</li>\r\n<li data-start=\"231\" data-end=\"318\">¿Qué relación existe entre la estructura cristalina y la conducción eléctrica?</li>\r\n<li data-start=\"319\" data-end=\"397\">¿Qué son los electrones libres y qué papel juegan en los conductores?</li>\r\n<li data-start=\"398\" data-end=\"474\">¿Cuáles son los metales más utilizados como conductores eléctricos?</li>\r\n<li data-start=\"475\" data-end=\"571\">¿Qué ventajas tienen las aleaciones sobre los metales puros en aplicaciones eléctricas?</li>\r\n<li data-start=\"572\" data-end=\"653\">¿Qué es la resistividad y cómo influye en la eficiencia de un conductor?</li>\r\n<li data-start=\"654\" data-end=\"726\">Menciona una aplicación práctica de los conductores eléctricos.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Magnitudes Eléctricas Fundamentales', '<ul>\r\n<li data-start=\"91\" data-end=\"220\">¿Qué es un multímetro digital y cómo se utiliza en la medición de corriente (amperio), tensión (voltio) y resistencia (ohmio)?</li>\r\n<li data-start=\"221\" data-end=\"343\">¿Cómo funciona un osciloscopio y qué tipo de señales permite analizar en relación con corriente, tensión y resistencia?</li>\r\n<li data-start=\"344\" data-end=\"440\">¿Cuál es la función de un vatímetro y cómo mide la potencia eléctrica (vatio) en un circuito?</li>\r\n<li data-start=\"441\" data-end=\"554\">¿Para qué se utiliza un medidor de energía (joule, kWh) y cómo determina el consumo energético en un circuito?</li>\r\n<li data-start=\"555\" data-end=\"688\">¿Qué mide un medidor LCR y cuál es su importancia en la caracterización de componentes eléctricos como capacitancia e inductancia?</li>\r\n<li data-start=\"689\" data-end=\"874\">¿Cuáles son las principales técnicas de medición en circuitos eléctricos y cómo se pueden minimizar los errores en la medición de corriente, tensión, resistencia, potencia y energía?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: 5: Análisis de Circuitos', '<p><strong>Objetivo:</strong> Resolver problemas de circuitos en serie, paralelo y mixtos.</p>\r\n<p><strong>Entregable:</strong> Documento con diagramas, cálculos y explicaciones.</p>\r\n<p></p>\r\n<p><strong>Ejemplos Actualizados:</strong></p>\r\n<p><br>1. Calcular la resistencia equivalente de tres resistencias en serie:<br>220 Ω, 470 Ω y 1 kΩ.<br>2. En un circuito paralelo con resistencias de 100 Ω, 200 Ω y 300 Ω,<br>determinar la corriente para 12 V.<br>3. Simplificar un circuito mixto y calcular la corriente total.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: Elementos Activos', '<ul>\r\n<li>¿Qué son los elementos activos en un circuito eléctrico, como las fuentes de tensión y corriente, generadores y amplificadores?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Dispositivos Electrónicos', '<ul>\r\n<li data-start=\"1824\" data-end=\"1899\">¿Cómo se clasifican los dispositivos electrónicos en términos generales?</li>\r\n<li data-start=\"1900\" data-end=\"2024\">¿Cuáles son los circuitos integrados, la optoelectrónica, los sensores y los actuadores, y cómo funcionan en un circuito?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Elementos Pasivos', '<ul>\r\n<li data-start=\"1567\" data-end=\"1684\">¿Qué son los elementos pasivos en un circuito, como las resistencias, condensadores, inductores y transformadores?</li>\r\n<li data-start=\"1685\" data-end=\"1774\">¿Cómo se comportan los elementos pasivos en circuitos de corriente continua y alterna?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: Los Diodos y sus Aplicaciones', '<ul>\r\n<li data-start=\"2078\" data-end=\"2153\">¿Cómo funcionan los diodos y cómo se representa su curva característica?</li>\r\n<li data-start=\"2154\" data-end=\"2243\">¿Cuál es la diferencia entre los diodos rectificadores y sus aplicaciones más comunes?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Instrumentos de Medida Eléctrica', '<ul>\r\n<li data-start=\"46\" data-end=\"154\">¿Qué es un multímetro digital y cómo se utiliza en la medición de voltaje, corriente y resistencia?</li>\r\n<li data-start=\"155\" data-end=\"234\">¿Cómo funciona un osciloscopio y qué tipo de señales permite analizar?</li>\r\n<li data-start=\"235\" data-end=\"329\">¿Cuál es la función de un vatímetro y cómo mide la potencia eléctrica en un circuito?</li>\r\n<li data-start=\"330\" data-end=\"422\">¿Para qué se utiliza un frecuencímetro y cómo determina la frecuencia de una señal?</li>\r\n<li data-start=\"423\" data-end=\"530\">¿Qué mide un medidor LCR y cuál es su importancia en la caracterización de componentes eléctricos?</li>\r\n<li data-start=\"531\" data-end=\"646\">¿Cuáles son las principales técnicas de medición y cómo se pueden minimizar los errores en los resultados?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Construcción de una Fuente de Alimentación', '<ul>\r\n<li data-start=\"2310\" data-end=\"2447\">¿Cuáles son los componentes esenciales para construir una fuente de alimentación (transformador, rectificador, filtrado y regulación)?</li>\r\n<li data-start=\"2448\" data-end=\"2506\">¿Cómo se diseña paso a paso una fuente de alimentación?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: Los Diodos LED y sus Aplicaciones', '<ul>\r\n<li data-start=\"2564\" data-end=\"2677\">¿Cómo funcionan los diodos LED y qué características deben considerarse al calcular la resistencia limitadora?</li>\r\n<li data-start=\"2678\" data-end=\"2757\">¿Cómo se diseñan y utilizan circuitos con LEDs en aplicaciones electrónicas?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Los Diodos Zener y sus Aplicaciones', '<ul>\r\n<li data-start=\"139\" data-end=\"217\">¿Cómo funciona un diodo Zener y cómo se representa su curva característica?</li>\r\n<li data-start=\"218\" data-end=\"319\">¿De qué manera los diodos Zener se utilizan en la regulación de tensión en circuitos electrónicos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: Los Condensadores-Capacitores y sus Aplicaciones', '<ul>\r\n<li data-start=\"392\" data-end=\"485\">¿Cuál es el principio de funcionamiento de un condensador o capacitor y qué tipos existen?</li>\r\n<li data-start=\"486\" data-end=\"606\">¿Cómo se realiza el proceso de carga y descarga en un condensador, y cómo se aplican estos conceptos en circuitos RC?</li>\r\n<li data-start=\"607\" data-end=\"681\">¿Cómo se calculan las propiedades de los condensadores en circuitos RC?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 1: Análisis de Circuitos con Condensadores', '<p><strong>Objetivo:</strong> Resolver ejercicios de carga/descarga y cálculos en circuitos RC.</p>\r\n<p></p>\r\n<p><strong>Entregable:</strong> Informe técnico con simulaciones y cálculos.</p>\r\n<p></p>\r\n<p><strong>Ejercicios Actualizados:</strong></p>\r\n<ol>\r\n<li> Calcular la constante de tiempo (τ) de un condensador de 100 μF con<br>una resistencia de 10 kΩ.</li>\r\n<li>Determinar la capacidad equivalente de tres condensadores (10 μF, 22<br>μF y 47 μF) en serie.<br>3. Diseñar un circuito RC que genere un retardo de 1 segundo.</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 2: Clasificación de los Diodos', '<p><strong>Objetivo:</strong> Investigar y clasificar al menos 6 tipos de diodos, detallando características y aplicaciones.</p>\r\n<p></p>\r\n<p><strong>Entregable</strong>: Informe técnic</p>\r\n<p></p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea:  Interruptores, Conmutadores y Pulsadores', '<ul>\r\n<li data-start=\"808\" data-end=\"924\">¿Cuáles son los tipos de interruptores, conmutadores y pulsadores, y cuáles son sus principios de funcionamiento?</li>\r\n<li data-start=\"925\" data-end=\"1056\">¿Cómo se representa la simbología de interruptores, conmutadores y pulsadores, y qué aplicaciones prácticas tienen en circuitos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Relé o Relevador', '<ul>\r\n<li data-start=\"1097\" data-end=\"1156\">¿Cómo funciona un relé o relevador, y qué tipos existen?</li>\r\n<li data-start=\"1157\" data-end=\"1255\">¿Cuáles son las características eléctricas de un relé y cómo se aplica en circuitos de control?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: De los  Transformadores', '<ul>\r\n<li data-start=\"1332\" data-end=\"1428\">¿Cuál es el principio de inducción electromagnética en el funcionamiento de un transformador?</li>\r\n<li data-start=\"1429\" data-end=\"1550\">¿Cómo se estructura un transformador, y cuál es la relación de transformación entre sus bobinas primaria y secundaria?</li>\r\n<li data-start=\"1551\" data-end=\"1659\">¿Qué tipos de transformadores existen, y cómo afectan las pérdidas y el rendimiento en su funcionamiento?</li>\r\n<li data-start=\"1660\" data-end=\"1748\">¿Cuáles son las aplicaciones prácticas de los transformadores en sistemas eléctricos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 2.1:  Preparación del Substrato Construcción', '<p></p>\r\n<p>Descripción detallada de los materiales semiconductores utilizados y el proceso de fabricación de los transistores.<br><br></p>\r\n<p>Explicación de la estructura de capas de los transistores NPN y PNP.<br><br></p>\r\n<p>Representación gráfica con símbolos y convenciones estándar para los transistores NPN y PNP.<br><br></p>\r\n<p>Esquemas o diagramas ilustrando las distintas etapas del proceso de fabricación y la estructura interna de los transistores.</p>\r\n<p></p>\r\n<p style=\"font-weight: bold;\"><strong>Producto Esperado :</strong></p>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea: 4.6 Comparación con BJT', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación detallada entre MOSFET y BJT en términos de potencia, eficiencia energética, velocidad de conmutación, costos, y aplicaciones específicas.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre MOSFET y BJT, destacando sus principales diferencias y ventajas.<br><br></p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Enviar Capturas de Pantalla', '<p><strong>Construye tu propio átomo:</strong></p>\r\n<p>Utilizando el simulador de <strong data-start=\"192\" data-end=\"200\">PhET</strong>, crea al menos <strong data-start=\"216\" data-end=\"243\">cinco átomos diferentes</strong>, asegurándote de asignar correctamente el número de <strong data-start=\"296\" data-end=\"332\">protones, neutrones y electrones</strong>. Además, explica la composición de cada uno y justifica tus elecciones.</p>\r\n<p><strong>A terminar Sus Practicas Enviar:</strong></p>\r\n<p>✅ Capturas de pantalla de cada átomo creado en el simulador.<br data-start=\"469\" data-end=\"472\">✅ Un breve documento explicativo donde describas la estructura de cada átomo y razones tus elecciones.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 1.1: Historia y Evolución de los Transistores', '<p data-pm-slice=\"1 1 []\"><strong>Introducción</strong></p>\r\n<p>El transistor es uno de los inventos más revolucionarios del siglo XX, cuya aparición en 1947 marcó el inicio de la era de la electrónica moderna. Su descubrimiento surgió como resultado de la necesidad de encontrar un reemplazo eficiente para las voluminosas y poco confiables válvulas de vacío utilizadas en circuitos electrónicos. Gracias al trabajo pionero de John Bardeen, William Shockley y Walter Brattain en los laboratorios Bell, el transistor se convirtió en la base del desarrollo tecnológico que dio origen a la computación moderna, las telecomunicaciones y numerosos dispositivos electrónicos.</p>\r\n<p>Desde su invención, los transistores han experimentado una evolución significativa a lo largo de cuatro generaciones, cada una caracterizada por avances en materiales, diseño y aplicaciones. En la Primera Generación (1947-1950), los transistores de contacto puntual marcaron el inicio de esta tecnología. La Segunda Generación (1950-1960) introdujo los semiconductores y permitió la fabricación de transistores de mayor confiabilidad y menor consumo de energía. La Tercera Generación (1960-1970) trajo consigo el desarrollo de los circuitos integrados, que permitieron la miniaturización y la mejora en el rendimiento de los dispositivos electrónicos. Finalmente, la Cuarta Generación (1970-presente) ha sido testigo de una miniaturización extrema y la creación de transistores de tamaño nanométrico, los cuales son esenciales en la fabricación de microprocesadores y tecnologías avanzadas.</p>\r\n<p>El impacto de los transistores en la revolución electrónica es innegable. Sin ellos, el desarrollo de computadoras, teléfonos inteligentes, redes de comunicación y sistemas de automatización no habría sido posible. Su evolución ha permitido la creación de dispositivos cada vez más potentes y eficientes, transformando la vida cotidiana y la manera en que interactuamos con la tecnología.</p>\r\n<p>Esta tarea explorará en detalle el descubrimiento del transistor, las contribuciones de sus inventores, la evolución histórica a través de sus cuatro generaciones y el impacto que ha tenido en la revolución electrónica. Además, se presentará una línea de tiempo con los principales hitos de su desarrollo, proporcionando una visión clara y estructurada de su importancia en el mundo actual.</p>\r\n<p></p>\r\n<p></p>\r\n<ul>\r\n<li class=\"\" data-start=\"300\" data-end=\"1030\">\r\n<p data-start=\"303\" data-end=\"323\" class=\"\"><strong data-start=\"303\" data-end=\"321\">Investigación:</strong></p>\r\n<ul data-start=\"327\" data-end=\"1030\">\r\n<li class=\"\" data-start=\"327\" data-end=\"414\">\r\n<p data-start=\"329\" data-end=\"414\" class=\"\">Investiga sobre el <strong data-start=\"348\" data-end=\"389\">descubrimiento del transistor en 1947</strong> y explica cómo surgió.</p>\r\n</li>\r\n<li class=\"\" data-start=\"418\" data-end=\"523\">\r\n<p data-start=\"420\" data-end=\"523\" class=\"\">Describe las <strong data-start=\"433\" data-end=\"469\">contribuciones de los inventores</strong> (John Bardeen, William Shockley y Walter Brattain).</p>\r\n</li>\r\n<li class=\"\" data-start=\"527\" data-end=\"950\">\r\n<p data-start=\"529\" data-end=\"613\" class=\"\">Explica la <strong data-start=\"540\" data-end=\"563\">evolución histórica</strong> de los transistores en sus cuatro generaciones:</p>\r\n<ol data-start=\"619\" data-end=\"950\">\r\n<li class=\"\" data-start=\"619\" data-end=\"686\">\r\n<p data-start=\"622\" data-end=\"686\" class=\"\"><strong data-start=\"622\" data-end=\"657\">Primera Generación (1947-1950):</strong> Características y avances.</p>\r\n</li>\r\n<li class=\"\" data-start=\"692\" data-end=\"771\">\r\n<p data-start=\"695\" data-end=\"771\" class=\"\"><strong data-start=\"695\" data-end=\"730\">Segunda Generación (1950-1960):</strong> Uso de semiconductores y aplicaciones.</p>\r\n</li>\r\n<li class=\"\" data-start=\"777\" data-end=\"852\">\r\n<p data-start=\"780\" data-end=\"852\" class=\"\"><strong data-start=\"780\" data-end=\"815\">Tercera Generación (1960-1970):</strong> Avance hacia circuitos integrados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"858\" data-end=\"950\">\r\n<p data-start=\"861\" data-end=\"950\" class=\"\"><strong data-start=\"861\" data-end=\"899\">Cuarta Generación (1970-presente):</strong> Miniaturización y transistores en la actualidad.</p>\r\n</li>\r\n</ol>\r\n</li>\r\n<li class=\"\" data-start=\"954\" data-end=\"1030\">\r\n<p data-start=\"956\" data-end=\"1030\" class=\"\">Analiza el <strong data-start=\"967\" data-end=\"1027\">impacto de los transistores en la revolución electrónica</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1032\" data-end=\"1303\">\r\n<p data-start=\"1035\" data-end=\"1059\" class=\"\"><strong data-start=\"1035\" data-end=\"1057\">Producto esperado:</strong></p>\r\n<ul data-start=\"1063\" data-end=\"1303\">\r\n<li class=\"\" data-start=\"1063\" data-end=\"1157\">\r\n<p data-start=\"1065\" data-end=\"1157\" class=\"\"><strong data-start=\"1065\" data-end=\"1086\">Documento escrito</strong> (PDF o Word) de <strong data-start=\"1103\" data-end=\"1123\">mínimo 2 páginas</strong> con la información investigada.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1161\" data-end=\"1303\">\r\n<p data-start=\"1163\" data-end=\"1303\" class=\"\"><strong data-start=\"1163\" data-end=\"1182\">Línea de tiempo</strong> con los principales hitos de la evolución del transistor. (Puede ser en PowerPoint, Word, Canva o a mano y escaneado).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Concepto de Iones y Ley de Cargas', '<h4><strong data-start=\"130\" data-end=\"160\">Para profundizar en estos temas, puedes investigar:</strong></h4>\r\n<ul>\r\n<li data-start=\"127\" data-end=\"160\">¿Cómo se forman los iones?</li>\r\n<li data-start=\"161\" data-end=\"197\">¿Qué es un catión y un anión?</li>\r\n<li data-start=\"198\" data-end=\"243\">¿Qué dice la Ley de Cargas Eléctricas?</li>\r\n<li data-start=\"244\" data-end=\"295\">¿Cómo interactúan las cargas de igual signo?</li>\r\n<li data-start=\"296\" data-end=\"349\">¿Cómo interactúan las cargas de signo opuesto?</li>\r\n<li data-start=\"350\" data-end=\"413\">¿Qué es la conductividad iónica y por qué es importante?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Aislantes Eléctricos', '<h4><strong>Investigar Las Siguientes Preguntas:</strong></h4>\r\n<ul>\r\n<li data-start=\"145\" data-end=\"229\">¿Qué es un aislante eléctrico y cuáles son sus principales características?</li>\r\n<li data-start=\"230\" data-end=\"305\">¿Cómo funcionan las bandas de energía en los materiales aislantes?</li>\r\n<li data-start=\"306\" data-end=\"388\">¿Cuáles son los materiales aislantes más comunes y en qué se diferencian?</li>\r\n<li data-start=\"389\" data-end=\"503\">¿Cuáles son las principales aplicaciones de los materiales aislantes en la industria y la vida cotidiana?</li>\r\n<li data-start=\"504\" data-end=\"600\">¿Qué es la rigidez dieléctrica y cómo influye en el desempeño de un aislante eléctrico?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Semiconductores', '<h3><strong>Investigar Las Siguientes Preguntas:</strong></h3>\r\n<ul data-start=\"715\" data-end=\"903\">\r\n<li data-start=\"86\" data-end=\"175\">¿Qué son los semiconductores intrínsecos y extrínsecos, y en qué se diferencian?</li>\r\n<li data-start=\"176\" data-end=\"246\">¿Cómo funcionan las bandas de energía en los semiconductores?</li>\r\n<li data-start=\"247\" data-end=\"343\">¿Qué es el dopaje en los semiconductores y cuál es la diferencia entre los tipos N y P?</li>\r\n<li data-start=\"344\" data-end=\"443\">¿Cuáles son las principales aplicaciones de los semiconductores en la electrónica moderna?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 1.2: Funcionalidad General de los Transistores', '<p dir=\"ltr\">Investigación sobre la funcionalidad general de los transistores:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Concepto de Amplificación</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Principio de Conmutación</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Control de Corriente y Voltaje</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Funcionamiento como Interruptor Electrónico</p>\r\n</li>\r\n</ul>\r\n<p></p>\r\n<p dir=\"ltr\"><strong>Producto Esperado:</strong></p>\r\n<ul id=\"yui_3_18_1_1_1742941190269_193\" data-start=\"1063\" data-end=\"1303\">\r\n<li id=\"yui_3_18_1_1_1742941190269_201\" class=\"\" data-start=\"1063\" data-end=\"1157\">\r\n<p data-start=\"1065\" data-end=\"1157\" class=\"\" id=\"yui_3_18_1_1_1742941190269_200\"><strong id=\"yui_3_18_1_1_1742941190269_199\" data-start=\"1065\" data-end=\"1086\">Documento escrito</strong> (PDF o Word) de <strong data-start=\"1103\" data-end=\"1123\">mínimo 3 páginas</strong> con la información investigada.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Campos de Aplicación de la Electrónica', '<p></p>\r\n<p data-start=\"0\" data-end=\"990\" class=\"\">La electrónica es una disciplina fundamental que abarca una amplia gama de aplicaciones que transforman la tecnología y la vida cotidiana. La <strong data-start=\"142\" data-end=\"177\">electrónica analógica y digital</strong> son las bases sobre las cuales se desarrollan los sistemas modernos, desde circuitos básicos hasta complejos procesadores. Por otro lado, la <strong data-start=\"319\" data-end=\"339\">microelectrónica</strong> se enfoca en la fabricación de componentes diminutos que permiten dispositivos de alto rendimiento en áreas como <strong data-start=\"453\" data-end=\"465\">potencia</strong> y <strong data-start=\"468\" data-end=\"487\">optoelectrónica</strong>, esenciales en la creación de productos de consumo y sistemas de comunicación avanzados. En el campo de la <strong data-start=\"595\" data-end=\"607\">robótica</strong>, la electrónica es clave para el diseño de máquinas inteligentes, mientras que en <strong data-start=\"690\" data-end=\"712\">telecomunicaciones</strong> es responsable de la transmisión y recepción de señales a través de diversos medios. Finalmente, la <strong data-start=\"813\" data-end=\"831\">bioelectrónica</strong> ha revolucionado el sector de la salud, desarrollando dispositivos médicos que interactúan con el cuerpo humano para diagnósticos y tratamientos más precisos.</p>\r\n<p data-start=\"992\" data-end=\"1268\" class=\"\">Para profundizar en estos temas, investiga cómo la <strong data-start=\"1043\" data-end=\"1063\">microelectrónica</strong> ha influido en el avance de los teléfonos móviles y dispositivos portátiles, y cómo la <strong data-start=\"1151\" data-end=\"1169\">bioelectrónica</strong> está transformando la medicina moderna a través de nuevos dispositivos de monitoreo y tratamiento.</p>\r\n<p data-start=\"109\" data-end=\"145\" class=\"\"><strong data-start=\"109\" data-end=\"145\">Instrucciones para la Actividad:</strong></p>\r\n<ol data-start=\"147\" data-end=\"2311\">\r\n<li class=\"\" data-start=\"147\" data-end=\"499\">\r\n<p data-start=\"150\" data-end=\"499\" class=\"\"><strong data-start=\"150\" data-end=\"175\">Introducción al Tema:</strong> Lee atentamente el párrafo introductorio sobre los diferentes campos de la electrónica, incluyendo la electrónica analógica y digital, la microelectrónica, la robótica, las telecomunicaciones y la bioelectrónica. Este conocimiento te ayudará a comprender cómo estas disciplinas se aplican en diversas áreas tecnológicas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"501\" data-end=\"1521\">\r\n<p data-start=\"504\" data-end=\"613\" class=\"\"><strong data-start=\"504\" data-end=\"536\">Investigación Personalizada:</strong> Elige uno de los siguientes temas de interés para investigar más a fondo:</p>\r\n<ul data-start=\"621\" data-end=\"1521\">\r\n<li class=\"\" data-start=\"621\" data-end=\"806\">\r\n<p data-start=\"623\" data-end=\"806\" class=\"\"><strong data-start=\"623\" data-end=\"659\">Electrónica Analógica y Digital:</strong> Investiga las diferencias entre ambos tipos de circuitos y cómo se aplican en dispositivos comunes (como radios, televisores, computadoras, etc.).</p>\r\n</li>\r\n<li class=\"\" data-start=\"810\" data-end=\"1029\">\r\n<p data-start=\"812\" data-end=\"1029\" class=\"\"><strong data-start=\"812\" data-end=\"851\">Microelectrónica y Optoelectrónica:</strong> Investiga cómo los avances en microelectrónica han permitido el desarrollo de dispositivos portátiles y qué aplicaciones tiene la optoelectrónica en las comunicaciones modernas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1033\" data-end=\"1156\">\r\n<p data-start=\"1035\" data-end=\"1156\" class=\"\"><strong data-start=\"1035\" data-end=\"1048\">Robótica:</strong> Investiga cómo los circuitos electrónicos se utilizan en la creación de robots y automatización industrial.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1160\" data-end=\"1337\">\r\n<p data-start=\"1162\" data-end=\"1337\" class=\"\"><strong data-start=\"1162\" data-end=\"1185\">Telecomunicaciones:</strong> Investiga cómo la electrónica permite la transmisión de señales de voz y datos a través de diferentes tecnologías (como redes móviles, internet, etc.).</p>\r\n</li>\r\n<li class=\"\" data-start=\"1341\" data-end=\"1521\">\r\n<p data-start=\"1343\" data-end=\"1521\" class=\"\"><strong data-start=\"1343\" data-end=\"1362\">Bioelectrónica:</strong> Investiga cómo los dispositivos electrónicos interactúan con el cuerpo humano en el campo de la medicina, tales como marcapasos o dispositivos de diagnóstico.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1523\" data-end=\"1817\">\r\n<p data-start=\"1526\" data-end=\"1638\" class=\"\"><strong data-start=\"1526\" data-end=\"1550\">Entrega del Informe:</strong> Una vez hayas seleccionado tu tema de investigación, escribe un informe que incluya:</p>\r\n<ul data-start=\"1646\" data-end=\"1817\">\r\n<li class=\"\" data-start=\"1646\" data-end=\"1699\">\r\n<p data-start=\"1648\" data-end=\"1699\" class=\"\">Una breve descripción del tema que has investigado.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1703\" data-end=\"1765\">\r\n<p data-start=\"1705\" data-end=\"1765\" class=\"\">Ejemplos de aplicaciones prácticas actuales en la vida real.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1769\" data-end=\"1813\">\r\n<p data-start=\"1771\" data-end=\"1813\" class=\"\">Avances o tendencias futuras en ese campo.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1818\" data-end=\"2041\">\r\n<p data-start=\"1821\" data-end=\"2041\" class=\"\"><strong data-start=\"1821\" data-end=\"1850\">Presentación de documento:</strong> Prepara un documento donde resumas tu investigación. Incluye imágenes, gráficos o videos relevantes para hacer la presentación más dinámica.</p>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Estructura y Resistividad de los Materiales', '<h3><strong>Investigar Las Siguientes Preguntas:</strong></h3>\r\n<ul data-start=\"715\" data-end=\"903\">\r\n<li data-start=\"106\" data-end=\"196\">¿Cómo influye la estructura atómica en las propiedades eléctricas de un material?</li>\r\n<li data-start=\"197\" data-end=\"306\">¿Cuáles son los factores que afectan la resistividad eléctrica, como la temperatura y las impurezas?</li>\r\n<li data-start=\"307\" data-end=\"391\">¿Qué son los superconductores y cuáles son sus principales características?</li>\r\n<li data-start=\"392\" data-end=\"472\">¿Qué técnicas se utilizan para medir la resistividad de los materiales?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 1.3: Tipos de Transistores y Clasificación', '<h3 class=\"\" data-start=\"71\" data-end=\"178\"><strong data-start=\"75\" data-end=\"178\">Tarea: Tipos de Transistores y su Clasificación según Estructura, Material Semiconductor y Potencia</strong></h3>\r\n<p data-start=\"180\" data-end=\"455\" class=\"\"><strong data-start=\"180\" data-end=\"193\">Objetivo:</strong> Investigar los diferentes tipos de transistores, clasificarlos según su estructura, material semiconductor y potencia, y comparar sus aplicaciones específicas. Esto permitirá entender sus funciones, ventajas y limitaciones en diversas aplicaciones tecnológicas.</p>\r\n<hr class=\"\" data-start=\"457\" data-end=\"460\">\r\n<h3 class=\"\" data-start=\"462\" data-end=\"484\"><strong data-start=\"466\" data-end=\"484\">Instrucciones:</strong></h3>\r\n<ol data-start=\"486\" data-end=\"2842\">\r\n<li class=\"\" data-start=\"486\" data-end=\"1487\">\r\n<p data-start=\"489\" data-end=\"519\" class=\"\"><strong data-start=\"489\" data-end=\"519\">Investigación y Redacción:</strong></p>\r\n<ul data-start=\"523\" data-end=\"1487\">\r\n<li class=\"\" data-start=\"523\" data-end=\"849\">\r\n<p data-start=\"525\" data-end=\"849\" class=\"\"><strong data-start=\"525\" data-end=\"571\">Tipos de Transistores según su Estructura:</strong> Investiga los transistores bipolares (BJT) y los transistores de efecto de campo (FET), detallando las diferencias en sus estructuras, como la disposición de las capas de material semiconductor (NPN, PNP en los BJTs y las características de los MOSFET y JFET en los FETs).</p>\r\n</li>\r\n<li class=\"\" data-start=\"859\" data-end=\"1141\">\r\n<p data-start=\"861\" data-end=\"1141\" class=\"\"><strong data-start=\"861\" data-end=\"888\">Material Semiconductor:</strong> Investiga los diferentes materiales semiconductores utilizados en la fabricación de transistores, tales como <strong data-start=\"1003\" data-end=\"1014\">silicio</strong>, <strong data-start=\"1016\" data-end=\"1028\">germanio</strong> y <strong data-start=\"1031\" data-end=\"1053\">arseniuro de galio</strong>, y cómo influye cada material en el rendimiento y las aplicaciones de los transistores.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1151\" data-end=\"1481\">\r\n<p data-start=\"1153\" data-end=\"1481\" class=\"\"><strong data-start=\"1153\" data-end=\"1186\">Clasificación según Potencia:</strong> Compara los transistores de <strong data-start=\"1220\" data-end=\"1237\">baja potencia</strong> (utilizados en circuitos integrados y pequeños dispositivos electrónicos) y los de <strong data-start=\"1321\" data-end=\"1338\">alta potencia</strong> (empleados en aplicaciones que requieren manejar grandes corrientes y voltajes, como en fuentes de alimentación y amplificadores de potencia).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1488\" data-end=\"1914\">\r\n<p data-start=\"1491\" data-end=\"1539\" class=\"\"><strong data-start=\"1491\" data-end=\"1539\">Comparación entre los Tipos de Transistores:</strong></p>\r\n<ul data-start=\"1543\" data-end=\"1914\">\r\n<li class=\"\" data-start=\"1543\" data-end=\"1728\">\r\n<p data-start=\"1545\" data-end=\"1728\" class=\"\">Elabora una tabla comparativa entre los diferentes tipos de transistores (BJT, MOSFET, JFET, etc.), que incluya sus ventajas, desventajas y las aplicaciones específicas para cada uno.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1732\" data-end=\"1910\">\r\n<p data-start=\"1734\" data-end=\"1910\" class=\"\">Destaca las principales diferencias en términos de <strong data-start=\"1785\" data-end=\"1799\">eficiencia</strong>, <strong data-start=\"1801\" data-end=\"1828\">respuesta de frecuencia</strong>, <strong data-start=\"1830\" data-end=\"1852\">consumo de energía</strong> y <strong data-start=\"1855\" data-end=\"1909\">facilidad de integración en circuitos electrónicos</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1915\" data-end=\"2509\">\r\n<p data-start=\"1918\" data-end=\"1940\" class=\"\"><strong data-start=\"1918\" data-end=\"1940\">Producto Esperado:</strong></p>\r\n<ul data-start=\"1944\" data-end=\"2509\">\r\n<li class=\"\" data-start=\"1944\" data-end=\"2509\">\r\n<p data-start=\"1946\" data-end=\"2039\" class=\"\"><strong data-start=\"1946\" data-end=\"1967\">Documento escrito</strong> (PDF o Word) con la información investigada. El documento debe incluir:</p>\r\n<ul data-start=\"2045\" data-end=\"2509\">\r\n<li class=\"\" data-start=\"2045\" data-end=\"2132\">\r\n<p data-start=\"2047\" data-end=\"2132\" class=\"\">Una introducción breve sobre qué es un transistor y su importancia en la electrónica.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2138\" data-end=\"2258\">\r\n<p data-start=\"2140\" data-end=\"2258\" class=\"\">Descripción detallada de los tipos de transistores según su <strong data-start=\"2200\" data-end=\"2214\">estructura</strong>, <strong data-start=\"2216\" data-end=\"2242\">material semiconductor</strong> y <strong data-start=\"2245\" data-end=\"2257\">potencia</strong>.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2264\" data-end=\"2341\">\r\n<p data-start=\"2266\" data-end=\"2341\" class=\"\">Comparación entre los tipos de transistores y sus aplicaciones específicas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2347\" data-end=\"2509\">\r\n<p data-start=\"2349\" data-end=\"2509\" class=\"\">Conclusiones sobre qué tipo de transistor sería el más adecuado para diferentes escenarios (por ejemplo, uso en amplificadores, circuitos de conmutación, etc.).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"2511\" data-end=\"2797\">\r\n<p data-start=\"2514\" data-end=\"2538\" class=\"\"><strong data-start=\"2514\" data-end=\"2538\">Formato y Extensión:</strong></p>\r\n<ul data-start=\"2542\" data-end=\"2797\">\r\n<li class=\"\" data-start=\"2542\" data-end=\"2591\">\r\n<p data-start=\"2544\" data-end=\"2591\" class=\"\">El documento debe tener un mínimo de 2 páginas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2595\" data-end=\"2685\">\r\n<p data-start=\"2597\" data-end=\"2685\" class=\"\">Usa un formato de texto claro, bien estructurado, con subtítulos y párrafos organizados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2689\" data-end=\"2797\">\r\n<p data-start=\"2691\" data-end=\"2797\" class=\"\">Incluye imágenes o diagramas que ayuden a ilustrar las estructuras de los transistores y sus aplicaciones.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea de Sistemas de Unidades de Medida', '<ul>\r\n<li data-start=\"77\" data-end=\"151\">¿Qué es un sistema de unidades de medida y por qué es importante?</li>\r\n<li data-start=\"152\" data-end=\"229\">¿Cuáles son las principales unidades del Sistema Internacional (SI)?</li>\r\n<li data-start=\"230\" data-end=\"305\">¿En qué se diferencian los sistemas MKS, CGS y el sistema técnico?</li>\r\n<li data-start=\"306\" data-end=\"384\">¿Cómo se realizan conversiones entre diferentes sistemas de unidades?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Múltiplos y Submúltiplos', '<ul>\r\n<li data-start=\"68\" data-end=\"152\">¿Qué son los prefijos del Sistema Internacional (SI) y por qué se utilizan?</li>\r\n<li data-start=\"153\" data-end=\"256\">¿Cuáles son los principales prefijos del SI, desde nano hasta giga, y qué valores representan?</li>\r\n<li data-start=\"257\" data-end=\"369\">¿Qué es la notación científica y cómo facilita la representación de números muy grandes o muy pequeños?</li>\r\n<li data-start=\"370\" data-end=\"465\">¿Cómo se realizan conversiones entre diferentes prefijos del SI y notación científica?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Práctica: Mediciones con Multímetro', '<p><strong>Laboratorio Virtual: \"Mediciones con Multímetro\"</strong></p>\r\n<ul>\r\n<li>Realización de mediciones virtuales (voltaje,corriente y resistencia) en circuitos simulados.</li>\r\n</ul>\r\n<p></p>\r\n<p><strong>Entregable</strong>: Informe de laboratorio con resultados, cálculos y análisis.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 1.4: Comparación con Válvulas de Vacío', '<h3 class=\"\" data-start=\"123\" data-end=\"196\"><strong data-start=\"127\" data-end=\"196\">Tarea: Comparación entre los Transistores y las Válvulas de Vacío</strong></h3>\r\n<p data-start=\"198\" data-end=\"522\" class=\"\"><strong data-start=\"198\" data-end=\"211\">Objetivo:</strong> Investigar las características fundamentales de los transistores y las válvulas de vacío, y realizar una comparación detallada entre ambos en términos de funcionamiento, aplicaciones y ventajas/desventajas. Esto permitirá entender cómo estas tecnologías han influido en el desarrollo de la electrónica moderna.</p>\r\n<hr class=\"\" data-start=\"524\" data-end=\"527\">\r\n<h3 class=\"\" data-start=\"529\" data-end=\"551\"><strong data-start=\"533\" data-end=\"551\">Instrucciones:</strong></h3>\r\n<ol data-start=\"553\" data-end=\"2691\">\r\n<li class=\"\" data-start=\"553\" data-end=\"1050\">\r\n<p data-start=\"556\" data-end=\"586\" class=\"\"><strong data-start=\"556\" data-end=\"586\">Investigación y Redacción:</strong></p>\r\n<ul data-start=\"590\" data-end=\"1050\">\r\n<li class=\"\" data-start=\"590\" data-end=\"826\">\r\n<p data-start=\"592\" data-end=\"826\" class=\"\"><strong data-start=\"592\" data-end=\"614\">Válvulas de Vacío:</strong> Investiga qué son las válvulas de vacío, su estructura y cómo funcionan. Incluye detalles sobre su historia, sus aplicaciones iniciales y sus limitaciones (por ejemplo, tamaño, consumo de energía y durabilidad).</p>\r\n</li>\r\n<li class=\"\" data-start=\"834\" data-end=\"1050\">\r\n<p data-start=\"836\" data-end=\"1050\" class=\"\"><strong data-start=\"836\" data-end=\"853\">Transistores:</strong> Investiga cómo los transistores funcionan como reemplazo de las válvulas de vacío en muchas aplicaciones. Describa los diferentes tipos de transistores, su funcionamiento, ventajas y aplicaciones.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1052\" data-end=\"1794\">\r\n<p data-start=\"1055\" data-end=\"1081\" class=\"\"><strong data-start=\"1055\" data-end=\"1081\">Comparación Detallada:</strong></p>\r\n<ul data-start=\"1085\" data-end=\"1794\">\r\n<li class=\"\" data-start=\"1085\" data-end=\"1794\">\r\n<p data-start=\"1087\" data-end=\"1149\" class=\"\">Elabora una tabla comparativa que incluya aspectos clave como:</p>\r\n<ul data-start=\"1155\" data-end=\"1794\">\r\n<li class=\"\" data-start=\"1155\" data-end=\"1261\">\r\n<p data-start=\"1157\" data-end=\"1261\" class=\"\"><strong data-start=\"1157\" data-end=\"1174\">Tamaño y peso</strong>: ¿Cómo afectan las dimensiones de cada tecnología a su uso en diferentes dispositivos?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1267\" data-end=\"1376\">\r\n<p data-start=\"1269\" data-end=\"1376\" class=\"\"><strong data-start=\"1269\" data-end=\"1294\">Eficiencia energética</strong>: ¿Cuál de las dos tecnologías es más eficiente en términos de consumo de energía?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1382\" data-end=\"1472\">\r\n<p data-start=\"1384\" data-end=\"1472\" class=\"\"><strong data-start=\"1384\" data-end=\"1399\">Durabilidad</strong>: ¿Qué tan duraderas son las válvulas de vacío frente a los transistores?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1478\" data-end=\"1560\">\r\n<p data-start=\"1480\" data-end=\"1560\" class=\"\"><strong data-start=\"1480\" data-end=\"1489\">Costo</strong>: ¿Cuál de las dos tecnologías es más económica de producir y mantener?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1566\" data-end=\"1662\">\r\n<p data-start=\"1568\" data-end=\"1662\" class=\"\"><strong data-start=\"1568\" data-end=\"1596\">Aplicaciones específicas</strong>: ¿En qué tipo de dispositivos o contextos se usa cada tecnología?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1668\" data-end=\"1794\">\r\n<p data-start=\"1670\" data-end=\"1794\" class=\"\"><strong data-start=\"1670\" data-end=\"1697\">Rendimiento y velocidad</strong>: Compara la capacidad de procesamiento, la velocidad de conmutación y la fiabilidad de cada una.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1796\" data-end=\"2346\">\r\n<p data-start=\"1799\" data-end=\"1821\" class=\"\"><strong data-start=\"1799\" data-end=\"1821\">Producto Esperado:</strong></p>\r\n<ul data-start=\"1825\" data-end=\"2346\">\r\n<li class=\"\" data-start=\"1825\" data-end=\"2346\">\r\n<p data-start=\"1827\" data-end=\"1920\" class=\"\"><strong data-start=\"1827\" data-end=\"1848\">Documento escrito</strong> (PDF o Word) con la información investigada. El documento debe incluir:</p>\r\n<ul data-start=\"1926\" data-end=\"2346\">\r\n<li class=\"\" data-start=\"1926\" data-end=\"2070\">\r\n<p data-start=\"1928\" data-end=\"2070\" class=\"\">Una introducción breve sobre qué son las válvulas de vacío y los transistores, y cómo cada uno ha influido en el desarrollo de la electrónica.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2076\" data-end=\"2199\">\r\n<p data-start=\"2078\" data-end=\"2199\" class=\"\">Descripción detallada de cómo funcionan las válvulas de vacío y los transistores, sus aplicaciones y sus características.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2205\" data-end=\"2256\">\r\n<p data-start=\"2207\" data-end=\"2256\" class=\"\">Comparación detallada entre los dos dispositivos.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2262\" data-end=\"2346\">\r\n<p data-start=\"2264\" data-end=\"2346\" class=\"\">Conclusiones sobre en qué situaciones podría ser ventajoso usar uno sobre el otro.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"2348\" data-end=\"2646\">\r\n<p data-start=\"2351\" data-end=\"2375\" class=\"\"><strong data-start=\"2351\" data-end=\"2375\">Formato y Extensión:</strong></p>\r\n<ul data-start=\"2379\" data-end=\"2646\">\r\n<li class=\"\" data-start=\"2379\" data-end=\"2428\">\r\n<p data-start=\"2381\" data-end=\"2428\" class=\"\">El documento debe tener un mínimo de 2 páginas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2432\" data-end=\"2523\">\r\n<p data-start=\"2434\" data-end=\"2523\" class=\"\">Usa un formato de texto claro y bien estructurado, con subtítulos y párrafos organizados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2527\" data-end=\"2646\">\r\n<p data-start=\"2529\" data-end=\"2646\" class=\"\">Incluye imágenes, diagramas o gráficos que ayuden a ilustrar cómo funcionan las válvulas de vacío y los transistores.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 1: Conversiones de Unidades', '<p><strong>Objetivo:</strong> Resolver ejercicios de conversión entre sistemas y múltiplos/submúltiplos.</p>\r\n<p><strong>Entregable:</strong> Documento con soluciones detalladas.<br> </p>\r\n<p><strong>Ejercicios Actualizados:</strong></p>\r\n<ol>\r\n<li> Convertir 2.5 mA a μA.</li>\r\n<li>Expresar 4700 Ω en kΩ.</li>\r\n<li>Convertir 0.025 MV a V.</li>\r\n<li> Calcular la energía (en Joules) que consume una resistencia disipada a 0.5 W durante 2 horas.</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 2: Instrumentos de Medición', '<p><strong>Objetivo:</strong> Analizar y comparar diferentes instrumentos de medición eléctrica y<br>sus aplicaciones.</p>\r\n<p><strong>Entregable:</strong> Informe técnico (3–5 páginas).<br> </p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Actividad Colaborativa-Grupal 3: Mapa Mental', '<p><strong>Objetivo: </strong>Crear un mapa mental (usando Mindomo) sobre las magnitudes eléctricas y sus interrelaciones.</p>\r\n<p><strong>Entregable:</strong> Enlace al mapa mental y documento explicativo.</p>\r\n<ul>\r\n<li><strong>Evaluación:</strong> Estructura (25%), contenido técnico (35%), conexiones (25%) y diseño visual (15%).</li>\r\n<li><strong>Valor:</strong> 40% del módulo.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 2.2: Principio de Operación', '<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Descripción detallada del principio de operación del transistor BJT.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicación sobre el mecanismo de conducción y control de corriente.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Representación gráfica de las curvas características (IC vs VBE, IC vs VCE, etc.).</li>\r\n<li dir=\"ltr\" role=\"presentation\">Cálculos y ecuaciones ilustrando el control de corriente y las características de transferencia del transistor BJT.</li>\r\n</ul>\r\n<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 2.3: Modos de Funcionamiento', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada sobre los modos de funcionamiento del transistor BJT (Corte, Saturación, Activa).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de las condiciones de operación y características de cada región.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Aplicaciones prácticas de cada modo de funcionamiento en circuitos electrónicos.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gráficos mostrando las curvas de salida y transferencia de un transistor en diferentes modos de funcionamiento.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 2.4: Configuraciones', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada de las configuraciones de transistores (Emisor Común, Base Común, Colector Común).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de sus características, ventajas y aplicaciones típicas.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa de las configuraciones, destacando sus principales diferencias y usos en la práctica.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 3.1: Tipos de FET', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada de las características, estructura y funcionamiento de JFET y MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación de las aplicaciones de ambos tipos de transistores.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre JFET y MOSFET, destacando sus principales características y aplicaciones</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 3.2: Construcción y Estructura Interna', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada del proceso de fabricación, materiales utilizados y la estructura interna de los transistores FET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Diagramas representativos de la estructura interna de JFET y MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Esquemas de los procesos de fabricación y las capas utilizadas en JFET y MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 3.3: Principio de Operación', '<h3 dir=\"ltr\">Producto Esperado :</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada del principio de operación de los transistores FET, con énfasis en el control por voltaje y el efecto de campo.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Cálculos matemáticos y gráficos de las características de transferencia (ID vs VGS, gm vs VGS, etc.).<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gráficos que muestran las curvas de salida de JFET y MOSFET en diferentes regiones de operación.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: Ley de Ohm', '<ul>\r\n<li data-start=\"61\" data-end=\"181\">¿Qué establece la Ley de Ohm y cómo se relacionan la corriente, el voltaje y la resistencia en un circuito eléctrico?</li>\r\n<li data-start=\"182\" data-end=\"298\">¿Cómo varía la corriente en un circuito si se aumenta el voltaje o se cambia la resistencia, según la Ley de Ohm?</li>\r\n<li data-start=\"299\" data-end=\"400\">¿Cuáles son las aplicaciones prácticas de la Ley de Ohm en dispositivos eléctricos y electrónicos?</li>\r\n<li data-start=\"401\" data-end=\"523\">¿Qué limitaciones tiene la Ley de Ohm cuando se trata de materiales no ohmicos o circuitos con componentes no lineales?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: Circuitos en Serie y Paralelo', '<ul>\r\n<li data-start=\"120\" data-end=\"215\">¿Qué son los circuitos en serie y en paralelo, y cuáles son sus principales características?</li>\r\n<li data-start=\"216\" data-end=\"298\">¿Cómo se dividen la tensión y la corriente en circuitos en serie y en paralelo?</li>\r\n<li data-start=\"299\" data-end=\"381\">¿Cuáles son las ventajas y desventajas de los circuitos en serie y en paralelo?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Resistencia Equivalente', '<ul>\r\n<li data-start=\"429\" data-end=\"514\">¿Cómo se calcula la resistencia equivalente en un circuito en serie y en paralelo?</li>\r\n<li data-start=\"515\" data-end=\"601\">¿Cómo se analiza un circuito mixto que combina resistencias en serie y en paralelo?</li>\r\n<li data-start=\"602\" data-end=\"710\">¿Qué técnicas de simplificación se utilizan para resolver circuitos con resistencias en serie y paralelo?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: Código de Colores de Resistencias', '<ul>\r\n<li data-start=\"768\" data-end=\"843\">¿Cómo funciona el sistema de codificación por colores para resistencias?</li>\r\n<li data-start=\"844\" data-end=\"936\">¿Cuál es la diferencia entre resistencias de 4, 5 y 6 bandas en cuanto a su codificación?</li>\r\n<li data-start=\"937\" data-end=\"1057\">¿Cómo se determina la tolerancia y el coeficiente de temperatura de una resistencia a partir de su código de colores?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 3.4: Comparación con BJT', '<h3 dir=\"ltr\">Producto Esperado :</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis detallado de las ventajas y desventajas de JFET y MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de las aplicaciones, costos y disponibilidad de ambos tipos de transistores.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre JFET y MOSFET, destacando sus características, aplicaciones y costos.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 4.1: Proceso de Fabricación CMOS', '<p><strong>Preparación del Substrato. Explica:</strong><br><br></p>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Limpieza química<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Oxidación térmica<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Recubrimiento de fotoresist<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Litografía<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Formación de Capas<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Deposición de óxido de compuerta (SiO₂, HfO₂)<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Implantación iónica<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Recocido térmico<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Procesos de Grabado<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Grabado húmedo<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Grabado en seco<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Limpieza<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Pasivación</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 4.2: Estructura de Capas', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción del proceso de fabricación de los MOSFET, desde la preparación del substrato hasta los procesos de grabado.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Detalles sobre la estructura de capas de los MOSFET, incluyendo el substrato, óxido de compuerta, compuerta, drenaje y fuente.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Diagramas y esquemas mostrando la estructura interna del MOSFET y los procesos de fabricación.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 4.3: Mecanismo de Conducción', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada sobre el mecanismo de conducción del MOSFET, incluida la formación del canal y el control de corriente.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Representación matemática de la ecuación de corriente y el factor K.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis de los efectos secundarios que afectan el rendimiento del MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 4.4: Características Eléctricas', '<ol>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Parámetros Estáticos<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">VTH: 0.5-3V<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">IDSS: 0.1-100 mA<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">gm: 1-100 mS<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">ro: 10-100 kΩ<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Parámetros Dinámicos<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Ciss: 1-100 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Coss: 0.1-10 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Crss: 0.01-1 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">tr/tf: 1-100 ns<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Límites de Operación<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">VDSmax: 5-1000V<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">IDmax: 0.1-100A<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">PDmax: 0.1-1000W<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Tjmax: 150-200°C<br><br></p>\r\n</li>\r\n</ul>\r\n</ol>\r\n<p dir=\"ltr\"></p>\r\n<hr>\r\n<p></p>\r\n<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de los parámetros estáticos y dinámicos del MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación de los límites de operación y sus implicaciones en el diseño de circuitos.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p><strong id=\"docs-internal-guid-98c38875-7fff-3772-89fd-baac19aea7f3\">Gráficos que muestren las características eléctricas del MOSFET en diferentes condiciones.<br></strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Circuitos Mixtos Eléctricos', '<ul>\r\n<li data-start=\"1109\" data-end=\"1209\">¿Cómo se realiza el análisis de circuitos mixtos que combinan componentes en serie y en paralelo?</li>\r\n<li data-start=\"1210\" data-end=\"1301\">¿Cuáles son las técnicas de simplificación y resolución paso a paso de circuitos mixtos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: 5: Análisis de Circuitos', '<p><strong>Objetivo:</strong> Resolver problemas de circuitos en serie, paralelo y mixtos.</p>\r\n<p><strong>Entregable:</strong> Documento con diagramas, cálculos y explicaciones.</p>\r\n<p></p>\r\n<p><strong>Ejemplos Actualizados:</strong></p>\r\n<p><br>1. Calcular la resistencia equivalente de tres resistencias en serie:<br>220 Ω, 470 Ω y 1 kΩ.<br>2. En un circuito paralelo con resistencias de 100 Ω, 200 Ω y 300 Ω,<br>determinar la corriente para 12 V.<br>3. Simplificar un circuito mixto y calcular la corriente total.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: Elementos Activos', '<ul>\r\n<li>¿Qué son los elementos activos en un circuito eléctrico, como las fuentes de tensión y corriente, generadores y amplificadores?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Tarea 4.5: Modelos de Operación', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de los modelos de operación del MOSFET (Nivel 1, BSIM, PSP).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de las ecuaciones utilizadas en cada modelo y sus limitaciones.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p><strong id=\"docs-internal-guid-fa8c9657-7fff-46cf-0a09-05925e7efffa\">Análisis de los efectos cuánticos y de alta frecuencia en los modelos avanzados.<br></strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Tarea (Assignment)', 'Examen Final (PRESENCIAL) no hacer', '<p><strong>Opciones de Proyecto:</strong></p>\r\n<p><strong>Fuente de alimentación regulada.<br>■ Sistema de iluminación automatizado.<br>■ Detector de nivel con alarma.<br>■ Temporizador electrónico.<br>■ Proyecto alternativo (previa aprobación).</strong></p>\r\n<p><strong>Entregables:<br>■ Memoria técnica (documento PDF).<br>■ Esquema del circuito.<br>■ Simulación (Proteus o Tinkercad).<br>■ Video demostrativo (5–7 minutos).<br>■ Presentación final.</strong></p>\r\n<p><strong>Evaluación:<br>■ Funcionamiento (30%),<br>■ Diseño y construcción (25%),<br>■ Documentación técnica (20%),<br>■ Presentación y video (15%),<br>■ Originalidad e innovación (10%).<br></strong></p>\r\n<p><strong>Valor: 70% del módulo.</strong></p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Estructura Atómica Tarea', '<p><strong style=\"text-align: initial;\" data-start=\"144\" data-end=\"168\">Lección 1: Estructura Atómica</strong></p>\r\n<p>En esta sección exploraremos los fundamentos de la estructura atómica, incluyendo las partículas subatómicas, el número atómico y másico, así como los conceptos de isótopos e iones. También analizaremos los diferentes modelos atómicos a lo largo de la historia.</p>\r\n<p><strong>Investigar Estas Preguntas:</strong></p>\r\n<ul>\r\n<li> ¿Qué características tienen los protones, neutrones y electrones?</li>\r\n<li>¿Cómo se calcula el número atómico y el número másico?</li>\r\n<li>¿Qué diferencia hay entre un isótopo y un ion?</li>\r\n<li>¿Cuáles son los principales modelos atómicos y cómo han evolucionado?</li>\r\n</ul>\r\n<p>Valor: 2 Puntos</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Ley Universal de Conservación de Energía:', '<p data-start=\"436\" data-end=\"493\"><strong data-start=\"436\" data-end=\"491\">Para profundizar en estos temas, puedes investigar:</strong></p>\r\n<ul data-start=\"494\" data-end=\"747\">\r\n<li class=\"\" data-start=\"417\" data-end=\"474\">\r\n<p data-start=\"420\" data-end=\"474\" class=\"\">¿En qué consiste la <a class=\"autolink\" title=\"Ley de Conservación de la Energía\" href=\"https://lasaedu.t-ecogroup.net/mod/url/view.php?id=227\">Ley de Conservación de la Energía</a>?</p>\r\n</li>\r\n<li class=\"\" data-start=\"475\" data-end=\"520\">\r\n<p data-start=\"478\" data-end=\"520\" class=\"\">¿Por qué se considera una \"ley universal\"?</p>\r\n</li>\r\n<li class=\"\" data-start=\"521\" data-end=\"594\">\r\n<p data-start=\"524\" data-end=\"594\" class=\"\">¿Quiénes fueron los científicos que contribuyeron a formular esta ley?</p>\r\n</li>\r\n<li class=\"\" data-start=\"2018\" data-end=\"2042\">\r\n<p data-start=\"2020\" data-end=\"2042\" class=\"\">Ejemplos cotidianos.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2043\" data-end=\"2064\">\r\n<p data-start=\"2045\" data-end=\"2064\" class=\"\">Tipos de energía.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Lección 6: Conductores Eléctricos', '<h4><strong>Investigar Las Siguientes Preguntas:</strong></h4>\r\n<ul>\r\n<li data-start=\"106\" data-end=\"146\">¿Qué es un conductor eléctrico?</li>\r\n<li data-start=\"147\" data-end=\"230\">¿Cuáles son las principales características de los conductores eléctricos?</li>\r\n<li data-start=\"231\" data-end=\"318\">¿Qué relación existe entre la estructura cristalina y la conducción eléctrica?</li>\r\n<li data-start=\"319\" data-end=\"397\">¿Qué son los electrones libres y qué papel juegan en los conductores?</li>\r\n<li data-start=\"398\" data-end=\"474\">¿Cuáles son los metales más utilizados como conductores eléctricos?</li>\r\n<li data-start=\"475\" data-end=\"571\">¿Qué ventajas tienen las aleaciones sobre los metales puros en aplicaciones eléctricas?</li>\r\n<li data-start=\"572\" data-end=\"653\">¿Qué es la resistividad y cómo influye en la eficiencia de un conductor?</li>\r\n<li data-start=\"654\" data-end=\"726\">Menciona una aplicación práctica de los conductores eléctricos.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Magnitudes Eléctricas Fundamentales', '<ul>\r\n<li data-start=\"91\" data-end=\"220\">¿Qué es un multímetro digital y cómo se utiliza en la medición de corriente (amperio), tensión (voltio) y resistencia (ohmio)?</li>\r\n<li data-start=\"221\" data-end=\"343\">¿Cómo funciona un osciloscopio y qué tipo de señales permite analizar en relación con corriente, tensión y resistencia?</li>\r\n<li data-start=\"344\" data-end=\"440\">¿Cuál es la función de un vatímetro y cómo mide la potencia eléctrica (vatio) en un circuito?</li>\r\n<li data-start=\"441\" data-end=\"554\">¿Para qué se utiliza un medidor de energía (joule, kWh) y cómo determina el consumo energético en un circuito?</li>\r\n<li data-start=\"555\" data-end=\"688\">¿Qué mide un medidor LCR y cuál es su importancia en la caracterización de componentes eléctricos como capacitancia e inductancia?</li>\r\n<li data-start=\"689\" data-end=\"874\">¿Cuáles son las principales técnicas de medición en circuitos eléctricos y cómo se pueden minimizar los errores en la medición de corriente, tensión, resistencia, potencia y energía?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Dispositivos Electrónicos', '<ul>\r\n<li data-start=\"1824\" data-end=\"1899\">¿Cómo se clasifican los dispositivos electrónicos en términos generales?</li>\r\n<li data-start=\"1900\" data-end=\"2024\">¿Cuáles son los circuitos integrados, la optoelectrónica, los sensores y los actuadores, y cómo funcionan en un circuito?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Elementos Pasivos', '<ul>\r\n<li data-start=\"1567\" data-end=\"1684\">¿Qué son los elementos pasivos en un circuito, como las resistencias, condensadores, inductores y transformadores?</li>\r\n<li data-start=\"1685\" data-end=\"1774\">¿Cómo se comportan los elementos pasivos en circuitos de corriente continua y alterna?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: Los Diodos y sus Aplicaciones', '<ul>\r\n<li data-start=\"2078\" data-end=\"2153\">¿Cómo funcionan los diodos y cómo se representa su curva característica?</li>\r\n<li data-start=\"2154\" data-end=\"2243\">¿Cuál es la diferencia entre los diodos rectificadores y sus aplicaciones más comunes?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Construcción de una Fuente de Alimentación', '<ul>\r\n<li data-start=\"2310\" data-end=\"2447\">¿Cuáles son los componentes esenciales para construir una fuente de alimentación (transformador, rectificador, filtrado y regulación)?</li>\r\n<li data-start=\"2448\" data-end=\"2506\">¿Cómo se diseña paso a paso una fuente de alimentación?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Instrumentos de Medida Eléctrica', '<ul>\r\n<li data-start=\"46\" data-end=\"154\">¿Qué es un multímetro digital y cómo se utiliza en la medición de voltaje, corriente y resistencia?</li>\r\n<li data-start=\"155\" data-end=\"234\">¿Cómo funciona un osciloscopio y qué tipo de señales permite analizar?</li>\r\n<li data-start=\"235\" data-end=\"329\">¿Cuál es la función de un vatímetro y cómo mide la potencia eléctrica en un circuito?</li>\r\n<li data-start=\"330\" data-end=\"422\">¿Para qué se utiliza un frecuencímetro y cómo determina la frecuencia de una señal?</li>\r\n<li data-start=\"423\" data-end=\"530\">¿Qué mide un medidor LCR y cuál es su importancia en la caracterización de componentes eléctricos?</li>\r\n<li data-start=\"531\" data-end=\"646\">¿Cuáles son las principales técnicas de medición y cómo se pueden minimizar los errores en los resultados?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: Los Diodos LED y sus Aplicaciones', '<ul>\r\n<li data-start=\"2564\" data-end=\"2677\">¿Cómo funcionan los diodos LED y qué características deben considerarse al calcular la resistencia limitadora?</li>\r\n<li data-start=\"2678\" data-end=\"2757\">¿Cómo se diseñan y utilizan circuitos con LEDs en aplicaciones electrónicas?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Los Diodos Zener y sus Aplicaciones', '<ul>\r\n<li data-start=\"139\" data-end=\"217\">¿Cómo funciona un diodo Zener y cómo se representa su curva característica?</li>\r\n<li data-start=\"218\" data-end=\"319\">¿De qué manera los diodos Zener se utilizan en la regulación de tensión en circuitos electrónicos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: Los Condensadores-Capacitores y sus Aplicaciones', '<ul>\r\n<li data-start=\"392\" data-end=\"485\">¿Cuál es el principio de funcionamiento de un condensador o capacitor y qué tipos existen?</li>\r\n<li data-start=\"486\" data-end=\"606\">¿Cómo se realiza el proceso de carga y descarga en un condensador, y cómo se aplican estos conceptos en circuitos RC?</li>\r\n<li data-start=\"607\" data-end=\"681\">¿Cómo se calculan las propiedades de los condensadores en circuitos RC?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 1: Análisis de Circuitos con Condensadores', '<p><strong>Objetivo:</strong> Resolver ejercicios de carga/descarga y cálculos en circuitos RC.</p>\r\n<p></p>\r\n<p><strong>Entregable:</strong> Informe técnico con simulaciones y cálculos.</p>\r\n<p></p>\r\n<p><strong>Ejercicios Actualizados:</strong></p>\r\n<ol>\r\n<li> Calcular la constante de tiempo (τ) de un condensador de 100 μF con<br>una resistencia de 10 kΩ.</li>\r\n<li>Determinar la capacidad equivalente de tres condensadores (10 μF, 22<br>μF y 47 μF) en serie.<br>3. Diseñar un circuito RC que genere un retardo de 1 segundo.</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 2: Clasificación de los Diodos', '<p><strong>Objetivo:</strong> Investigar y clasificar al menos 6 tipos de diodos, detallando características y aplicaciones.</p>\r\n<p></p>\r\n<p><strong>Entregable</strong>: Informe técnic</p>\r\n<p></p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea:  Interruptores, Conmutadores y Pulsadores', '<ul>\r\n<li data-start=\"808\" data-end=\"924\">¿Cuáles son los tipos de interruptores, conmutadores y pulsadores, y cuáles son sus principios de funcionamiento?</li>\r\n<li data-start=\"925\" data-end=\"1056\">¿Cómo se representa la simbología de interruptores, conmutadores y pulsadores, y qué aplicaciones prácticas tienen en circuitos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Relé o Relevador', '<ul>\r\n<li data-start=\"1097\" data-end=\"1156\">¿Cómo funciona un relé o relevador, y qué tipos existen?</li>\r\n<li data-start=\"1157\" data-end=\"1255\">¿Cuáles son las características eléctricas de un relé y cómo se aplica en circuitos de control?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: De los  Transformadores', '<ul>\r\n<li data-start=\"1332\" data-end=\"1428\">¿Cuál es el principio de inducción electromagnética en el funcionamiento de un transformador?</li>\r\n<li data-start=\"1429\" data-end=\"1550\">¿Cómo se estructura un transformador, y cuál es la relación de transformación entre sus bobinas primaria y secundaria?</li>\r\n<li data-start=\"1551\" data-end=\"1659\">¿Qué tipos de transformadores existen, y cómo afectan las pérdidas y el rendimiento en su funcionamiento?</li>\r\n<li data-start=\"1660\" data-end=\"1748\">¿Cuáles son las aplicaciones prácticas de los transformadores en sistemas eléctricos?</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 1.2: Funcionalidad General de los Transistores', '<p dir=\"ltr\">Investigación sobre la funcionalidad general de los transistores:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Concepto de Amplificación</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Principio de Conmutación</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Control de Corriente y Voltaje</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Funcionamiento como Interruptor Electrónico</p>\r\n</li>\r\n</ul>\r\n<p></p>\r\n<p dir=\"ltr\"><strong>Producto Esperado:</strong></p>\r\n<ul id=\"yui_3_18_1_1_1742941190269_193\" data-start=\"1063\" data-end=\"1303\">\r\n<li id=\"yui_3_18_1_1_1742941190269_201\" class=\"\" data-start=\"1063\" data-end=\"1157\">\r\n<p data-start=\"1065\" data-end=\"1157\" class=\"\" id=\"yui_3_18_1_1_1742941190269_200\"><strong id=\"yui_3_18_1_1_1742941190269_199\" data-start=\"1065\" data-end=\"1086\">Documento escrito</strong> (PDF o Word) de <strong data-start=\"1103\" data-end=\"1123\">mínimo 3 páginas</strong> con la información investigada.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea: 4.6 Comparación con BJT', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación detallada entre MOSFET y BJT en términos de potencia, eficiencia energética, velocidad de conmutación, costos, y aplicaciones específicas.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre MOSFET y BJT, destacando sus principales diferencias y ventajas.<br><br></p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'la Calidad en la Industria Tabacalera', '<h3><strong data-start=\"144\" data-end=\"168\">Lección 1: la calidad en la industria tabacalera dominicana</strong></h3>\r\n<p>En esta sección exploraremos los fundamentos de la de la calidad en la industria.</p>\r\n<h5><strong>Define los siguientes conceptos </strong></h5>\r\n<p><strong data-start=\"144\" data-end=\"168\"> </strong>1- Calidad.</p>\r\n<p>2- Normal ISO 9001;2015.</p>\r\n<p>3- Importancia de la calidad en las organizaciones.</p>\r\n<p>Valor 2 puntos. </p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 1.1: Historia y Evolución de los Transistores', '<p data-pm-slice=\"1 1 []\"><strong>Introducción</strong></p>\r\n<p>El transistor es uno de los inventos más revolucionarios del siglo XX, cuya aparición en 1947 marcó el inicio de la era de la electrónica moderna. Su descubrimiento surgió como resultado de la necesidad de encontrar un reemplazo eficiente para las voluminosas y poco confiables válvulas de vacío utilizadas en circuitos electrónicos. Gracias al trabajo pionero de John Bardeen, William Shockley y Walter Brattain en los laboratorios Bell, el transistor se convirtió en la base del desarrollo tecnológico que dio origen a la computación moderna, las telecomunicaciones y numerosos dispositivos electrónicos.</p>\r\n<p>Desde su invención, los transistores han experimentado una evolución significativa a lo largo de cuatro generaciones, cada una caracterizada por avances en materiales, diseño y aplicaciones. En la Primera Generación (1947-1950), los transistores de contacto puntual marcaron el inicio de esta tecnología. La Segunda Generación (1950-1960) introdujo los semiconductores y permitió la fabricación de transistores de mayor confiabilidad y menor consumo de energía. La Tercera Generación (1960-1970) trajo consigo el desarrollo de los circuitos integrados, que permitieron la miniaturización y la mejora en el rendimiento de los dispositivos electrónicos. Finalmente, la Cuarta Generación (1970-presente) ha sido testigo de una miniaturización extrema y la creación de transistores de tamaño nanométrico, los cuales son esenciales en la fabricación de microprocesadores y tecnologías avanzadas.</p>\r\n<p>El impacto de los transistores en la revolución electrónica es innegable. Sin ellos, el desarrollo de computadoras, teléfonos inteligentes, redes de comunicación y sistemas de automatización no habría sido posible. Su evolución ha permitido la creación de dispositivos cada vez más potentes y eficientes, transformando la vida cotidiana y la manera en que interactuamos con la tecnología.</p>\r\n<p>Esta tarea explorará en detalle el descubrimiento del transistor, las contribuciones de sus inventores, la evolución histórica a través de sus cuatro generaciones y el impacto que ha tenido en la revolución electrónica. Además, se presentará una línea de tiempo con los principales hitos de su desarrollo, proporcionando una visión clara y estructurada de su importancia en el mundo actual.</p>\r\n<p></p>\r\n<p></p>\r\n<ul>\r\n<li class=\"\" data-start=\"300\" data-end=\"1030\">\r\n<p data-start=\"303\" data-end=\"323\" class=\"\"><strong data-start=\"303\" data-end=\"321\">Investigación:</strong></p>\r\n<ul data-start=\"327\" data-end=\"1030\">\r\n<li class=\"\" data-start=\"327\" data-end=\"414\">\r\n<p data-start=\"329\" data-end=\"414\" class=\"\">Investiga sobre el <strong data-start=\"348\" data-end=\"389\">descubrimiento del transistor en 1947</strong> y explica cómo surgió.</p>\r\n</li>\r\n<li class=\"\" data-start=\"418\" data-end=\"523\">\r\n<p data-start=\"420\" data-end=\"523\" class=\"\">Describe las <strong data-start=\"433\" data-end=\"469\">contribuciones de los inventores</strong> (John Bardeen, William Shockley y Walter Brattain).</p>\r\n</li>\r\n<li class=\"\" data-start=\"527\" data-end=\"950\">\r\n<p data-start=\"529\" data-end=\"613\" class=\"\">Explica la <strong data-start=\"540\" data-end=\"563\">evolución histórica</strong> de los transistores en sus cuatro generaciones:</p>\r\n<ol data-start=\"619\" data-end=\"950\">\r\n<li class=\"\" data-start=\"619\" data-end=\"686\">\r\n<p data-start=\"622\" data-end=\"686\" class=\"\"><strong data-start=\"622\" data-end=\"657\">Primera Generación (1947-1950):</strong> Características y avances.</p>\r\n</li>\r\n<li class=\"\" data-start=\"692\" data-end=\"771\">\r\n<p data-start=\"695\" data-end=\"771\" class=\"\"><strong data-start=\"695\" data-end=\"730\">Segunda Generación (1950-1960):</strong> Uso de semiconductores y aplicaciones.</p>\r\n</li>\r\n<li class=\"\" data-start=\"777\" data-end=\"852\">\r\n<p data-start=\"780\" data-end=\"852\" class=\"\"><strong data-start=\"780\" data-end=\"815\">Tercera Generación (1960-1970):</strong> Avance hacia circuitos integrados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"858\" data-end=\"950\">\r\n<p data-start=\"861\" data-end=\"950\" class=\"\"><strong data-start=\"861\" data-end=\"899\">Cuarta Generación (1970-presente):</strong> Miniaturización y transistores en la actualidad.</p>\r\n</li>\r\n</ol>\r\n</li>\r\n<li class=\"\" data-start=\"954\" data-end=\"1030\">\r\n<p data-start=\"956\" data-end=\"1030\" class=\"\">Analiza el <strong data-start=\"967\" data-end=\"1027\">impacto de los transistores en la revolución electrónica</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1032\" data-end=\"1303\">\r\n<p data-start=\"1035\" data-end=\"1059\" class=\"\"><strong data-start=\"1035\" data-end=\"1057\">Producto esperado:</strong></p>\r\n<ul data-start=\"1063\" data-end=\"1303\">\r\n<li class=\"\" data-start=\"1063\" data-end=\"1157\">\r\n<p data-start=\"1065\" data-end=\"1157\" class=\"\"><strong data-start=\"1065\" data-end=\"1086\">Documento escrito</strong> (PDF o Word) de <strong data-start=\"1103\" data-end=\"1123\">mínimo 2 páginas</strong> con la información investigada.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1161\" data-end=\"1303\">\r\n<p data-start=\"1163\" data-end=\"1303\" class=\"\"><strong data-start=\"1163\" data-end=\"1182\">Línea de tiempo</strong> con los principales hitos de la evolución del transistor. (Puede ser en PowerPoint, Word, Canva o a mano y escaneado).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio:  Documentación y Control en Producción de Cigarros', '<h2 dir=\"ltr\">Ejercicio </h2>\r\n<p dir=\"ltr\">Caso:<br>Durante la revisión de registros en el área de torcido, detectas que un colaborador llenó los formatos con retraso y algunos campos quedaron incompletos.</p>\r\n<p dir=\"ltr\">Actividad:<br>Redacta cómo abordarías la situación con el colaborador, asegurando:</p>\r\n<ul>\r\n<li>Explicar la importancia de los registros en tiempo real.</li>\r\n<li>Motivar a la responsabilidad sin desmoralizar.</li>\r\n<li>Proponer una acción inmediata para evitar la repetición.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio: Herramientas de Calidad y Control Estadístico (SPC)', '<h2 dir=\"ltr\">Ejercicio </h2>\r\n<p dir=\"ltr\">Caso:<br>En un análisis de Pareto, el supervisor descubre que el 70% de los rechazos en torcido se deben a humedad incorrecta de la hoja.</p>\r\n<p dir=\"ltr\"><strong>Actividad:</strong><br>Redacta cómo comunicarías este hallazgo al equipo, explicando el problema con datos, resaltando su importancia y motivando a trabajar en conjunto para corregir la causa principal.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', ' Ejercicio: Mejora Continua y Resolución de Problemas', '<h2 dir=\"ltr\"> Ejercicio </h2>\r\n<p dir=\"ltr\">Caso:<br>En el área de empaque, un lote de cigarros presenta un 4% de anillas mal colocadas. El supervisor aplica los 5 Porqués y descubre que la causa raíz es la falta de capacitación en el uso de una nueva herramienta.</p>\r\n<p dir=\"ltr\"><strong>Actividad:</strong><br>Redacta un mensaje breve dirigido al equipo, explicando el hallazgo y motivándolos a participar en la capacitación como parte de la mejora continua.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Campos de Aplicación de la Electrónica', '<p></p>\r\n<p data-start=\"0\" data-end=\"990\" class=\"\">La electrónica es una disciplina fundamental que abarca una amplia gama de aplicaciones que transforman la tecnología y la vida cotidiana. La <strong data-start=\"142\" data-end=\"177\">electrónica analógica y digital</strong> son las bases sobre las cuales se desarrollan los sistemas modernos, desde circuitos básicos hasta complejos procesadores. Por otro lado, la <strong data-start=\"319\" data-end=\"339\">microelectrónica</strong> se enfoca en la fabricación de componentes diminutos que permiten dispositivos de alto rendimiento en áreas como <strong data-start=\"453\" data-end=\"465\">potencia</strong> y <strong data-start=\"468\" data-end=\"487\">optoelectrónica</strong>, esenciales en la creación de productos de consumo y sistemas de comunicación avanzados. En el campo de la <strong data-start=\"595\" data-end=\"607\">robótica</strong>, la electrónica es clave para el diseño de máquinas inteligentes, mientras que en <strong data-start=\"690\" data-end=\"712\">telecomunicaciones</strong> es responsable de la transmisión y recepción de señales a través de diversos medios. Finalmente, la <strong data-start=\"813\" data-end=\"831\">bioelectrónica</strong> ha revolucionado el sector de la salud, desarrollando dispositivos médicos que interactúan con el cuerpo humano para diagnósticos y tratamientos más precisos.</p>\r\n<p data-start=\"992\" data-end=\"1268\" class=\"\">Para profundizar en estos temas, investiga cómo la <strong data-start=\"1043\" data-end=\"1063\">microelectrónica</strong> ha influido en el avance de los teléfonos móviles y dispositivos portátiles, y cómo la <strong data-start=\"1151\" data-end=\"1169\">bioelectrónica</strong> está transformando la medicina moderna a través de nuevos dispositivos de monitoreo y tratamiento.</p>\r\n<p data-start=\"109\" data-end=\"145\" class=\"\"><strong data-start=\"109\" data-end=\"145\">Instrucciones para la Actividad:</strong></p>\r\n<ol data-start=\"147\" data-end=\"2311\">\r\n<li class=\"\" data-start=\"147\" data-end=\"499\">\r\n<p data-start=\"150\" data-end=\"499\" class=\"\"><strong data-start=\"150\" data-end=\"175\">Introducción al Tema:</strong> Lee atentamente el párrafo introductorio sobre los diferentes campos de la electrónica, incluyendo la electrónica analógica y digital, la microelectrónica, la robótica, las telecomunicaciones y la bioelectrónica. Este conocimiento te ayudará a comprender cómo estas disciplinas se aplican en diversas áreas tecnológicas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"501\" data-end=\"1521\">\r\n<p data-start=\"504\" data-end=\"613\" class=\"\"><strong data-start=\"504\" data-end=\"536\">Investigación Personalizada:</strong> Elige uno de los siguientes temas de interés para investigar más a fondo:</p>\r\n<ul data-start=\"621\" data-end=\"1521\">\r\n<li class=\"\" data-start=\"621\" data-end=\"806\">\r\n<p data-start=\"623\" data-end=\"806\" class=\"\"><strong data-start=\"623\" data-end=\"659\">Electrónica Analógica y Digital:</strong> Investiga las diferencias entre ambos tipos de circuitos y cómo se aplican en dispositivos comunes (como radios, televisores, computadoras, etc.).</p>\r\n</li>\r\n<li class=\"\" data-start=\"810\" data-end=\"1029\">\r\n<p data-start=\"812\" data-end=\"1029\" class=\"\"><strong data-start=\"812\" data-end=\"851\">Microelectrónica y Optoelectrónica:</strong> Investiga cómo los avances en microelectrónica han permitido el desarrollo de dispositivos portátiles y qué aplicaciones tiene la optoelectrónica en las comunicaciones modernas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1033\" data-end=\"1156\">\r\n<p data-start=\"1035\" data-end=\"1156\" class=\"\"><strong data-start=\"1035\" data-end=\"1048\">Robótica:</strong> Investiga cómo los circuitos electrónicos se utilizan en la creación de robots y automatización industrial.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1160\" data-end=\"1337\">\r\n<p data-start=\"1162\" data-end=\"1337\" class=\"\"><strong data-start=\"1162\" data-end=\"1185\">Telecomunicaciones:</strong> Investiga cómo la electrónica permite la transmisión de señales de voz y datos a través de diferentes tecnologías (como redes móviles, internet, etc.).</p>\r\n</li>\r\n<li class=\"\" data-start=\"1341\" data-end=\"1521\">\r\n<p data-start=\"1343\" data-end=\"1521\" class=\"\"><strong data-start=\"1343\" data-end=\"1362\">Bioelectrónica:</strong> Investiga cómo los dispositivos electrónicos interactúan con el cuerpo humano en el campo de la medicina, tales como marcapasos o dispositivos de diagnóstico.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1523\" data-end=\"1817\">\r\n<p data-start=\"1526\" data-end=\"1638\" class=\"\"><strong data-start=\"1526\" data-end=\"1550\">Entrega del Informe:</strong> Una vez hayas seleccionado tu tema de investigación, escribe un informe que incluya:</p>\r\n<ul data-start=\"1646\" data-end=\"1817\">\r\n<li class=\"\" data-start=\"1646\" data-end=\"1699\">\r\n<p data-start=\"1648\" data-end=\"1699\" class=\"\">Una breve descripción del tema que has investigado.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1703\" data-end=\"1765\">\r\n<p data-start=\"1705\" data-end=\"1765\" class=\"\">Ejemplos de aplicaciones prácticas actuales en la vida real.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1769\" data-end=\"1813\">\r\n<p data-start=\"1771\" data-end=\"1813\" class=\"\">Avances o tendencias futuras en ese campo.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1818\" data-end=\"2041\">\r\n<p data-start=\"1821\" data-end=\"2041\" class=\"\"><strong data-start=\"1821\" data-end=\"1850\">Presentación de documento:</strong> Prepara un documento donde resumas tu investigación. Incluye imágenes, gráficos o videos relevantes para hacer la presentación más dinámica.</p>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio: Modelos de Excelencia y Six Sigma en Tabaco', '<p dir=\"ltr\">Ejercicio </p>\r\n<p dir=\"ltr\">Caso:<br>Una evaluación organizacional basada en EFQM muestra que el área de empaque presenta retrasos y errores frecuentes en anillado, afectando la percepción del cliente. El gerente de calidad debe decidir cómo comunicar los resultados y orientar al equipo hacia una solución.</p>\r\n<p dir=\"ltr\"><strong>Actividad:</strong><br>Redacta un breve mensaje dirigido al equipo de empaque, en el que expliques el problema identificado y resaltes cómo corregirlo contribuirá a la estrategia global de excelencia de la fábrica.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio: Supervisión Activa y Gestión del Cambio', '<h2 dir=\"ltr\">Ejercicio </h2>\r\n<p dir=\"ltr\">Caso:<br>Un cambio en la receta de liga genera incertidumbre entre torcedores, quienes temen que el cigarro pierda su sabor característico. El supervisor debe comunicar la decisión de forma clara y empática.</p>\r\n<p dir=\"ltr\"><strong>Actividad:</strong><br>Redacta un mensaje breve para tu equipo, explicando la razón del cambio, cómo se asegura la calidad sensorial y motivando a colaborar durante la transición.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio: Análisis de Datos para la Calidad', '<h2 dir=\"ltr\"> Ejercicio</h2>\r\n<p dir=\"ltr\"><strong>Caso:</strong><br>El sistema de control digital muestra que la variación de peso de los cigarros ha aumentado en las últimas dos semanas. El supervisor debe comunicar la situación al equipo de torcido.</p>\r\n<p dir=\"ltr\"><strong>Actividad:</strong><br>Redacta un mensaje breve explicando el problema, destacando la importancia del control de peso para la calidad sensorial y motivando al equipo a reforzar la atención en su trabajo.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 1.3: Tipos de Transistores y Clasificación', '<h3 class=\"\" data-start=\"71\" data-end=\"178\"><strong data-start=\"75\" data-end=\"178\">Tarea: Tipos de Transistores y su Clasificación según Estructura, Material Semiconductor y Potencia</strong></h3>\r\n<p data-start=\"180\" data-end=\"455\" class=\"\"><strong data-start=\"180\" data-end=\"193\">Objetivo:</strong> Investigar los diferentes tipos de transistores, clasificarlos según su estructura, material semiconductor y potencia, y comparar sus aplicaciones específicas. Esto permitirá entender sus funciones, ventajas y limitaciones en diversas aplicaciones tecnológicas.</p>\r\n<hr class=\"\" data-start=\"457\" data-end=\"460\">\r\n<h3 class=\"\" data-start=\"462\" data-end=\"484\"><strong data-start=\"466\" data-end=\"484\">Instrucciones:</strong></h3>\r\n<ol data-start=\"486\" data-end=\"2842\">\r\n<li class=\"\" data-start=\"486\" data-end=\"1487\">\r\n<p data-start=\"489\" data-end=\"519\" class=\"\"><strong data-start=\"489\" data-end=\"519\">Investigación y Redacción:</strong></p>\r\n<ul data-start=\"523\" data-end=\"1487\">\r\n<li class=\"\" data-start=\"523\" data-end=\"849\">\r\n<p data-start=\"525\" data-end=\"849\" class=\"\"><strong data-start=\"525\" data-end=\"571\">Tipos de Transistores según su Estructura:</strong> Investiga los transistores bipolares (BJT) y los transistores de efecto de campo (FET), detallando las diferencias en sus estructuras, como la disposición de las capas de material semiconductor (NPN, PNP en los BJTs y las características de los MOSFET y JFET en los FETs).</p>\r\n</li>\r\n<li class=\"\" data-start=\"859\" data-end=\"1141\">\r\n<p data-start=\"861\" data-end=\"1141\" class=\"\"><strong data-start=\"861\" data-end=\"888\">Material Semiconductor:</strong> Investiga los diferentes materiales semiconductores utilizados en la fabricación de transistores, tales como <strong data-start=\"1003\" data-end=\"1014\">silicio</strong>, <strong data-start=\"1016\" data-end=\"1028\">germanio</strong> y <strong data-start=\"1031\" data-end=\"1053\">arseniuro de galio</strong>, y cómo influye cada material en el rendimiento y las aplicaciones de los transistores.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1151\" data-end=\"1481\">\r\n<p data-start=\"1153\" data-end=\"1481\" class=\"\"><strong data-start=\"1153\" data-end=\"1186\">Clasificación según Potencia:</strong> Compara los transistores de <strong data-start=\"1220\" data-end=\"1237\">baja potencia</strong> (utilizados en circuitos integrados y pequeños dispositivos electrónicos) y los de <strong data-start=\"1321\" data-end=\"1338\">alta potencia</strong> (empleados en aplicaciones que requieren manejar grandes corrientes y voltajes, como en fuentes de alimentación y amplificadores de potencia).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1488\" data-end=\"1914\">\r\n<p data-start=\"1491\" data-end=\"1539\" class=\"\"><strong data-start=\"1491\" data-end=\"1539\">Comparación entre los Tipos de Transistores:</strong></p>\r\n<ul data-start=\"1543\" data-end=\"1914\">\r\n<li class=\"\" data-start=\"1543\" data-end=\"1728\">\r\n<p data-start=\"1545\" data-end=\"1728\" class=\"\">Elabora una tabla comparativa entre los diferentes tipos de transistores (BJT, MOSFET, JFET, etc.), que incluya sus ventajas, desventajas y las aplicaciones específicas para cada uno.</p>\r\n</li>\r\n<li class=\"\" data-start=\"1732\" data-end=\"1910\">\r\n<p data-start=\"1734\" data-end=\"1910\" class=\"\">Destaca las principales diferencias en términos de <strong data-start=\"1785\" data-end=\"1799\">eficiencia</strong>, <strong data-start=\"1801\" data-end=\"1828\">respuesta de frecuencia</strong>, <strong data-start=\"1830\" data-end=\"1852\">consumo de energía</strong> y <strong data-start=\"1855\" data-end=\"1909\">facilidad de integración en circuitos electrónicos</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1915\" data-end=\"2509\">\r\n<p data-start=\"1918\" data-end=\"1940\" class=\"\"><strong data-start=\"1918\" data-end=\"1940\">Producto Esperado:</strong></p>\r\n<ul data-start=\"1944\" data-end=\"2509\">\r\n<li class=\"\" data-start=\"1944\" data-end=\"2509\">\r\n<p data-start=\"1946\" data-end=\"2039\" class=\"\"><strong data-start=\"1946\" data-end=\"1967\">Documento escrito</strong> (PDF o Word) con la información investigada. El documento debe incluir:</p>\r\n<ul data-start=\"2045\" data-end=\"2509\">\r\n<li class=\"\" data-start=\"2045\" data-end=\"2132\">\r\n<p data-start=\"2047\" data-end=\"2132\" class=\"\">Una introducción breve sobre qué es un transistor y su importancia en la electrónica.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2138\" data-end=\"2258\">\r\n<p data-start=\"2140\" data-end=\"2258\" class=\"\">Descripción detallada de los tipos de transistores según su <strong data-start=\"2200\" data-end=\"2214\">estructura</strong>, <strong data-start=\"2216\" data-end=\"2242\">material semiconductor</strong> y <strong data-start=\"2245\" data-end=\"2257\">potencia</strong>.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2264\" data-end=\"2341\">\r\n<p data-start=\"2266\" data-end=\"2341\" class=\"\">Comparación entre los tipos de transistores y sus aplicaciones específicas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2347\" data-end=\"2509\">\r\n<p data-start=\"2349\" data-end=\"2509\" class=\"\">Conclusiones sobre qué tipo de transistor sería el más adecuado para diferentes escenarios (por ejemplo, uso en amplificadores, circuitos de conmutación, etc.).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"2511\" data-end=\"2797\">\r\n<p data-start=\"2514\" data-end=\"2538\" class=\"\"><strong data-start=\"2514\" data-end=\"2538\">Formato y Extensión:</strong></p>\r\n<ul data-start=\"2542\" data-end=\"2797\">\r\n<li class=\"\" data-start=\"2542\" data-end=\"2591\">\r\n<p data-start=\"2544\" data-end=\"2591\" class=\"\">El documento debe tener un mínimo de 2 páginas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2595\" data-end=\"2685\">\r\n<p data-start=\"2597\" data-end=\"2685\" class=\"\">Usa un formato de texto claro, bien estructurado, con subtítulos y párrafos organizados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2689\" data-end=\"2797\">\r\n<p data-start=\"2691\" data-end=\"2797\" class=\"\">Incluye imágenes o diagramas que ayuden a ilustrar las estructuras de los transistores y sus aplicaciones.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ol>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Cuestionario (Quiz)', 'Cuestionario 1: Conductores y Aislantes', '<ul>\r\n<li data-start=\"246\" data-end=\"367\"><strong data-start=\"248\" data-end=\"259\">Formato</strong>: El examen consta de 10 preguntas, que incluyen: </li>\r\n</ul>\r\n<p></p>\r\n<ul>\r\n<li data-start=\"368\" data-end=\"425\"><strong data-start=\"370\" data-end=\"380\">Tiempo</strong>: Tienes 1 Hora para completar el examen.</li>\r\n<li data-start=\"426\" data-end=\"505\"><strong data-start=\"428\" data-end=\"437\">Valor</strong>: Este examen representa el 30% de la calificación final del módulo.</li>\r\n<li><strong data-start=\"508\" data-end=\"525\">Instrucciones</strong>: Lee cuidadosamente cada pregunta antes de responder. Asegúrate de completar todas las preguntas dentro del tiempo asignado mucha suerte.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Cuestionario (Quiz)', 'Cuestionario 2: Semiconductores', '<ul>\r\n<li data-start=\"246\" data-end=\"367\"><strong data-start=\"248\" data-end=\"259\">Formato</strong>: El examen consta de 10 preguntas, que incluyen: </li>\r\n</ul>\r\n<p></p>\r\n<ul>\r\n<li data-start=\"368\" data-end=\"425\"><strong data-start=\"370\" data-end=\"380\">Tiempo</strong>: Tienes 1 Hora para completar el examen.</li>\r\n<li data-start=\"426\" data-end=\"505\"><strong data-start=\"428\" data-end=\"437\">Valor</strong>: Este examen representa el 30% de la calificación final del módulo.</li>\r\n<li><strong data-start=\"508\" data-end=\"525\">Instrucciones</strong>: Lee cuidadosamente cada pregunta antes de responder. Asegúrate de completar todas las preguntas dentro del tiempo asignado mucha suerte.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 1.4: Comparación con Válvulas de Vacío', '<h3 class=\"\" data-start=\"123\" data-end=\"196\"><strong data-start=\"127\" data-end=\"196\">Tarea: Comparación entre los Transistores y las Válvulas de Vacío</strong></h3>\r\n<p data-start=\"198\" data-end=\"522\" class=\"\"><strong data-start=\"198\" data-end=\"211\">Objetivo:</strong> Investigar las características fundamentales de los transistores y las válvulas de vacío, y realizar una comparación detallada entre ambos en términos de funcionamiento, aplicaciones y ventajas/desventajas. Esto permitirá entender cómo estas tecnologías han influido en el desarrollo de la electrónica moderna.</p>\r\n<hr class=\"\" data-start=\"524\" data-end=\"527\">\r\n<h3 class=\"\" data-start=\"529\" data-end=\"551\"><strong data-start=\"533\" data-end=\"551\">Instrucciones:</strong></h3>\r\n<ol data-start=\"553\" data-end=\"2691\">\r\n<li class=\"\" data-start=\"553\" data-end=\"1050\">\r\n<p data-start=\"556\" data-end=\"586\" class=\"\"><strong data-start=\"556\" data-end=\"586\">Investigación y Redacción:</strong></p>\r\n<ul data-start=\"590\" data-end=\"1050\">\r\n<li class=\"\" data-start=\"590\" data-end=\"826\">\r\n<p data-start=\"592\" data-end=\"826\" class=\"\"><strong data-start=\"592\" data-end=\"614\">Válvulas de Vacío:</strong> Investiga qué son las válvulas de vacío, su estructura y cómo funcionan. Incluye detalles sobre su historia, sus aplicaciones iniciales y sus limitaciones (por ejemplo, tamaño, consumo de energía y durabilidad).</p>\r\n</li>\r\n<li class=\"\" data-start=\"834\" data-end=\"1050\">\r\n<p data-start=\"836\" data-end=\"1050\" class=\"\"><strong data-start=\"836\" data-end=\"853\">Transistores:</strong> Investiga cómo los transistores funcionan como reemplazo de las válvulas de vacío en muchas aplicaciones. Describa los diferentes tipos de transistores, su funcionamiento, ventajas y aplicaciones.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1052\" data-end=\"1794\">\r\n<p data-start=\"1055\" data-end=\"1081\" class=\"\"><strong data-start=\"1055\" data-end=\"1081\">Comparación Detallada:</strong></p>\r\n<ul data-start=\"1085\" data-end=\"1794\">\r\n<li class=\"\" data-start=\"1085\" data-end=\"1794\">\r\n<p data-start=\"1087\" data-end=\"1149\" class=\"\">Elabora una tabla comparativa que incluya aspectos clave como:</p>\r\n<ul data-start=\"1155\" data-end=\"1794\">\r\n<li class=\"\" data-start=\"1155\" data-end=\"1261\">\r\n<p data-start=\"1157\" data-end=\"1261\" class=\"\"><strong data-start=\"1157\" data-end=\"1174\">Tamaño y peso</strong>: ¿Cómo afectan las dimensiones de cada tecnología a su uso en diferentes dispositivos?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1267\" data-end=\"1376\">\r\n<p data-start=\"1269\" data-end=\"1376\" class=\"\"><strong data-start=\"1269\" data-end=\"1294\">Eficiencia energética</strong>: ¿Cuál de las dos tecnologías es más eficiente en términos de consumo de energía?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1382\" data-end=\"1472\">\r\n<p data-start=\"1384\" data-end=\"1472\" class=\"\"><strong data-start=\"1384\" data-end=\"1399\">Durabilidad</strong>: ¿Qué tan duraderas son las válvulas de vacío frente a los transistores?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1478\" data-end=\"1560\">\r\n<p data-start=\"1480\" data-end=\"1560\" class=\"\"><strong data-start=\"1480\" data-end=\"1489\">Costo</strong>: ¿Cuál de las dos tecnologías es más económica de producir y mantener?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1566\" data-end=\"1662\">\r\n<p data-start=\"1568\" data-end=\"1662\" class=\"\"><strong data-start=\"1568\" data-end=\"1596\">Aplicaciones específicas</strong>: ¿En qué tipo de dispositivos o contextos se usa cada tecnología?</p>\r\n</li>\r\n<li class=\"\" data-start=\"1668\" data-end=\"1794\">\r\n<p data-start=\"1670\" data-end=\"1794\" class=\"\"><strong data-start=\"1670\" data-end=\"1697\">Rendimiento y velocidad</strong>: Compara la capacidad de procesamiento, la velocidad de conmutación y la fiabilidad de cada una.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"1796\" data-end=\"2346\">\r\n<p data-start=\"1799\" data-end=\"1821\" class=\"\"><strong data-start=\"1799\" data-end=\"1821\">Producto Esperado:</strong></p>\r\n<ul data-start=\"1825\" data-end=\"2346\">\r\n<li class=\"\" data-start=\"1825\" data-end=\"2346\">\r\n<p data-start=\"1827\" data-end=\"1920\" class=\"\"><strong data-start=\"1827\" data-end=\"1848\">Documento escrito</strong> (PDF o Word) con la información investigada. El documento debe incluir:</p>\r\n<ul data-start=\"1926\" data-end=\"2346\">\r\n<li class=\"\" data-start=\"1926\" data-end=\"2070\">\r\n<p data-start=\"1928\" data-end=\"2070\" class=\"\">Una introducción breve sobre qué son las válvulas de vacío y los transistores, y cómo cada uno ha influido en el desarrollo de la electrónica.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2076\" data-end=\"2199\">\r\n<p data-start=\"2078\" data-end=\"2199\" class=\"\">Descripción detallada de cómo funcionan las válvulas de vacío y los transistores, sus aplicaciones y sus características.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2205\" data-end=\"2256\">\r\n<p data-start=\"2207\" data-end=\"2256\" class=\"\">Comparación detallada entre los dos dispositivos.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2262\" data-end=\"2346\">\r\n<p data-start=\"2264\" data-end=\"2346\" class=\"\">Conclusiones sobre en qué situaciones podría ser ventajoso usar uno sobre el otro.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n</li>\r\n<li class=\"\" data-start=\"2348\" data-end=\"2646\">\r\n<p data-start=\"2351\" data-end=\"2375\" class=\"\"><strong data-start=\"2351\" data-end=\"2375\">Formato y Extensión:</strong></p>\r\n<ul data-start=\"2379\" data-end=\"2646\">\r\n<li class=\"\" data-start=\"2379\" data-end=\"2428\">\r\n<p data-start=\"2381\" data-end=\"2428\" class=\"\">El documento debe tener un mínimo de 2 páginas.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2432\" data-end=\"2523\">\r\n<p data-start=\"2434\" data-end=\"2523\" class=\"\">Usa un formato de texto claro y bien estructurado, con subtítulos y párrafos organizados.</p>\r\n</li>\r\n<li class=\"\" data-start=\"2527\" data-end=\"2646\">\r\n<p data-start=\"2529\" data-end=\"2646\" class=\"\">Incluye imágenes, diagramas o gráficos que ayuden a ilustrar cómo funcionan las válvulas de vacío y los transistores.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ol>');
