INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Cuestionario (Quiz)', 'Cuestionario 2: Semiconductores', '<ul>\r\n<li data-start=\"246\" data-end=\"367\"><strong data-start=\"248\" data-end=\"259\">Formato</strong>: El examen consta de 10 preguntas, que incluyen: </li>\r\n</ul>\r\n<p></p>\r\n<ul>\r\n<li data-start=\"368\" data-end=\"425\"><strong data-start=\"370\" data-end=\"380\">Tiempo</strong>: Tienes 1 Hora para completar el examen.</li>\r\n<li data-start=\"426\" data-end=\"505\"><strong data-start=\"428\" data-end=\"437\">Valor</strong>: Este examen representa el 30% de la calificación final del módulo.</li>\r\n<li><strong data-start=\"508\" data-end=\"525\">Instrucciones</strong>: Lee cuidadosamente cada pregunta antes de responder. Asegúrate de completar todas las preguntas dentro del tiempo asignado mucha suerte.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 2.1:  Preparación del Substrato Construcción', '<p></p>\r\n<p>Descripción detallada de los materiales semiconductores utilizados y el proceso de fabricación de los transistores.<br><br></p>\r\n<p>Explicación de la estructura de capas de los transistores NPN y PNP.<br><br></p>\r\n<p>Representación gráfica con símbolos y convenciones estándar para los transistores NPN y PNP.<br><br></p>\r\n<p>Esquemas o diagramas ilustrando las distintas etapas del proceso de fabricación y la estructura interna de los transistores.</p>\r\n<p></p>\r\n<p style=\"font-weight: bold;\"><strong>Producto Esperado :</strong></p>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 2.2: Principio de Operación', '<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Descripción detallada del principio de operación del transistor BJT.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Explicación sobre el mecanismo de conducción y control de corriente.</li>\r\n<li dir=\"ltr\" role=\"presentation\">Representación gráfica de las curvas características (IC vs VBE, IC vs VCE, etc.).</li>\r\n<li dir=\"ltr\" role=\"presentation\">Cálculos y ecuaciones ilustrando el control de corriente y las características de transferencia del transistor BJT.</li>\r\n</ul>\r\n<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 2.3: Modos de Funcionamiento', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada sobre los modos de funcionamiento del transistor BJT (Corte, Saturación, Activa).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de las condiciones de operación y características de cada región.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Aplicaciones prácticas de cada modo de funcionamiento en circuitos electrónicos.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gráficos mostrando las curvas de salida y transferencia de un transistor en diferentes modos de funcionamiento.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 2.4: Configuraciones', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada de las configuraciones de transistores (Emisor Común, Base Común, Colector Común).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de sus características, ventajas y aplicaciones típicas.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa de las configuraciones, destacando sus principales diferencias y usos en la práctica.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 3.1: Tipos de FET', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada de las características, estructura y funcionamiento de JFET y MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación de las aplicaciones de ambos tipos de transistores.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre JFET y MOSFET, destacando sus principales características y aplicaciones</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 3.2: Construcción y Estructura Interna', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción detallada del proceso de fabricación, materiales utilizados y la estructura interna de los transistores FET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Diagramas representativos de la estructura interna de JFET y MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Esquemas de los procesos de fabricación y las capas utilizadas en JFET y MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Cuestionario (Quiz)', 'Cuestionario 2: Semiconductores', '<ul>\r\n<li data-start=\"246\" data-end=\"367\"><strong data-start=\"248\" data-end=\"259\">Formato</strong>: El examen consta de 10 preguntas, que incluyen: </li>\r\n</ul>\r\n<p></p>\r\n<ul>\r\n<li data-start=\"368\" data-end=\"425\"><strong data-start=\"370\" data-end=\"380\">Tiempo</strong>: Tienes 1 Hora para completar el examen.</li>\r\n<li data-start=\"426\" data-end=\"505\"><strong data-start=\"428\" data-end=\"437\">Valor</strong>: Este examen representa el 30% de la calificación final del módulo.</li>\r\n<li><strong data-start=\"508\" data-end=\"525\">Instrucciones</strong>: Lee cuidadosamente cada pregunta antes de responder. Asegúrate de completar todas las preguntas dentro del tiempo asignado mucha suerte.</li>\r\n</ul>');
