INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 3.3: Principio de Operación', '<h3 dir=\"ltr\">Producto Esperado :</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada del principio de operación de los transistores FET, con énfasis en el control por voltaje y el efecto de campo.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Cálculos matemáticos y gráficos de las características de transferencia (ID vs VGS, gm vs VGS, etc.).<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gráficos que muestran las curvas de salida de JFET y MOSFET en diferentes regiones de operación.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 3.4: Comparación con BJT', '<h3 dir=\"ltr\">Producto Esperado :</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis detallado de las ventajas y desventajas de JFET y MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de las aplicaciones, costos y disponibilidad de ambos tipos de transistores.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Tabla comparativa entre JFET y MOSFET, destacando sus características, aplicaciones y costos.</p>\r\n</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 4.1: Proceso de Fabricación CMOS', '<p><strong>Preparación del Substrato. Explica:</strong><br><br></p>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Limpieza química<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Oxidación térmica<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Recubrimiento de fotoresist<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Litografía<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Formación de Capas<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Deposición de óxido de compuerta (SiO₂, HfO₂)<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Implantación iónica<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Recocido térmico<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Procesos de Grabado<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Grabado húmedo<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Grabado en seco<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Limpieza<br><br></li>\r\n<li dir=\"ltr\" role=\"presentation\">Pasivación</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 4.2: Estructura de Capas', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción del proceso de fabricación de los MOSFET, desde la preparación del substrato hasta los procesos de grabado.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Detalles sobre la estructura de capas de los MOSFET, incluyendo el substrato, óxido de compuerta, compuerta, drenaje y fuente.<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Diagramas y esquemas mostrando la estructura interna del MOSFET y los procesos de fabricación.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 4.3: Mecanismo de Conducción', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación detallada sobre el mecanismo de conducción del MOSFET, incluida la formación del canal y el control de corriente.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Representación matemática de la ecuación de corriente y el factor K.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis de los efectos secundarios que afectan el rendimiento del MOSFET.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 4.4: Características Eléctricas', '<ol>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Parámetros Estáticos<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">VTH: 0.5-3V<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">IDSS: 0.1-100 mA<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">gm: 1-100 mS<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">ro: 10-100 kΩ<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Parámetros Dinámicos<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Ciss: 1-100 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Coss: 0.1-10 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Crss: 0.01-1 pF<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">tr/tf: 1-100 ns<br><br></p>\r\n</li>\r\n</ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Límites de Operación<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">VDSmax: 5-1000V<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">IDmax: 0.1-100A<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">PDmax: 0.1-1000W<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Tjmax: 150-200°C<br><br></p>\r\n</li>\r\n</ul>\r\n</ol>\r\n<p dir=\"ltr\"></p>\r\n<hr>\r\n<p></p>\r\n<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de los parámetros estáticos y dinámicos del MOSFET.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicación de los límites de operación y sus implicaciones en el diseño de circuitos.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p><strong id=\"docs-internal-guid-98c38875-7fff-3772-89fd-baac19aea7f3\">Gráficos que muestren las características eléctricas del MOSFET en diferentes condiciones.<br></strong></p>');
