INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Tarea 4.5: Modelos de Operación', '<h3 dir=\"ltr\">Producto Esperado:</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Documento escrito (PDF o Word) con la información investigada, de mínimo 2 páginas.<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Descripción de los modelos de operación del MOSFET (Nivel 1, BSIM, PSP).<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Comparación de las ecuaciones utilizadas en cada modelo y sus limitaciones.<br><br></p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p><strong id=\"docs-internal-guid-fa8c9657-7fff-46cf-0a09-05925e7efffa\">Análisis de los efectos cuánticos y de alta frecuencia en los modelos avanzados.<br></strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Tarea (Assignment)', 'Examen Final (PRESENCIAL) no hacer', '<p><strong>Opciones de Proyecto:</strong></p>\r\n<p><strong>Fuente de alimentación regulada.<br>■ Sistema de iluminación automatizado.<br>■ Detector de nivel con alarma.<br>■ Temporizador electrónico.<br>■ Proyecto alternativo (previa aprobación).</strong></p>\r\n<p><strong>Entregables:<br>■ Memoria técnica (documento PDF).<br>■ Esquema del circuito.<br>■ Simulación (Proteus o Tinkercad).<br>■ Video demostrativo (5–7 minutos).<br>■ Presentación final.</strong></p>\r\n<p><strong>Evaluación:<br>■ Funcionamiento (30%),<br>■ Diseño y construcción (25%),<br>■ Documentación técnica (20%),<br>■ Presentación y video (15%),<br>■ Originalidad e innovación (10%).<br></strong></p>\r\n<p><strong>Valor: 70% del módulo.</strong></p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Concepto de Calidad', '<h2 dir=\"ltr\">Dinámica: Caso de Comunicación Efectiva en Calidad</h2>\r\n<h3 dir=\"ltr\">Escenario:</h3>\r\n<p dir=\"ltr\"><br>Un supervisor detecta que un lote presenta tiro muy apretado en varios cigarros (rechazo 4%), superando el límite permitido del 2%. Debe informar al equipo de torcedores sin desmotivarlos, y al mismo tiempo proponer acciones de mejora.</p>\r\n<h3 dir=\"ltr\"> </h3>\r\n<h3 dir=\"ltr\">Actividad </h3>\r\n<ol>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Redacta un mensaje breve y claro como si fueras el supervisor, explicando el problema y motivando al equipo a corregirlo.<br><br></p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Incluye:<br><br></p>\r\n</li>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Qué pasó.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Por qué es importante corregirlo (impacto en cliente y marca país).</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Qué acciones inmediatas se proponen.<br><br></p>\r\n</li>\r\n</ul>\r\n</ol>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Acciones inmediatas que se aplicarán bajo las 5S.', '<h2 dir=\"ltr\"> Ejercicio</h2>\r\n<p dir=\"ltr\"><strong>Caso:</strong><br>En la galera de torcido se detecta desorden: hojas mezcladas, herramientas dispersas y residuos en las mesas. Como responsable del área, debes aplicar 5S y comunicar al equipo la importancia de este método.</p>\r\n<p dir=\"ltr\">Actividad:<br>Redacta un mensaje dirigido al equipo explicando:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">El problema detectado.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Por qué el orden y la limpieza impactan la calidad del cigarro y la satisfacción del cliente.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Acciones inmediatas que se aplicarán bajo las 5S.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio principio de gestión de calidad', '<h2 dir=\"ltr\">Ejercicio </h2>\r\n<p dir=\"ltr\">Caso:<br>En la galera de torcido se detecta desorden: hojas mezcladas, herramientas dispersas y residuos en las mesas. Como responsable del área, debes aplicar 5S y comunicar al equipo la importancia de este método.</p>\r\n<p dir=\"ltr\">Actividad:<br>Redacta un mensaje dirigido al equipo explicando:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">El problema detectado.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Por qué el orden y la limpieza impactan la calidad del cigarro y la satisfacción del cliente.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Acciones inmediatas que se aplicarán bajo las 5S.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', ' Ejercicio Sistema de Gestión de la Calidad (SGC) en la Industria Tabacalera', '<h2 dir=\"ltr\"> Ejercicio de Habilidades Blandas</h2>\r\n<p dir=\"ltr\"><strong>Caso:</strong><br>Eres supervisor en el área de almacenamiento y detectas que la humedad relativa estuvo fuera de rango durante 3 días. Debes informar al equipo y proponer acciones inmediatas.</p>\r\n<p dir=\"ltr\"><strong>Actividad:</strong><br>Redacta un mensaje breve y claro dirigido al equipo, explicando:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Qué ocurrió.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Por qué es importante corregirlo.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Qué acciones se tomarán para garantizar la calidad de los cigarros.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
