INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio: Gestión de Procesos y Producción', '<p dir=\"ltr\"><strong id=\"docs-internal-guid-fad1f6ff-7fff-66f2-665a-93ad3edfa582\">Ejercicio</strong></p>\r\n<p dir=\"ltr\">Caso:<br>Durante la revisión de registros en el área de torcido, detectas que un colaborador llenó los formatos con retraso y algunos campos quedaron incompletos.</p>\r\n<p dir=\"ltr\">Actividad:<br>Redacta cómo abordarías la situación con el colaborador, asegurando:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Explicar la importancia de los registros en tiempo real.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Motivar a la responsabilidad sin desmoralizar.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Proponer una acción inmediata para evitar la repetición.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Tarea (Assignment)', 'Ejercicio Buenas Prácticas de Manufactura (BPM) para Tabaco', '<h3 dir=\"ltr\">Ejercicio </h3>\r\n<p dir=\"ltr\">Caso:<br>Un auditor externo observa que algunos colaboradores en la galera manipulan tabaco sin guantes y con bebidas en la mesa.</p>\r\n<p dir=\"ltr\">Actividad:<br>Como supervisor, redacta un mensaje para el equipo que:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Explique el riesgo de incumplir las BPM.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Refuerce el compromiso con la calidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Motive al grupo a trabajar de forma colaborativa para corregir la situación.<br><br></p>\r\n</li>\r\n</ul>\r\n<p></p>');
