INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Cuestionario (Quiz)', 'Examen Análisis de Datos para la Calidad', '<div class=\"activity-header\" data-for=\"page-activity-header\">\r\n<div id=\"intro\" class=\"activity-description\">\r\n<div class=\"no-overflow\">\r\n<p><strong data-start=\"248\" data-end=\"259\">Formato</strong>: El examen consta de 10 preguntas, que incluyen: </p>\r\n<p></p>\r\n<ul>\r\n<li>Opción múltiple</li>\r\n<li>Verdadero/Falso</li>\r\n<li>Emparejamiento</li>\r\n</ul>\r\n<p></p>\r\n<ul>\r\n<li data-start=\"368\" data-end=\"425\"><strong data-start=\"370\" data-end=\"380\">Tiempo</strong>: Tienes 1 Hora para completar el examen.</li>\r\n<li data-start=\"426\" data-end=\"505\"><strong data-start=\"428\" data-end=\"437\">Valor</strong>: Este examen representa el 60% de la calificación final del módulo.</li>\r\n<li data-start=\"506\" data-end=\"650\"><strong data-start=\"508\" data-end=\"525\">Instrucciones</strong>: Lee cuidadosamente cada pregunta antes de responder. Asegúrate de completar todas las preguntas dentro del tiempo asignado mucha suerte.</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n<div role=\"main\">\r\n<div class=\"container-fluid tertiary-navigation\">\r\n<div class=\"row\">\r\n<div class=\"singlebutton quizstartbuttondiv\"> </div>\r\n</div>\r\n</div>\r\n<div class=\"box py-3 quizinfo\"> </div>\r\n</div>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Recurso/Archivo', 'El Sistema 5S', '<p dir=\"ltr\">5S (Seiri, Seiton, Seiso, Seiketsu, Shitsuke)</p>\r\n<h2 dir=\"ltr\">Origen histórico</h2>\r\n<p dir=\"ltr\">Las 5S surgieron en Japón, en la década de 1950, dentro del sistema de producción de Toyota. Japón enfrentaba un periodo de reconstrucción industrial tras la Segunda Guerra Mundial, con recursos escasos y la necesidad de ser más productivos y competitivos.</p>\r\n<p dir=\"ltr\">En ese contexto, los ingenieros japoneses desarrollaron métodos simples pero poderosos para:</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Eliminar desperdicios.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Organizar el trabajo.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Mejorar la disciplina laboral.<br>El resultado fue el método de las 5S, llamado así por las iniciales de cinco palabras japonesas que representan principios básicos de orden y limpieza en el entorno laboral.</p>\r\n</li>\r\n</ul>\r\n<p>Este enfoque se convirtió en un pilar del Kaizen (mejora continua), demostrando que el orden y la disciplina son tan importantes como la tecnología o la maquinaria para lograr calidad y productividad.</p>');
