INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', '\"La Resistividad Eléctrica\"', '<p><strong>Discutir cómo la resistividad afecta el diseño de sistemas eléctricos y</strong><br><strong>electrónicos.</strong><br><br></p>\r\n<ul>\r\n<li> Evaluación: Análisis (40%), participación (30%), fundamento técnico (20%) y<br>redacción (10%).<br> </li>\r\n<li>Valor: 15% del módulo.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Examen Final', '<p>Este foro está habilitado para resolver cualquier duda relacionada con el examen final presencial. Los estudiantes pueden consultar sobre la fecha, el contenido que será evaluado, la modalidad del examen, y cualquier otra inquietud organizativa o académica.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro 1 del Módulo 4:', '<p><strong>Objetivo: </strong>Debatir sobre aplicaciones innovadoras de dispositivos de<br>control en sistemas automatizados.</p>\r\n<p><strong>Evaluación</strong>: Originalidad (35%), fundamentación (30%), participación<br>(25%) y redacción (10%).</p>\r\n<p><br><strong>Valor: </strong>10% de esta sección</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Dudas de la unidad', '<p><strong>Objetivo: </strong>Espacio de retroalimentación y discusión sobre los avances del<br>proyecto final.</p>\n<p><strong>Evaluación:</strong> Participación (40%), calidad de aportes (30%), colaboración (20%)<br>y redacción (10%).</p>\n<p></p>\n<p><strong>Valor</strong>: 10% del proyecto final.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Estructura Atómica Tarea', '<p data-start=\"90\" data-end=\"496\" class=\"\">Bienvenidos al foro de la tarea <strong data-start=\"122\" data-end=\"144\">Estructura Atómica</strong>.<br data-start=\"145\" data-end=\"148\">Este espacio ha sido creado para que puedan compartir cualquier duda, comentario o sugerencia relacionada con esta actividad.<br data-start=\"273\" data-end=\"276\">El facilitador estará atento a sus participaciones para brindar orientación y retroalimentación.<br data-start=\"372\" data-end=\"375\">Recuerden que este foro es una herramienta clave para apoyarse mutuamente y avanzar con éxito en el desarrollo del curso.</p>\r\n<p data-start=\"498\" data-end=\"533\" class=\"\">🔔 <strong data-start=\"585\" data-end=\"600\">Importante:</strong> Este foro es solo para dudas, <strong data-start=\"631\" data-end=\"668\">no debes enviar la tarea por aquí</strong>.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Enviar Capturas de Pantalla', '<p data-start=\"177\" data-end=\"349\" class=\"\">Este foro es un espacio para que puedas hacer preguntas o expresar cualquier duda relacionada con la tarea <strong data-start=\"284\" data-end=\"315\">\"Construye tu propio átomo\"</strong>, del tema <strong data-start=\"326\" data-end=\"348\">Estructura Atómica</strong>.</p>\r\n<p data-start=\"351\" data-end=\"580\" class=\"\">Si no estás segura/o de cómo usar el simulador PhET, cómo asignar protones, neutrones o electrones, o tienes dudas sobre la justificación de tu respuesta, puedes escribir aquí. El facilitador te estará respondiendo para ayudarte.</p>\r\n<p data-start=\"582\" data-end=\"669\" class=\"\">🔔 <strong data-start=\"585\" data-end=\"600\">Importante:</strong> Este foro es solo para dudas, <strong data-start=\"631\" data-end=\"668\">no debes enviar la tarea por aquí</strong>.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Ley Universal de Conservación de Energía', '<p data-start=\"159\" data-end=\"287\" class=\"\">Este foro es para que puedas hacer preguntas o compartir tus dudas sobre el tema <strong data-start=\"240\" data-end=\"286\">\"Ley Universal de Conservación de Energía\"</strong>.</p>\r\n<p data-start=\"289\" data-end=\"537\" class=\"\">Si tienes preguntas sobre los conceptos relacionados con la ley, cómo se aplica en diferentes contextos, o necesitas ayuda para entender algún ejercicio o explicación, no dudes en escribir aquí. El facilitador te ayudará a resolver tus inquietudes.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Lección 6 Conductores Electricos.', '<p data-start=\"112\" data-end=\"210\" class=\"\">Este foro es para resolver cualquier duda relacionada con el tema de <strong data-start=\"181\" data-end=\"209\">\"Conductores Eléctricos\"</strong>.</p>\r\n<p data-start=\"212\" data-end=\"466\" class=\"\">Si tienes preguntas sobre qué materiales son conductores, cómo funcionan, o cualquier concepto relacionado con la conducción eléctrica, este es el lugar para escribirlas. El facilitador estará disponible para ayudarte a aclarar cualquier duda que tengas.</p>\r\n<p data-start=\"468\" data-end=\"544\" class=\"\">🔔 <strong data-start=\"471\" data-end=\"484\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"515\" data-end=\"544\">no es para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Aislantes Eléctricos', '<p data-start=\"107\" data-end=\"209\" class=\"\">Este foro está diseñado para que resuelvas cualquier duda sobre el tema de <strong data-start=\"182\" data-end=\"208\">\"Aislantes Eléctricos\"</strong>.</p>\r\n<p data-start=\"211\" data-end=\"450\" class=\"\">Si tienes preguntas sobre qué materiales son aislantes, cómo funcionan para evitar el paso de electricidad o cualquier concepto relacionado, este es el espacio para plantearlas. El facilitador estará aquí para brindarte el apoyo necesario.</p>\r\n<p data-start=\"452\" data-end=\"538\" class=\"\">🔔 <strong data-start=\"455\" data-end=\"468\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"499\" data-end=\"538\">no se deben enviar tareas por aquí.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Concepto de Iones y Ley de Cargas', '<p data-start=\"142\" data-end=\"253\" class=\"\">Este foro está destinado a resolver cualquier duda que tengas sobre el <strong data-start=\"213\" data-end=\"252\">\"Concepto de Iones y Ley de Cargas\"</strong>.</p>\r\n<p data-start=\"255\" data-end=\"512\" class=\"\">Si no entiendes cómo se forman los iones, cómo interactúan según la ley de cargas, o si tienes dudas con los ejercicios relacionados, este es el lugar adecuado para preguntar. El facilitador te dará la orientación necesaria para aclarar cualquier inquietud.</p>\r\n<p data-start=\"514\" data-end=\"592\" class=\"\">🔔 <strong data-start=\"517\" data-end=\"530\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"561\" data-end=\"592\">no es para entregar tareas.</strong></p>\r\n<p data-start=\"514\" data-end=\"592\" class=\"\"></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Semiconductores', '<p data-start=\"102\" data-end=\"183\" class=\"\">Este foro es el espacio para resolver cualquier duda sobre <strong data-start=\"161\" data-end=\"182\">\"Semiconductores\"</strong>.</p>\r\n<p data-start=\"185\" data-end=\"418\" class=\"\">Si no entiendes cómo funcionan los semiconductores, sus aplicaciones o cualquier otro concepto relacionado, puedes escribir tus preguntas aquí. El facilitador te ayudará a aclarar cualquier duda y proporcionará orientación adicional.</p>\r\n<p data-start=\"420\" data-end=\"498\" class=\"\">🔔 <strong data-start=\"423\" data-end=\"436\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"467\" data-end=\"498\">no es para entregar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Estructura y Resistividad de los Materiales', '<p data-start=\"130\" data-end=\"258\" class=\"\">Este foro está diseñado para resolver cualquier duda que tengas sobre el tema <strong data-start=\"208\" data-end=\"257\">\"Estructura y Resistividad de los Materiales\"</strong>.</p>\r\n<p data-start=\"260\" data-end=\"479\" class=\"\">Si tienes preguntas sobre cómo la estructura de los materiales afecta su resistividad, o cualquier concepto relacionado, puedes plantearlas aquí. El facilitador estará disponible para ayudarte a aclarar tus inquietudes.</p>\r\n<p data-start=\"481\" data-end=\"557\" class=\"\">🔔 <strong data-start=\"484\" data-end=\"497\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"528\" data-end=\"557\">no es para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Tarea de Sistemas de Unidades de Medida', '<p data-start=\"129\" data-end=\"247\" class=\"\">Este foro es para que puedas resolver cualquier duda relacionada con la <strong data-start=\"201\" data-end=\"246\">\"Tarea de Sistemas de Unidades de Medida\"</strong>.</p>\r\n<p data-start=\"249\" data-end=\"534\" class=\"\">Si tienes preguntas sobre cómo se utilizan diferentes sistemas de unidades, las conversiones entre ellos, o cualquier otro concepto relacionado con la tarea, este es el lugar para plantearlas. El facilitador te ayudará a aclarar tus dudas y orientarte en la resolución de la actividad.</p>\r\n<p data-start=\"536\" data-end=\"622\" class=\"\">🔔 <strong data-start=\"539\" data-end=\"552\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"583\" data-end=\"622\">no se debe usar para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Magnitudes Eléctricas Fundamentales', '<p data-start=\"140\" data-end=\"258\" class=\"\">Este foro es para que puedas hacer preguntas o expresar dudas sobre el tema <strong data-start=\"216\" data-end=\"257\">\"Magnitudes Eléctricas Fundamentales\"</strong>.</p>\r\n<p data-start=\"260\" data-end=\"469\" class=\"\">Si no comprendes bien conceptos como voltaje, corriente, resistencia, o cualquier otra magnitud eléctrica básica, puedes escribir aquí. El facilitador estará disponible para ayudarte y aclarar tus inquietudes.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Múltiplos y Submúltiplos', '<p data-start=\"138\" data-end=\"244\" class=\"\">Este foro está destinado a resolver cualquier duda relacionada con el tema <strong data-start=\"213\" data-end=\"243\">\"Múltiplos y Submúltiplos\"</strong>.</p>\r\n<p data-start=\"246\" data-end=\"477\" class=\"\">Si tienes preguntas sobre cómo identificar o convertir múltiplos y submúltiplos en el sistema de unidades, o si no comprendes bien cómo aplicarlos en ejercicios, puedes escribir aquí. El facilitador estará disponible para ayudarte.</p>\r\n<p data-start=\"479\" data-end=\"568\" class=\"\">🔔 <strong data-start=\"482\" data-end=\"495\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"526\" data-end=\"568\">no debes enviar tareas por este medio.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Instrumentos de Medida Eléctrica', '<p data-start=\"258\" data-end=\"528\" class=\"\">Este foro es para resolver cualquier duda sobre los <strong data-start=\"349\" data-end=\"385\">instrumentos de medida eléctrica</strong>. Si no comprendes cómo funcionan, para qué sirven o cómo se utilizan, puedes escribir aquí. El facilitador te ayudará a aclarar tus preguntas.</p>\r\n<p data-start=\"530\" data-end=\"586\" class=\"\">🔔 Recuerda: Solo para dudas. No se deben enviar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Mediciones con Multímetro', '<p data-start=\"593\" data-end=\"831\" class=\"\">Utiliza este foro si tienes dudas sobre cómo realizar las <strong data-start=\"693\" data-end=\"722\">mediciones con multímetro</strong>. Puedes preguntar sobre el uso correcto, los valores que se deben obtener o la interpretación de resultados.</p>\r\n<p data-start=\"833\" data-end=\"921\" class=\"\">🔔 Recuerda: Este foro es solo para dudas. Las tareas se entregan por el medio indicado.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Conversiones de Unidades', '<p data-start=\"928\" data-end=\"1136\" class=\"\">¿Tienes dudas sobre las <strong data-start=\"992\" data-end=\"1023\">conversiones entre unidades</strong>? Este foro está habilitado para ayudarte a comprender los métodos de conversión y cómo aplicarlos correctamente.</p>\r\n<p data-start=\"1138\" data-end=\"1197\" class=\"\">🔔 Este espacio es para preguntas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro:  Instrumentos de Medición', '<p data-start=\"1204\" data-end=\"1435\" class=\"\">Este foro te servirá para consultar cualquier duda relacionada con los <strong data-start=\"1315\" data-end=\"1343\">instrumentos de medición</strong> utilizados en electricidad y electrónica. El facilitador te orientará con lo que necesites.</p>\r\n<p data-start=\"1719\" data-end=\"1762\" class=\"\">🔔 Solo para dudas, no para subir trabajos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Colaborativa-Grupal 3: Mapa Mental', '<p data-start=\"1473\" data-end=\"1717\" class=\"\">Si tienen preguntas sobre la <strong data-start=\"1553\" data-end=\"1589\">actividad grupal del mapa mental</strong>, cómo organizar la información o qué herramientas utilizar, pueden compartirlas aquí. El facilitador los apoyará en el proceso.</p>\r\n<p data-start=\"1719\" data-end=\"1762\" class=\"\">🔔 Solo para dudas, no para subir trabajos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Ley de Ohm', '<p data-start=\"1769\" data-end=\"1918\" class=\"\">Este foro es para aclarar conceptos sobre la <strong data-start=\"1838\" data-end=\"1852\">Ley de Ohm</strong>, su fórmula, cómo aplicarla y cualquier confusión con ejercicios.</p>\r\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Circuitos en Serie y Paralelo', '<p data-start=\"1977\" data-end=\"2184\" class=\"\">¿No sabes cómo funcionan los <strong data-start=\"2049\" data-end=\"2082\">circuitos en serie o paralelo</strong>? Este foro es para resolver tus dudas, entender sus características y cómo analizarlos correctamente.</p>\r\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro:  Resistencia Equivalente', '<p>Este foro es para preguntas relacionadas con cómo calcular la <strong data-start=\"2321\" data-end=\"2348\">resistencia equivalente</strong> en diferentes tipos de circuitos. Si necesitas apoyo con ejemplos o fórmulas, escríbelo aquí.</p>\r\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Código de Colores de Resistencias', '<p data-start=\"2490\" data-end=\"2686\" class=\"\">¿Tienes dudas con el <strong data-start=\"2558\" data-end=\"2599\">código de colores de las resistencias</strong>? Aquí puedes preguntar cómo identificar valores, leer bandas o calcular su tolerancia.</p>\r\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Circuitos Mixtos Eléctricos', '<p>Este foro es para dudas relacionadas con los <strong data-start=\"2815\" data-end=\"2835\">circuitos mixtos</strong> (combinación de serie y paralelo). Si necesitas ayuda con su análisis o con la teoría, este es el lugar.</p>\r\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro:  Análisis de Circuitos', '<p>Aquí puedes hacer preguntas sobre el <strong data-start=\"3049\" data-end=\"3074\">análisis de circuitos</strong>: cómo resolverlos, qué métodos usar y cómo interpretar resultados. El facilitador responderá a tus inquietudes.</p>\r\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Elementos Activos', '<p>Este foro está disponible para que preguntes sobre los <strong data-start=\"3310\" data-end=\"3331\">elementos activos</strong> en electrónica: su función, características y ejemplos.</p>\r\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Dispositivos Electrónicos', '<p data-start=\"2688\" data-end=\"2729\" class=\"\">¿Tienes dudas sobre los <strong data-start=\"3485\" data-end=\"3514\">dispositivos electrónicos</strong> y cómo funcionan? Este foro te permitirá consultar todo lo relacionado con este tema.</p>\r\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Elementos Pasivos', '<p>En este foro puedes preguntar sobre los <strong data-start=\"3700\" data-end=\"3721\">elementos pasivos</strong> en los circuitos electrónicos: resistencias, condensadores, inductores, etc.</p>\r\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Los Diodos y sus Aplicaciones', '<p>Si necesitas aclarar conceptos sobre los <strong data-start=\"3943\" data-end=\"3972\">diodos y sus aplicaciones</strong>, este foro es para ti. Pregunta aquí y recibirás orientación por parte del facilitador.</p>\r\n<p></p>\r\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Construcción de una Fuente de Alimentación', '<p data-start=\"2688\" data-end=\"2729\" class=\"\">Este foro es para resolver dudas sobre el proceso de <strong data-start=\"4219\" data-end=\"4265\">construcción de una fuente de alimentación</strong>: componentes, conexión y funcionamiento.</p>\r\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Tarea: Los Diodos LED y sus Aplicaciones', '<p>¿No comprendes bien cómo funcionan los <strong data-start=\"4424\" data-end=\"4438\">diodos LED</strong>? Este foro está disponible para ayudarte a entender su funcionamiento y aplicaciones.</p>\r\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Los Diodos Zener y sus Aplicaciones', '<p>Este foro está destinado a preguntas sobre los <strong data-start=\"4646\" data-end=\"4662\">diodos Zener</strong>: su uso como reguladores de voltaje y otras aplicaciones prácticas.</p>\r\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Los Condensadores-Capacitores y sus Aplicaciones', '<p>Este espacio está abierto para resolver dudas sobre los <strong data-start=\"4896\" data-end=\"4913\">condensadores</strong> o <strong data-start=\"4916\" data-end=\"4931\">capacitores</strong>: cómo funcionan, sus tipos y usos en los circuitos.</p>\r\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Análisis de Circuitos con Condensadores', '<p data-start=\"118\" data-end=\"403\" class=\"\">Este foro está disponible para que puedas resolver cualquier duda relacionada con el <strong data-start=\"258\" data-end=\"310\">análisis de circuitos que incluyen condensadores</strong>. Si no comprendes cómo se comportan o cómo se conectan en el circuito, puedes escribir aquí.</p>\r\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro:  Clasificación de los Diodos', '<p>¿Tienes preguntas sobre los <strong data-start=\"550\" data-end=\"569\">tipos de diodos</strong> y sus características? Usa este espacio para consultar sobre su clasificación, funcionamiento y aplicaciones. El facilitador estará atento a responder.</p>\r\n<p>🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Relé o Relevador', '<p>¿No entiendes cómo funciona un <strong data-start=\"1149\" data-end=\"1169\">relé o relevador</strong>? Este foro está habilitado para que preguntes sobre su uso, tipos y aplicaciones en los circuitos electrónicos.</p>\r\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Interruptores, Conmutadores y Pulsadores', '<p data-start=\"405\" data-end=\"472\" class=\"\">Este foro te servirá para plantear cualquier inquietud sobre el funcionamiento, tipos y diferencias entre <strong data-start=\"939\" data-end=\"983\">interruptores, conmutadores y pulsadores</strong>. Si algo no te queda claro, puedes preguntarlo aquí.</p>\r\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro:  De los Transformadores', '<p>Aquí puedes compartir tus preguntas sobre los <strong data-start=\"1416\" data-end=\"1435\">transformadores</strong>, cómo operan, para qué sirven y sus principales tipos. Si algo del tema no te queda claro, este foro es el lugar ideal para preguntarlo.</p>\r\n<p>🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Historia y Evolución de los Transistores', '<p>Este foro está disponible para responder cualquier duda sobre el origen, desarrollo y avances en la tecnología de los transistores. Si necesitas aclaraciones sobre fechas, inventores o evolución tecnológica, este es tu espacio.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Funcionalidad General de los Transistores', '<p>¿Tienes preguntas sobre cómo funcionan los transistores en los circuitos electrónicos? Este foro está diseñado para ayudarte a entender su funcionamiento general y sus componentes clave.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Campos de Aplicación de la Electrónica', '<p>Este espacio está abierto para aclarar cualquier inquietud sobre los diferentes entornos donde se aplica la electrónica, desde la industria hasta el hogar. Puedes escribir aquí si tienes dudas sobre ejemplos o contextos de uso.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Tipos de Transistores y Clasificación', '<p>Si no tienes claro cuántos tipos de transistores existen o cómo se clasifican, puedes usar este foro para resolver tus dudas sobre este tema. El facilitador te apoyará con las respuestas.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Comparación con Válvulas de Vacío', '<p>Aquí puedes plantear preguntas sobre las diferencias entre los transistores y las válvulas de vacío, sus ventajas, desventajas y evolución tecnológica. Si algo no entiendes, este es tu espacio.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Preparación del Substrato - Construcción', '<p>Este foro está habilitado para resolver dudas sobre cómo se prepara el substrato en el proceso de fabricación de componentes electrónicos. Si tienes preguntas técnicas o de procedimiento, puedes escribir aquí.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Principio de Operación', '<p>¿Tienes dudas sobre el principio de operación de los componentes electrónicos en estudio? Este foro te ayudará a comprender mejor su comportamiento y funcionamiento a nivel interno.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Modos de Funcionamiento', '<p>Si algo no te queda claro sobre los diferentes modos de funcionamiento de los transistores, este foro está disponible para ayudarte. Puedes preguntar libremente y el facilitador te orientará.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Configuraciones', '<p>Este foro está disponible para resolver dudas sobre las distintas configuraciones de transistores y cómo afectan su funcionamiento en los circuitos. Se puede consultar sobre configuraciones comunes, en colector o base, entre otras.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Tipos de FET', '<p>En este foro se atenderán dudas relacionadas con los distintos tipos de transistores de efecto de campo (FET), como JFET, MOSFET, y sus aplicaciones. Si alguna clasificación o funcionamiento no está claro, puedes consultarlo aquí.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Construcción y Estructura Interna', '<p>Si existen dudas sobre cómo están construidos los FET o cómo es su estructura interna, este foro está habilitado para resolverlas. Puedes escribir tus preguntas y serán respondidas por el facilitador.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Principio de Operación', '<p>Este foro está destinado a resolver dudas sobre el principio de funcionamiento de los transistores FET. Es ideal para entender cómo se comportan en diferentes condiciones eléctricas.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Comparación con BJT', '<p>¿Tienes dudas sobre las diferencias entre los FET y los BJT? Aquí puedes consultar sobre ventajas, desventajas y aplicaciones de cada uno. El facilitador responderá cualquier inquietud.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Proceso de Fabricación CMOS', '<p>Este foro está habilitado para resolver dudas sobre el proceso de fabricación de circuitos CMOS. Puedes consultar sobre etapas, materiales o procedimientos específicos.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Estructura de Capas', '<p>¿No entiendes cómo se conforman las capas en un circuito CMOS? Aquí puedes dejar tus dudas para recibir orientación clara y directa por parte del facilitador.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Mecanismo de Conducción', '<p>Si necesitas comprender mejor cómo se da el flujo de corriente en los dispositivos CMOS, este foro está habilitado para ayudarte con explicaciones claras y personalizadas.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Características Eléctricas', '<p>Este foro está diseñado para atender preguntas sobre las propiedades eléctricas de los componentes CMOS. Puedes consultar sobre voltajes, corrientes o comportamiento eléctrico.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Modelos de Operación', '<p>Aquí puedes plantear cualquier duda sobre los distintos modelos de operación utilizados para describir el comportamiento de los dispositivos electrónicos.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Comparación con BJT', '<p>En este foro puedes resolver tus dudas sobre las diferencias y similitudes entre los dispositivos CMOS y los transistores BJT, enfocándote en sus aplicaciones, rendimiento y eficiencia.</p>\r\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Cuestionario 1: Conductores y Aislantes', '<p>Este foro está disponible para aclarar dudas sobre el contenido del primer cuestionario, enfocado en los materiales conductores y aislantes. Si algo no queda claro sobre las propiedades o ejemplos de estos materiales, puedes consultarlo aquí.</p>\r\n<p data-start=\"377\" data-end=\"489\" class=\"\">🔔 Solo se responderán preguntas relacionadas al contenido. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Foro: Cuestionario 2: Semiconductores', '<p>En este foro puedes escribir cualquier duda sobre el segundo cuestionario relacionado con semiconductores. Ya sea sobre sus propiedades, tipos o funcionamiento, aquí recibirás apoyo para entender mejor el tema.</p>\r\n<p data-start=\"377\" data-end=\"489\" class=\"\">🔔 Solo se responderán preguntas relacionadas al contenido. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Foro', 'Cuestionario 1: Evaluación de Conocimientos', '<p data-start=\"73\" data-end=\"356\" class=\"\">Este foro está destinado a resolver cualquier duda relacionada con el primer cuestionario de evaluación general. Si necesitas aclarar conceptos, instrucciones o tienes preguntas sobre el contenido evaluado, este es el lugar indicado.</p>\r\n<p data-start=\"358\" data-end=\"464\" class=\"\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Estructura Atómica Tarea', '<p data-start=\"90\" data-end=\"496\" class=\"\">Bienvenidos al foro de la tarea <strong data-start=\"122\" data-end=\"144\">Estructura Atómica</strong>.<br data-start=\"145\" data-end=\"148\">Este espacio ha sido creado para que puedan compartir cualquier duda, comentario o sugerencia relacionada con esta actividad.<br data-start=\"273\" data-end=\"276\">El facilitador estará atento a sus participaciones para brindar orientación y retroalimentación.<br data-start=\"372\" data-end=\"375\">Recuerden que este foro es una herramienta clave para apoyarse mutuamente y avanzar con éxito en el desarrollo del curso.</p>\r\n<p data-start=\"498\" data-end=\"533\" class=\"\">🔔 <strong data-start=\"585\" data-end=\"600\">Importante:</strong> Este foro es solo para dudas, <strong data-start=\"631\" data-end=\"668\">no debes enviar la tarea por aquí</strong>.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Enviar Capturas de Pantalla', '<p data-start=\"177\" data-end=\"349\" class=\"\">Este foro es un espacio para que puedas hacer preguntas o expresar cualquier duda relacionada con la tarea <strong data-start=\"284\" data-end=\"315\">\"Construye tu propio átomo\"</strong>, del tema <strong data-start=\"326\" data-end=\"348\">Estructura Atómica</strong>.</p>\r\n<p data-start=\"351\" data-end=\"580\" class=\"\">Si no estás segura/o de cómo usar el simulador PhET, cómo asignar protones, neutrones o electrones, o tienes dudas sobre la justificación de tu respuesta, puedes escribir aquí. El facilitador te estará respondiendo para ayudarte.</p>\r\n<p data-start=\"582\" data-end=\"669\" class=\"\">🔔 <strong data-start=\"585\" data-end=\"600\">Importante:</strong> Este foro es solo para dudas, <strong data-start=\"631\" data-end=\"668\">no debes enviar la tarea por aquí</strong>.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Ley Universal de Conservación de Energía', '<p data-start=\"159\" data-end=\"287\" class=\"\">Este foro es para que puedas hacer preguntas o compartir tus dudas sobre el tema <strong data-start=\"240\" data-end=\"286\">\"Ley Universal de Conservación de Energía\"</strong>.</p>\r\n<p data-start=\"289\" data-end=\"537\" class=\"\">Si tienes preguntas sobre los conceptos relacionados con la ley, cómo se aplica en diferentes contextos, o necesitas ayuda para entender algún ejercicio o explicación, no dudes en escribir aquí. El facilitador te ayudará a resolver tus inquietudes.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Concepto de Iones y Ley de Cargas', '<p data-start=\"142\" data-end=\"253\" class=\"\">Este foro está destinado a resolver cualquier duda que tengas sobre el <strong data-start=\"213\" data-end=\"252\">\"Concepto de Iones y Ley de Cargas\"</strong>.</p>\r\n<p data-start=\"255\" data-end=\"512\" class=\"\">Si no entiendes cómo se forman los iones, cómo interactúan según la ley de cargas, o si tienes dudas con los ejercicios relacionados, este es el lugar adecuado para preguntar. El facilitador te dará la orientación necesaria para aclarar cualquier inquietud.</p>\r\n<p data-start=\"514\" data-end=\"592\" class=\"\">🔔 <strong data-start=\"517\" data-end=\"530\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"561\" data-end=\"592\">no es para entregar tareas.</strong></p>\r\n<p data-start=\"514\" data-end=\"592\" class=\"\"></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Cuestionario 1: Evaluación de Conocimientos', '<p data-start=\"73\" data-end=\"356\" class=\"\">Este foro está destinado a resolver cualquier duda relacionada con el primer cuestionario de evaluación general. Si necesitas aclarar conceptos, instrucciones o tienes preguntas sobre el contenido evaluado, este es el lugar indicado.</p>\r\n<p data-start=\"358\" data-end=\"464\" class=\"\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Lección 6 Conductores Electricos.', '<p data-start=\"112\" data-end=\"210\" class=\"\">Este foro es para resolver cualquier duda relacionada con el tema de <strong data-start=\"181\" data-end=\"209\">\"Conductores Eléctricos\"</strong>.</p>\n<p data-start=\"212\" data-end=\"466\" class=\"\">Si tienes preguntas sobre qué materiales son conductores, cómo funcionan, o cualquier concepto relacionado con la conducción eléctrica, este es el lugar para escribirlas. El facilitador estará disponible para ayudarte a aclarar cualquier duda que tengas.</p>\n<p data-start=\"468\" data-end=\"544\" class=\"\">🔔 <strong data-start=\"471\" data-end=\"484\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"515\" data-end=\"544\">no es para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Aislantes Eléctricos', '<p data-start=\"107\" data-end=\"209\" class=\"\">Este foro está diseñado para que resuelvas cualquier duda sobre el tema de <strong data-start=\"182\" data-end=\"208\">\"Aislantes Eléctricos\"</strong>.</p>\r\n<p data-start=\"211\" data-end=\"450\" class=\"\">Si tienes preguntas sobre qué materiales son aislantes, cómo funcionan para evitar el paso de electricidad o cualquier concepto relacionado, este es el espacio para plantearlas. El facilitador estará aquí para brindarte el apoyo necesario.</p>\r\n<p data-start=\"452\" data-end=\"538\" class=\"\">🔔 <strong data-start=\"455\" data-end=\"468\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"499\" data-end=\"538\">no se deben enviar tareas por aquí.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Semiconductores', '<p data-start=\"102\" data-end=\"183\" class=\"\">Este foro es el espacio para resolver cualquier duda sobre <strong data-start=\"161\" data-end=\"182\">\"Semiconductores\"</strong>.</p>\r\n<p data-start=\"185\" data-end=\"418\" class=\"\">Si no entiendes cómo funcionan los semiconductores, sus aplicaciones o cualquier otro concepto relacionado, puedes escribir tus preguntas aquí. El facilitador te ayudará a aclarar cualquier duda y proporcionará orientación adicional.</p>\r\n<p data-start=\"420\" data-end=\"498\" class=\"\">🔔 <strong data-start=\"423\" data-end=\"436\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"467\" data-end=\"498\">no es para entregar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', '\"La Resistividad Eléctrica\"', '<p><strong>Discutir cómo la resistividad afecta el diseño de sistemas eléctricos y</strong><br><strong>electrónicos.</strong><br><br></p>\r\n<ul>\r\n<li> Evaluación: Análisis (40%), participación (30%), fundamento técnico (20%) y<br>redacción (10%).<br> </li>\r\n<li>Valor: 15% del módulo.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Cuestionario 1: Conductores y Aislantes', '<p>Este foro está disponible para aclarar dudas sobre el contenido del primer cuestionario, enfocado en los materiales conductores y aislantes. Si algo no queda claro sobre las propiedades o ejemplos de estos materiales, puedes consultarlo aquí.</p>\n<p data-start=\"377\" data-end=\"489\" class=\"\">🔔 Solo se responderán preguntas relacionadas al contenido. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Cuestionario 2: Semiconductores', '<p>En este foro puedes escribir cualquier duda sobre el segundo cuestionario relacionado con semiconductores. Ya sea sobre sus propiedades, tipos o funcionamiento, aquí recibirás apoyo para entender mejor el tema.</p>\r\n<p data-start=\"377\" data-end=\"489\" class=\"\">🔔 Solo se responderán preguntas relacionadas al contenido. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Estructura y Resistividad de los Materiales', '<p data-start=\"130\" data-end=\"258\" class=\"\">Este foro está diseñado para resolver cualquier duda que tengas sobre el tema <strong data-start=\"208\" data-end=\"257\">\"Estructura y Resistividad de los Materiales\"</strong>.</p>\r\n<p data-start=\"260\" data-end=\"479\" class=\"\">Si tienes preguntas sobre cómo la estructura de los materiales afecta su resistividad, o cualquier concepto relacionado, puedes plantearlas aquí. El facilitador estará disponible para ayudarte a aclarar tus inquietudes.</p>\r\n<p data-start=\"481\" data-end=\"557\" class=\"\">🔔 <strong data-start=\"484\" data-end=\"497\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"528\" data-end=\"557\">no es para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Tarea de Sistemas de Unidades de Medida', '<p data-start=\"129\" data-end=\"247\" class=\"\">Este foro es para que puedas resolver cualquier duda relacionada con la <strong data-start=\"201\" data-end=\"246\">\"Tarea de Sistemas de Unidades de Medida\"</strong>.</p>\r\n<p data-start=\"249\" data-end=\"534\" class=\"\">Si tienes preguntas sobre cómo se utilizan diferentes sistemas de unidades, las conversiones entre ellos, o cualquier otro concepto relacionado con la tarea, este es el lugar para plantearlas. El facilitador te ayudará a aclarar tus dudas y orientarte en la resolución de la actividad.</p>\r\n<p data-start=\"536\" data-end=\"622\" class=\"\">🔔 <strong data-start=\"539\" data-end=\"552\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"583\" data-end=\"622\">no se debe usar para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Magnitudes Eléctricas Fundamentales', '<p data-start=\"140\" data-end=\"258\" class=\"\">Este foro es para que puedas hacer preguntas o expresar dudas sobre el tema <strong data-start=\"216\" data-end=\"257\">\"Magnitudes Eléctricas Fundamentales\"</strong>.</p>\r\n<p data-start=\"260\" data-end=\"469\" class=\"\">Si no comprendes bien conceptos como voltaje, corriente, resistencia, o cualquier otra magnitud eléctrica básica, puedes escribir aquí. El facilitador estará disponible para ayudarte y aclarar tus inquietudes.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Múltiplos y Submúltiplos', '<p data-start=\"138\" data-end=\"244\" class=\"\">Este foro está destinado a resolver cualquier duda relacionada con el tema <strong data-start=\"213\" data-end=\"243\">\"Múltiplos y Submúltiplos\"</strong>.</p>\r\n<p data-start=\"246\" data-end=\"477\" class=\"\">Si tienes preguntas sobre cómo identificar o convertir múltiplos y submúltiplos en el sistema de unidades, o si no comprendes bien cómo aplicarlos en ejercicios, puedes escribir aquí. El facilitador estará disponible para ayudarte.</p>\r\n<p data-start=\"479\" data-end=\"568\" class=\"\">🔔 <strong data-start=\"482\" data-end=\"495\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"526\" data-end=\"568\">no debes enviar tareas por este medio.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Instrumentos de Medida Eléctrica', '<p data-start=\"258\" data-end=\"528\" class=\"\">Este foro es para resolver cualquier duda sobre los <strong data-start=\"349\" data-end=\"385\">instrumentos de medida eléctrica</strong>. Si no comprendes cómo funcionan, para qué sirven o cómo se utilizan, puedes escribir aquí. El facilitador te ayudará a aclarar tus preguntas.</p>\r\n<p data-start=\"530\" data-end=\"586\" class=\"\">🔔 Recuerda: Solo para dudas. No se deben enviar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Mediciones con Multímetro', '<p data-start=\"593\" data-end=\"831\" class=\"\">Utiliza este foro si tienes dudas sobre cómo realizar las <strong data-start=\"693\" data-end=\"722\">mediciones con multímetro</strong>. Puedes preguntar sobre el uso correcto, los valores que se deben obtener o la interpretación de resultados.</p>\r\n<p data-start=\"833\" data-end=\"921\" class=\"\">🔔 Recuerda: Este foro es solo para dudas. Las tareas se entregan por el medio indicado.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Conversiones de Unidades', '<p data-start=\"928\" data-end=\"1136\" class=\"\">¿Tienes dudas sobre las <strong data-start=\"992\" data-end=\"1023\">conversiones entre unidades</strong>? Este foro está habilitado para ayudarte a comprender los métodos de conversión y cómo aplicarlos correctamente.</p>\r\n<p data-start=\"1138\" data-end=\"1197\" class=\"\">🔔 Este espacio es para preguntas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro:  Instrumentos de Medición', '<p data-start=\"1204\" data-end=\"1435\" class=\"\">Este foro te servirá para consultar cualquier duda relacionada con los <strong data-start=\"1315\" data-end=\"1343\">instrumentos de medición</strong> utilizados en electricidad y electrónica. El facilitador te orientará con lo que necesites.</p>\r\n<p data-start=\"1719\" data-end=\"1762\" class=\"\">🔔 Solo para dudas, no para subir trabajos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Colaborativa-Grupal 3: Mapa Mental', '<p data-start=\"1473\" data-end=\"1717\" class=\"\">Si tienen preguntas sobre la <strong data-start=\"1553\" data-end=\"1589\">actividad grupal del mapa mental</strong>, cómo organizar la información o qué herramientas utilizar, pueden compartirlas aquí. El facilitador los apoyará en el proceso.</p>\r\n<p data-start=\"1719\" data-end=\"1762\" class=\"\">🔔 Solo para dudas, no para subir trabajos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Ley de Ohm', '<p data-start=\"1769\" data-end=\"1918\" class=\"\">Este foro es para aclarar conceptos sobre la <strong data-start=\"1838\" data-end=\"1852\">Ley de Ohm</strong>, su fórmula, cómo aplicarla y cualquier confusión con ejercicios.</p>\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Circuitos en Serie y Paralelo', '<p data-start=\"1977\" data-end=\"2184\" class=\"\">¿No sabes cómo funcionan los <strong data-start=\"2049\" data-end=\"2082\">circuitos en serie o paralelo</strong>? Este foro es para resolver tus dudas, entender sus características y cómo analizarlos correctamente.</p>\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro:  Resistencia Equivalente', '<p>Este foro es para preguntas relacionadas con cómo calcular la <strong data-start=\"2321\" data-end=\"2348\">resistencia equivalente</strong> en diferentes tipos de circuitos. Si necesitas apoyo con ejemplos o fórmulas, escríbelo aquí.</p>\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Código de Colores de Resistencias', '<p data-start=\"2490\" data-end=\"2686\" class=\"\">¿Tienes dudas con el <strong data-start=\"2558\" data-end=\"2599\">código de colores de las resistencias</strong>? Aquí puedes preguntar cómo identificar valores, leer bandas o calcular su tolerancia.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Circuitos Mixtos Eléctricos', '<p>Este foro es para dudas relacionadas con los <strong data-start=\"2815\" data-end=\"2835\">circuitos mixtos</strong> (combinación de serie y paralelo). Si necesitas ayuda con su análisis o con la teoría, este es el lugar.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro:  Análisis de Circuitos', '<p>Aquí puedes hacer preguntas sobre el <strong data-start=\"3049\" data-end=\"3074\">análisis de circuitos</strong>: cómo resolverlos, qué métodos usar y cómo interpretar resultados. El facilitador responderá a tus inquietudes.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Elementos Activos', '<p>Este foro está disponible para que preguntes sobre los <strong data-start=\"3310\" data-end=\"3331\">elementos activos</strong> en electrónica: su función, características y ejemplos.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Dispositivos Electrónicos', '<p data-start=\"2688\" data-end=\"2729\" class=\"\">¿Tienes dudas sobre los <strong data-start=\"3485\" data-end=\"3514\">dispositivos electrónicos</strong> y cómo funcionan? Este foro te permitirá consultar todo lo relacionado con este tema.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Elementos Pasivos', '<p>En este foro puedes preguntar sobre los <strong data-start=\"3700\" data-end=\"3721\">elementos pasivos</strong> en los circuitos electrónicos: resistencias, condensadores, inductores, etc.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Los Diodos y sus Aplicaciones', '<p>Si necesitas aclarar conceptos sobre los <strong data-start=\"3943\" data-end=\"3972\">diodos y sus aplicaciones</strong>, este foro es para ti. Pregunta aquí y recibirás orientación por parte del facilitador.</p>\n<p></p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Construcción de una Fuente de Alimentación', '<p data-start=\"2688\" data-end=\"2729\" class=\"\">Este foro es para resolver dudas sobre el proceso de <strong data-start=\"4219\" data-end=\"4265\">construcción de una fuente de alimentación</strong>: componentes, conexión y funcionamiento.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Tarea: Los Diodos LED y sus Aplicaciones', '<p>¿No comprendes bien cómo funcionan los <strong data-start=\"4424\" data-end=\"4438\">diodos LED</strong>? Este foro está disponible para ayudarte a entender su funcionamiento y aplicaciones.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Los Diodos Zener y sus Aplicaciones', '<p>Este foro está destinado a preguntas sobre los <strong data-start=\"4646\" data-end=\"4662\">diodos Zener</strong>: su uso como reguladores de voltaje y otras aplicaciones prácticas.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Los Condensadores-Capacitores y sus Aplicaciones', '<p>Este espacio está abierto para resolver dudas sobre los <strong data-start=\"4896\" data-end=\"4913\">condensadores</strong> o <strong data-start=\"4916\" data-end=\"4931\">capacitores</strong>: cómo funcionan, sus tipos y usos en los circuitos.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Análisis de Circuitos con Condensadores', '<p data-start=\"118\" data-end=\"403\" class=\"\">Este foro está disponible para que puedas resolver cualquier duda relacionada con el <strong data-start=\"258\" data-end=\"310\">análisis de circuitos que incluyen condensadores</strong>. Si no comprendes cómo se comportan o cómo se conectan en el circuito, puedes escribir aquí.</p>\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro:  Clasificación de los Diodos', '<p>¿Tienes preguntas sobre los <strong data-start=\"550\" data-end=\"569\">tipos de diodos</strong> y sus características? Usa este espacio para consultar sobre su clasificación, funcionamiento y aplicaciones. El facilitador estará atento a responder.</p>\n<p>🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Interruptores, Conmutadores y Pulsadores', '<p data-start=\"405\" data-end=\"472\" class=\"\">Este foro te servirá para plantear cualquier inquietud sobre el funcionamiento, tipos y diferencias entre <strong data-start=\"939\" data-end=\"983\">interruptores, conmutadores y pulsadores</strong>. Si algo no te queda claro, puedes preguntarlo aquí.</p>\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Relé o Relevador', '<p>¿No entiendes cómo funciona un <strong data-start=\"1149\" data-end=\"1169\">relé o relevador</strong>? Este foro está habilitado para que preguntes sobre su uso, tipos y aplicaciones en los circuitos electrónicos.</p>\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro 1 del Módulo 4:', '<p><strong>Objetivo: </strong>Debatir sobre aplicaciones innovadoras de dispositivos de<br>control en sistemas automatizados.</p>\n<p><strong>Evaluación</strong>: Originalidad (35%), fundamentación (30%), participación<br>(25%) y redacción (10%).</p>\n<p><br><strong>Valor: </strong>10% de esta sección</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro:  De los Transformadores', '<p>Aquí puedes compartir tus preguntas sobre los <strong data-start=\"1416\" data-end=\"1435\">transformadores</strong>, cómo operan, para qué sirven y sus principales tipos. Si algo del tema no te queda claro, este foro es el lugar ideal para preguntarlo.</p>\n<p>🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Historia y Evolución de los Transistores', '<p>Este foro está disponible para responder cualquier duda sobre el origen, desarrollo y avances en la tecnología de los transistores. Si necesitas aclaraciones sobre fechas, inventores o evolución tecnológica, este es tu espacio.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Funcionalidad General de los Transistores', '<p>¿Tienes preguntas sobre cómo funcionan los transistores en los circuitos electrónicos? Este foro está diseñado para ayudarte a entender su funcionamiento general y sus componentes clave.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Campos de Aplicación de la Electrónica', '<p>Este espacio está abierto para aclarar cualquier inquietud sobre los diferentes entornos donde se aplica la electrónica, desde la industria hasta el hogar. Puedes escribir aquí si tienes dudas sobre ejemplos o contextos de uso.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Tipos de Transistores y Clasificación', '<p>Si no tienes claro cuántos tipos de transistores existen o cómo se clasifican, puedes usar este foro para resolver tus dudas sobre este tema. El facilitador te apoyará con las respuestas.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Comparación con Válvulas de Vacío', '<p>Aquí puedes plantear preguntas sobre las diferencias entre los transistores y las válvulas de vacío, sus ventajas, desventajas y evolución tecnológica. Si algo no entiendes, este es tu espacio.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Preparación del Substrato - Construcción', '<p>Este foro está habilitado para resolver dudas sobre cómo se prepara el substrato en el proceso de fabricación de componentes electrónicos. Si tienes preguntas técnicas o de procedimiento, puedes escribir aquí.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Principio de Operación', '<p>¿Tienes dudas sobre el principio de operación de los componentes electrónicos en estudio? Este foro te ayudará a comprender mejor su comportamiento y funcionamiento a nivel interno.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Modos de Funcionamiento', '<p>Si algo no te queda claro sobre los diferentes modos de funcionamiento de los transistores, este foro está disponible para ayudarte. Puedes preguntar libremente y el facilitador te orientará.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Configuraciones', '<p>Este foro está disponible para resolver dudas sobre las distintas configuraciones de transistores y cómo afectan su funcionamiento en los circuitos. Se puede consultar sobre configuraciones comunes, en colector o base, entre otras.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Tipos de FET', '<p>En este foro se atenderán dudas relacionadas con los distintos tipos de transistores de efecto de campo (FET), como JFET, MOSFET, y sus aplicaciones. Si alguna clasificación o funcionamiento no está claro, puedes consultarlo aquí.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Construcción y Estructura Interna', '<p>Si existen dudas sobre cómo están construidos los FET o cómo es su estructura interna, este foro está habilitado para resolverlas. Puedes escribir tus preguntas y serán respondidas por el facilitador.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Principio de Operación', '<p>Este foro está destinado a resolver dudas sobre el principio de funcionamiento de los transistores FET. Es ideal para entender cómo se comportan en diferentes condiciones eléctricas.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Comparación con BJT', '<p>¿Tienes dudas sobre las diferencias entre los FET y los BJT? Aquí puedes consultar sobre ventajas, desventajas y aplicaciones de cada uno. El facilitador responderá cualquier inquietud.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Dudas de la unidad', '<p><strong>Objetivo: </strong>Espacio de retroalimentación y discusión sobre los avances del<br>proyecto final.</p>\n<p><strong>Evaluación:</strong> Participación (40%), calidad de aportes (30%), colaboración (20%)<br>y redacción (10%).</p>\n<p></p>\n<p><strong>Valor</strong>: 10% del proyecto final.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Proceso de Fabricación CMOS', '<p>Este foro está habilitado para resolver dudas sobre el proceso de fabricación de circuitos CMOS. Puedes consultar sobre etapas, materiales o procedimientos específicos.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Estructura de Capas', '<p>¿No entiendes cómo se conforman las capas en un circuito CMOS? Aquí puedes dejar tus dudas para recibir orientación clara y directa por parte del facilitador.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Mecanismo de Conducción', '<p>Si necesitas comprender mejor cómo se da el flujo de corriente en los dispositivos CMOS, este foro está habilitado para ayudarte con explicaciones claras y personalizadas.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Características Eléctricas', '<p>Este foro está diseñado para atender preguntas sobre las propiedades eléctricas de los componentes CMOS. Puedes consultar sobre voltajes, corrientes o comportamiento eléctrico.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Modelos de Operación', '<p>Aquí puedes plantear cualquier duda sobre los distintos modelos de operación utilizados para describir el comportamiento de los dispositivos electrónicos.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Comparación con BJT', '<p>En este foro puedes resolver tus dudas sobre las diferencias y similitudes entre los dispositivos CMOS y los transistores BJT, enfocándote en sus aplicaciones, rendimiento y eficiencia.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Foro', 'Foro: Examen Final', '<p>Este foro está habilitado para resolver cualquier duda relacionada con el examen final presencial. Los estudiantes pueden consultar sobre la fecha, el contenido que será evaluado, la modalidad del examen, y cualquier otra inquietud organizativa o académica.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Avisos', 'Avisos y novedades generales');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Ley Universal de Conservación de Energía', '<p data-start=\"159\" data-end=\"287\" class=\"\">Este foro es para que puedas hacer preguntas o compartir tus dudas sobre el tema <strong data-start=\"240\" data-end=\"286\">\"Ley Universal de Conservación de Energía\"</strong>.</p>\r\n<p data-start=\"289\" data-end=\"537\" class=\"\">Si tienes preguntas sobre los conceptos relacionados con la ley, cómo se aplica en diferentes contextos, o necesitas ayuda para entender algún ejercicio o explicación, no dudes en escribir aquí. El facilitador te ayudará a resolver tus inquietudes.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Cuestionario 1: Evaluación de Conocimientos', '<p data-start=\"73\" data-end=\"356\" class=\"\">Este foro está destinado a resolver cualquier duda relacionada con el primer cuestionario de evaluación general. Si necesitas aclarar conceptos, instrucciones o tienes preguntas sobre el contenido evaluado, este es el lugar indicado.</p>\r\n<p data-start=\"358\" data-end=\"464\" class=\"\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Estructura Atómica Tarea', '<p data-start=\"90\" data-end=\"496\" class=\"\">Bienvenidos al foro de la tarea <strong data-start=\"122\" data-end=\"144\">Estructura Atómica</strong>.<br data-start=\"145\" data-end=\"148\">Este espacio ha sido creado para que puedan compartir cualquier duda, comentario o sugerencia relacionada con esta actividad.<br data-start=\"273\" data-end=\"276\">El facilitador estará atento a sus participaciones para brindar orientación y retroalimentación.<br data-start=\"372\" data-end=\"375\">Recuerden que este foro es una herramienta clave para apoyarse mutuamente y avanzar con éxito en el desarrollo del curso.</p>\r\n<p data-start=\"498\" data-end=\"533\" class=\"\">🔔 <strong data-start=\"585\" data-end=\"600\">Importante:</strong> Este foro es solo para dudas, <strong data-start=\"631\" data-end=\"668\">no debes enviar la tarea por aquí</strong>.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Enviar Capturas de Pantalla', '<p data-start=\"177\" data-end=\"349\" class=\"\">Este foro es un espacio para que puedas hacer preguntas o expresar cualquier duda relacionada con la tarea <strong data-start=\"284\" data-end=\"315\">\"Construye tu propio átomo\"</strong>, del tema <strong data-start=\"326\" data-end=\"348\">Estructura Atómica</strong>.</p>\r\n<p data-start=\"351\" data-end=\"580\" class=\"\">Si no estás segura/o de cómo usar el simulador PhET, cómo asignar protones, neutrones o electrones, o tienes dudas sobre la justificación de tu respuesta, puedes escribir aquí. El facilitador te estará respondiendo para ayudarte.</p>\r\n<p data-start=\"582\" data-end=\"669\" class=\"\">🔔 <strong data-start=\"585\" data-end=\"600\">Importante:</strong> Este foro es solo para dudas, <strong data-start=\"631\" data-end=\"668\">no debes enviar la tarea por aquí</strong>.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Concepto de Iones y Ley de Cargas', '<p data-start=\"142\" data-end=\"253\" class=\"\">Este foro está destinado a resolver cualquier duda que tengas sobre el <strong data-start=\"213\" data-end=\"252\">\"Concepto de Iones y Ley de Cargas\"</strong>.</p>\r\n<p data-start=\"255\" data-end=\"512\" class=\"\">Si no entiendes cómo se forman los iones, cómo interactúan según la ley de cargas, o si tienes dudas con los ejercicios relacionados, este es el lugar adecuado para preguntar. El facilitador te dará la orientación necesaria para aclarar cualquier inquietud.</p>\r\n<p data-start=\"514\" data-end=\"592\" class=\"\">🔔 <strong data-start=\"517\" data-end=\"530\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"561\" data-end=\"592\">no es para entregar tareas.</strong></p>\r\n<p data-start=\"514\" data-end=\"592\" class=\"\"></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Lección 6 Conductores Electricos.', '<p data-start=\"112\" data-end=\"210\" class=\"\">Este foro es para resolver cualquier duda relacionada con el tema de <strong data-start=\"181\" data-end=\"209\">\"Conductores Eléctricos\"</strong>.</p>\r\n<p data-start=\"212\" data-end=\"466\" class=\"\">Si tienes preguntas sobre qué materiales son conductores, cómo funcionan, o cualquier concepto relacionado con la conducción eléctrica, este es el lugar para escribirlas. El facilitador estará disponible para ayudarte a aclarar cualquier duda que tengas.</p>\r\n<p data-start=\"468\" data-end=\"544\" class=\"\">🔔 <strong data-start=\"471\" data-end=\"484\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"515\" data-end=\"544\">no es para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Aislantes Eléctricos', '<p data-start=\"107\" data-end=\"209\" class=\"\">Este foro está diseñado para que resuelvas cualquier duda sobre el tema de <strong data-start=\"182\" data-end=\"208\">\"Aislantes Eléctricos\"</strong>.</p>\r\n<p data-start=\"211\" data-end=\"450\" class=\"\">Si tienes preguntas sobre qué materiales son aislantes, cómo funcionan para evitar el paso de electricidad o cualquier concepto relacionado, este es el espacio para plantearlas. El facilitador estará aquí para brindarte el apoyo necesario.</p>\r\n<p data-start=\"452\" data-end=\"538\" class=\"\">🔔 <strong data-start=\"455\" data-end=\"468\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"499\" data-end=\"538\">no se deben enviar tareas por aquí.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Semiconductores', '<p data-start=\"102\" data-end=\"183\" class=\"\">Este foro es el espacio para resolver cualquier duda sobre <strong data-start=\"161\" data-end=\"182\">\"Semiconductores\"</strong>.</p>\r\n<p data-start=\"185\" data-end=\"418\" class=\"\">Si no entiendes cómo funcionan los semiconductores, sus aplicaciones o cualquier otro concepto relacionado, puedes escribir tus preguntas aquí. El facilitador te ayudará a aclarar cualquier duda y proporcionará orientación adicional.</p>\r\n<p data-start=\"420\" data-end=\"498\" class=\"\">🔔 <strong data-start=\"423\" data-end=\"436\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"467\" data-end=\"498\">no es para entregar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', '\"La Resistividad Eléctrica\"', '<p><strong>Discutir cómo la resistividad afecta el diseño de sistemas eléctricos y</strong><br><strong>electrónicos.</strong><br><br></p>\r\n<ul>\r\n<li> Evaluación: Análisis (40%), participación (30%), fundamento técnico (20%) y<br>redacción (10%).<br> </li>\r\n<li>Valor: 15% del módulo.</li>\r\n</ul>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Cuestionario 1: Conductores y Aislantes', '<p>Este foro está disponible para aclarar dudas sobre el contenido del primer cuestionario, enfocado en los materiales conductores y aislantes. Si algo no queda claro sobre las propiedades o ejemplos de estos materiales, puedes consultarlo aquí.</p>\n<p data-start=\"377\" data-end=\"489\" class=\"\">🔔 Solo se responderán preguntas relacionadas al contenido. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Cuestionario 2: Semiconductores', '<p>En este foro puedes escribir cualquier duda sobre el segundo cuestionario relacionado con semiconductores. Ya sea sobre sus propiedades, tipos o funcionamiento, aquí recibirás apoyo para entender mejor el tema.</p>\r\n<p data-start=\"377\" data-end=\"489\" class=\"\">🔔 Solo se responderán preguntas relacionadas al contenido. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Magnitudes Eléctricas Fundamentales', '<p data-start=\"140\" data-end=\"258\" class=\"\">Este foro es para que puedas hacer preguntas o expresar dudas sobre el tema <strong data-start=\"216\" data-end=\"257\">\"Magnitudes Eléctricas Fundamentales\"</strong>.</p>\r\n<p data-start=\"260\" data-end=\"469\" class=\"\">Si no comprendes bien conceptos como voltaje, corriente, resistencia, o cualquier otra magnitud eléctrica básica, puedes escribir aquí. El facilitador estará disponible para ayudarte y aclarar tus inquietudes.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Múltiplos y Submúltiplos', '<p data-start=\"138\" data-end=\"244\" class=\"\">Este foro está destinado a resolver cualquier duda relacionada con el tema <strong data-start=\"213\" data-end=\"243\">\"Múltiplos y Submúltiplos\"</strong>.</p>\r\n<p data-start=\"246\" data-end=\"477\" class=\"\">Si tienes preguntas sobre cómo identificar o convertir múltiplos y submúltiplos en el sistema de unidades, o si no comprendes bien cómo aplicarlos en ejercicios, puedes escribir aquí. El facilitador estará disponible para ayudarte.</p>\r\n<p data-start=\"479\" data-end=\"568\" class=\"\">🔔 <strong data-start=\"482\" data-end=\"495\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"526\" data-end=\"568\">no debes enviar tareas por este medio.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Estructura y Resistividad de los Materiales', '<p data-start=\"130\" data-end=\"258\" class=\"\">Este foro está diseñado para resolver cualquier duda que tengas sobre el tema <strong data-start=\"208\" data-end=\"257\">\"Estructura y Resistividad de los Materiales\"</strong>.</p>\r\n<p data-start=\"260\" data-end=\"479\" class=\"\">Si tienes preguntas sobre cómo la estructura de los materiales afecta su resistividad, o cualquier concepto relacionado, puedes plantearlas aquí. El facilitador estará disponible para ayudarte a aclarar tus inquietudes.</p>\r\n<p data-start=\"481\" data-end=\"557\" class=\"\">🔔 <strong data-start=\"484\" data-end=\"497\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"528\" data-end=\"557\">no es para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Tarea de Sistemas de Unidades de Medida', '<p data-start=\"129\" data-end=\"247\" class=\"\">Este foro es para que puedas resolver cualquier duda relacionada con la <strong data-start=\"201\" data-end=\"246\">\"Tarea de Sistemas de Unidades de Medida\"</strong>.</p>\r\n<p data-start=\"249\" data-end=\"534\" class=\"\">Si tienes preguntas sobre cómo se utilizan diferentes sistemas de unidades, las conversiones entre ellos, o cualquier otro concepto relacionado con la tarea, este es el lugar para plantearlas. El facilitador te ayudará a aclarar tus dudas y orientarte en la resolución de la actividad.</p>\r\n<p data-start=\"536\" data-end=\"622\" class=\"\">🔔 <strong data-start=\"539\" data-end=\"552\">Recuerda:</strong> Este foro es solo para dudas, <strong data-start=\"583\" data-end=\"622\">no se debe usar para enviar tareas.</strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Instrumentos de Medida Eléctrica', '<p data-start=\"258\" data-end=\"528\" class=\"\">Este foro es para resolver cualquier duda sobre los <strong data-start=\"349\" data-end=\"385\">instrumentos de medida eléctrica</strong>. Si no comprendes cómo funcionan, para qué sirven o cómo se utilizan, puedes escribir aquí. El facilitador te ayudará a aclarar tus preguntas.</p>\r\n<p data-start=\"530\" data-end=\"586\" class=\"\">🔔 Recuerda: Solo para dudas. No se deben enviar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Mediciones con Multímetro', '<p data-start=\"593\" data-end=\"831\" class=\"\">Utiliza este foro si tienes dudas sobre cómo realizar las <strong data-start=\"693\" data-end=\"722\">mediciones con multímetro</strong>. Puedes preguntar sobre el uso correcto, los valores que se deben obtener o la interpretación de resultados.</p>\r\n<p data-start=\"833\" data-end=\"921\" class=\"\">🔔 Recuerda: Este foro es solo para dudas. Las tareas se entregan por el medio indicado.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Conversiones de Unidades', '<p data-start=\"928\" data-end=\"1136\" class=\"\">¿Tienes dudas sobre las <strong data-start=\"992\" data-end=\"1023\">conversiones entre unidades</strong>? Este foro está habilitado para ayudarte a comprender los métodos de conversión y cómo aplicarlos correctamente.</p>\r\n<p data-start=\"1138\" data-end=\"1197\" class=\"\">🔔 Este espacio es para preguntas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro:  Instrumentos de Medición', '<p data-start=\"1204\" data-end=\"1435\" class=\"\">Este foro te servirá para consultar cualquier duda relacionada con los <strong data-start=\"1315\" data-end=\"1343\">instrumentos de medición</strong> utilizados en electricidad y electrónica. El facilitador te orientará con lo que necesites.</p>\r\n<p data-start=\"1719\" data-end=\"1762\" class=\"\">🔔 Solo para dudas, no para subir trabajos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Colaborativa-Grupal 3: Mapa Mental', '<p data-start=\"1473\" data-end=\"1717\" class=\"\">Si tienen preguntas sobre la <strong data-start=\"1553\" data-end=\"1589\">actividad grupal del mapa mental</strong>, cómo organizar la información o qué herramientas utilizar, pueden compartirlas aquí. El facilitador los apoyará en el proceso.</p>\r\n<p data-start=\"1719\" data-end=\"1762\" class=\"\">🔔 Solo para dudas, no para subir trabajos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Ley de Ohm', '<p data-start=\"1769\" data-end=\"1918\" class=\"\">Este foro es para aclarar conceptos sobre la <strong data-start=\"1838\" data-end=\"1852\">Ley de Ohm</strong>, su fórmula, cómo aplicarla y cualquier confusión con ejercicios.</p>\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Circuitos en Serie y Paralelo', '<p data-start=\"1977\" data-end=\"2184\" class=\"\">¿No sabes cómo funcionan los <strong data-start=\"2049\" data-end=\"2082\">circuitos en serie o paralelo</strong>? Este foro es para resolver tus dudas, entender sus características y cómo analizarlos correctamente.</p>\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro:  Resistencia Equivalente', '<p>Este foro es para preguntas relacionadas con cómo calcular la <strong data-start=\"2321\" data-end=\"2348\">resistencia equivalente</strong> en diferentes tipos de circuitos. Si necesitas apoyo con ejemplos o fórmulas, escríbelo aquí.</p>\n<p data-start=\"1920\" data-end=\"1970\" class=\"\">🔔 No se reciben tareas por este foro. Solo dudas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Código de Colores de Resistencias', '<p data-start=\"2490\" data-end=\"2686\" class=\"\">¿Tienes dudas con el <strong data-start=\"2558\" data-end=\"2599\">código de colores de las resistencias</strong>? Aquí puedes preguntar cómo identificar valores, leer bandas o calcular su tolerancia.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Circuitos Mixtos Eléctricos', '<p>Este foro es para dudas relacionadas con los <strong data-start=\"2815\" data-end=\"2835\">circuitos mixtos</strong> (combinación de serie y paralelo). Si necesitas ayuda con su análisis o con la teoría, este es el lugar.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro:  Análisis de Circuitos', '<p>Aquí puedes hacer preguntas sobre el <strong data-start=\"3049\" data-end=\"3074\">análisis de circuitos</strong>: cómo resolverlos, qué métodos usar y cómo interpretar resultados. El facilitador responderá a tus inquietudes.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Elementos Activos', '<p>Este foro está disponible para que preguntes sobre los <strong data-start=\"3310\" data-end=\"3331\">elementos activos</strong> en electrónica: su función, características y ejemplos.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Dispositivos Electrónicos', '<p data-start=\"2688\" data-end=\"2729\" class=\"\">¿Tienes dudas sobre los <strong data-start=\"3485\" data-end=\"3514\">dispositivos electrónicos</strong> y cómo funcionan? Este foro te permitirá consultar todo lo relacionado con este tema.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Elementos Pasivos', '<p>En este foro puedes preguntar sobre los <strong data-start=\"3700\" data-end=\"3721\">elementos pasivos</strong> en los circuitos electrónicos: resistencias, condensadores, inductores, etc.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Los Diodos y sus Aplicaciones', '<p>Si necesitas aclarar conceptos sobre los <strong data-start=\"3943\" data-end=\"3972\">diodos y sus aplicaciones</strong>, este foro es para ti. Pregunta aquí y recibirás orientación por parte del facilitador.</p>\n<p></p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Construcción de una Fuente de Alimentación', '<p data-start=\"2688\" data-end=\"2729\" class=\"\">Este foro es para resolver dudas sobre el proceso de <strong data-start=\"4219\" data-end=\"4265\">construcción de una fuente de alimentación</strong>: componentes, conexión y funcionamiento.</p>\n<p data-start=\"2688\" data-end=\"2729\" class=\"\">🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Tarea: Los Diodos LED y sus Aplicaciones', '<p>¿No comprendes bien cómo funcionan los <strong data-start=\"4424\" data-end=\"4438\">diodos LED</strong>? Este foro está disponible para ayudarte a entender su funcionamiento y aplicaciones.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Los Diodos Zener y sus Aplicaciones', '<p>Este foro está destinado a preguntas sobre los <strong data-start=\"4646\" data-end=\"4662\">diodos Zener</strong>: su uso como reguladores de voltaje y otras aplicaciones prácticas.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Los Condensadores-Capacitores y sus Aplicaciones', '<p>Este espacio está abierto para resolver dudas sobre los <strong data-start=\"4896\" data-end=\"4913\">condensadores</strong> o <strong data-start=\"4916\" data-end=\"4931\">capacitores</strong>: cómo funcionan, sus tipos y usos en los circuitos.</p>\n<p>🔔 Foro para preguntas, no para entregas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Análisis de Circuitos con Condensadores', '<p data-start=\"118\" data-end=\"403\" class=\"\">Este foro está disponible para que puedas resolver cualquier duda relacionada con el <strong data-start=\"258\" data-end=\"310\">análisis de circuitos que incluyen condensadores</strong>. Si no comprendes cómo se comportan o cómo se conectan en el circuito, puedes escribir aquí.</p>\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro:  Clasificación de los Diodos', '<p>¿Tienes preguntas sobre los <strong data-start=\"550\" data-end=\"569\">tipos de diodos</strong> y sus características? Usa este espacio para consultar sobre su clasificación, funcionamiento y aplicaciones. El facilitador estará atento a responder.</p>\n<p>🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Interruptores, Conmutadores y Pulsadores', '<p data-start=\"405\" data-end=\"472\" class=\"\">Este foro te servirá para plantear cualquier inquietud sobre el funcionamiento, tipos y diferencias entre <strong data-start=\"939\" data-end=\"983\">interruptores, conmutadores y pulsadores</strong>. Si algo no te queda claro, puedes preguntarlo aquí.</p>\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Relé o Relevador', '<p>¿No entiendes cómo funciona un <strong data-start=\"1149\" data-end=\"1169\">relé o relevador</strong>? Este foro está habilitado para que preguntes sobre su uso, tipos y aplicaciones en los circuitos electrónicos.</p>\n<p data-start=\"405\" data-end=\"472\" class=\"\">🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro 1 del Módulo 4:', '<p><strong>Objetivo: </strong>Debatir sobre aplicaciones innovadoras de dispositivos de<br>control en sistemas automatizados.</p>\n<p><strong>Evaluación</strong>: Originalidad (35%), fundamentación (30%), participación<br>(25%) y redacción (10%).</p>\n<p><br><strong>Valor: </strong>10% de esta sección</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro:  De los Transformadores', '<p>Aquí puedes compartir tus preguntas sobre los <strong data-start=\"1416\" data-end=\"1435\">transformadores</strong>, cómo operan, para qué sirven y sus principales tipos. Si algo del tema no te queda claro, este foro es el lugar ideal para preguntarlo.</p>\n<p>🔔 Recuerda: Este foro es solo para dudas, no para entregar tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Historia y Evolución de los Transistores', '<p>Este foro está disponible para responder cualquier duda sobre el origen, desarrollo y avances en la tecnología de los transistores. Si necesitas aclaraciones sobre fechas, inventores o evolución tecnológica, este es tu espacio.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Funcionalidad General de los Transistores', '<p>¿Tienes preguntas sobre cómo funcionan los transistores en los circuitos electrónicos? Este foro está diseñado para ayudarte a entender su funcionamiento general y sus componentes clave.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Campos de Aplicación de la Electrónica', '<p>Este espacio está abierto para aclarar cualquier inquietud sobre los diferentes entornos donde se aplica la electrónica, desde la industria hasta el hogar. Puedes escribir aquí si tienes dudas sobre ejemplos o contextos de uso.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Tipos de Transistores y Clasificación', '<p>Si no tienes claro cuántos tipos de transistores existen o cómo se clasifican, puedes usar este foro para resolver tus dudas sobre este tema. El facilitador te apoyará con las respuestas.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Comparación con Válvulas de Vacío', '<p>Aquí puedes plantear preguntas sobre las diferencias entre los transistores y las válvulas de vacío, sus ventajas, desventajas y evolución tecnológica. Si algo no entiendes, este es tu espacio.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Preparación del Substrato - Construcción', '<p>Este foro está habilitado para resolver dudas sobre cómo se prepara el substrato en el proceso de fabricación de componentes electrónicos. Si tienes preguntas técnicas o de procedimiento, puedes escribir aquí.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Principio de Operación', '<p>¿Tienes dudas sobre el principio de operación de los componentes electrónicos en estudio? Este foro te ayudará a comprender mejor su comportamiento y funcionamiento a nivel interno.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Modos de Funcionamiento', '<p>Si algo no te queda claro sobre los diferentes modos de funcionamiento de los transistores, este foro está disponible para ayudarte. Puedes preguntar libremente y el facilitador te orientará.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Configuraciones', '<p>Este foro está disponible para resolver dudas sobre las distintas configuraciones de transistores y cómo afectan su funcionamiento en los circuitos. Se puede consultar sobre configuraciones comunes, en colector o base, entre otras.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Tipos de FET', '<p>En este foro se atenderán dudas relacionadas con los distintos tipos de transistores de efecto de campo (FET), como JFET, MOSFET, y sus aplicaciones. Si alguna clasificación o funcionamiento no está claro, puedes consultarlo aquí.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Construcción y Estructura Interna', '<p>Si existen dudas sobre cómo están construidos los FET o cómo es su estructura interna, este foro está habilitado para resolverlas. Puedes escribir tus preguntas y serán respondidas por el facilitador.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Principio de Operación', '<p>Este foro está destinado a resolver dudas sobre el principio de funcionamiento de los transistores FET. Es ideal para entender cómo se comportan en diferentes condiciones eléctricas.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Comparación con BJT', '<p>¿Tienes dudas sobre las diferencias entre los FET y los BJT? Aquí puedes consultar sobre ventajas, desventajas y aplicaciones de cada uno. El facilitador responderá cualquier inquietud.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Dudas de la unidad', '<p><strong>Objetivo: </strong>Espacio de retroalimentación y discusión sobre los avances del<br>proyecto final.</p>\n<p><strong>Evaluación:</strong> Participación (40%), calidad de aportes (30%), colaboración (20%)<br>y redacción (10%).</p>\n<p></p>\n<p><strong>Valor</strong>: 10% del proyecto final.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Proceso de Fabricación CMOS', '<p>Este foro está habilitado para resolver dudas sobre el proceso de fabricación de circuitos CMOS. Puedes consultar sobre etapas, materiales o procedimientos específicos.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Estructura de Capas', '<p>¿No entiendes cómo se conforman las capas en un circuito CMOS? Aquí puedes dejar tus dudas para recibir orientación clara y directa por parte del facilitador.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Mecanismo de Conducción', '<p>Si necesitas comprender mejor cómo se da el flujo de corriente en los dispositivos CMOS, este foro está habilitado para ayudarte con explicaciones claras y personalizadas.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Características Eléctricas', '<p>Este foro está diseñado para atender preguntas sobre las propiedades eléctricas de los componentes CMOS. Puedes consultar sobre voltajes, corrientes o comportamiento eléctrico.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Modelos de Operación', '<p>Aquí puedes plantear cualquier duda sobre los distintos modelos de operación utilizados para describir el comportamiento de los dispositivos electrónicos.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Comparación con BJT', '<p>En este foro puedes resolver tus dudas sobre las diferencias y similitudes entre los dispositivos CMOS y los transistores BJT, enfocándote en sus aplicaciones, rendimiento y eficiencia.</p>\n<p>🔔 Foro de dudas solamente. No se deben subir tareas aquí.</p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segunda Generación  ', 'Foro', 'Foro: Examen Final', '<p>Este foro está habilitado para resolver cualquier duda relacionada con el examen final presencial. Los estudiantes pueden consultar sobre la fecha, el contenido que será evaluado, la modalidad del examen, y cualquier otra inquietud organizativa o académica.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Avisos', 'Avisos y novedades generales');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Funcionamiento General de los Transistores', '<p></p>\r\n<p></p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Tipos de Transistores y su Clasificación', '<p data-start=\"0\" data-end=\"333\" class=\"\">Los <strong data-start=\"4\" data-end=\"20\">transistores</strong> son componentes electrónicos fundamentales que amplifican o conmutan señales electrónicas y son esenciales en la mayoría de los dispositivos electrónicos modernos. Existen varios tipos de transistores, y su clasificación se puede hacer de diferentes maneras, principalmente según su construcción y su aplicación.</p>\r\n<h3 class=\"\" data-start=\"335\" data-end=\"379\"> </h3>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Transistores BJT: Funcionamiento, Materiales y Aplicaciones', '<p>El objetivo de esta página es proporcionar una explicación exhaustiva sobre los transistores BJT (Bipolar Junction Transistor), cubriendo desde los materiales semiconductores hasta los modos de funcionamiento, configuraciones y aplicaciones.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Funcionamiento del MOSFET', '<p>Este documento explora detalladamente el proceso de fabricación del MOSFET, desde la preparación del substrato hasta los procesos de grabado y pasivación. También describe su estructura interna, el mecanismo de conducción, las características eléctricas y las ventajas en comparación con otros tipos de transistores como el BJT. Además, se incluyen modelos de operación, parámetros estáticos y dinámicos, y su uso en diversas aplicaciones electrónicas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Circuitos en Serie y Paralelo', '<p>En esta página se exploran los conceptos de circuitos en serie y en paralelo, dos configuraciones fundamentales en la electrónica. Los circuitos en <strong data-start=\"233\" data-end=\"242\">serie</strong> son aquellos en los que los componentes están conectados uno tras otro, de manera que la corriente pasa a través de cada uno de ellos. En este tipo de circuito, la <strong data-start=\"407\" data-end=\"424\">tensión total</strong> se divide entre los componentes, pero la <strong data-start=\"466\" data-end=\"479\">corriente</strong> es la misma a través de todos ellos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'FORO : Programa Integral de Calidad (Manufactura de Cigarros)', '<h2 data-path-to-node=\"2\">Espacio de Consultas: Programa Integral de Calidad (Manufactura de Cigarros)</h2>\r\n<p data-path-to-node=\"3\">¡Bienvenidos al foro de la tarea <strong>Gestión de Calidad en la Manufactura de Cigarros</strong>!</p>\r\n<p data-path-to-node=\"4\">Este espacio ha sido diseñado como un canal abierto para que compartan sus dudas, observaciones o sugerencias técnicas sobre los estándares de calidad que estamos estudiando. Ya sea que tengan preguntas sobre el proceso de fermentación, el control de humedad, la selección de capa o los parámetros de construcción del cigarro, este es el lugar ideal para discutirlos.</p>\r\n<p data-path-to-node=\"5\">El facilitador estará monitoreando activamente sus participaciones para asegurar que cada concepto —desde la semilla hasta el empaque final— quede claro y alineado con las exigencias del mercado internacional.</p>\r\n<blockquote data-path-to-node=\"6\">\r\n<p data-path-to-node=\"6,0\"><strong>&nbsp;Nota:</strong> Aprovechen este foro para el intercambio de conocimientos. En la industria del cigarro, la atención al detalle y el aprendizaje colaborativo son los pilares de la excelencia.</p>\r\n</blockquote>\r\n<hr data-path-to-node=\"7\">\r\n<h3 data-path-to-node=\"8\">&nbsp;Aviso Importante</h3>\r\n<p data-path-to-node=\"9\">Este foro es <strong>exclusivamente para aclaración de dudas y debates técnicos</strong>. Por favor, <strong>no adjunten ni envíen su tarea por este medio</strong>; asegúrense de utilizar el enlace de entrega oficial correspondiente en la plataforma.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Introducción a la Calidad en la Industria Tabacalera', '<h2 data-path-to-node=\"2\">Foro de Dudas: Introducción a la Calidad en la Industria Tabacalera</h2>\r\n<p data-path-to-node=\"3\">¡Bienvenidos al foro de discusión del primer módulo! Este espacio está dedicado a resolver cualquier inquietud sobre los fundamentos de la <strong>Calidad Total</strong> aplicados específicamente a la producción de cigarros.</p>\r\n<p data-path-to-node=\"4\">Si tienes dudas sobre los conceptos de control de procesos, la historia de los estándares de calidad en el sector o cómo la inspección sensorial influye en el producto final, este es el lugar para plantearlas. Comprender estos pilares es fundamental para garantizar que cada cigarro cumpla con las expectativas del consumidor más exigente.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Acciones Inmediatas bajo las 5S', '<h2 data-path-to-node=\"2\">Foro de Dudas: Acciones Inmediatas bajo las 5S</h2>\r\n<p data-path-to-node=\"3\">Este espacio ha sido creado para apoyar la implementación de la metodología <strong>5S</strong> (Seiri, Seiton, Seiso, Seiketsu y Shitsuke) dentro de nuestro entorno de manufactura.</p>\r\n<p data-path-to-node=\"4\">Si tienes preguntas sobre cómo aplicar estas acciones inmediatas en el área de despalillo, en las mesas de rolado o en el área de empaque, este es el lugar para compartirlas. La disciplina de las 5S es el primer paso para garantizar un ambiente de trabajo seguro y un cigarro de calidad superior.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir tareas.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: de Examen de Terminología y Principios Clave de Calidad', '<h2 data-path-to-node=\"2\">Foro de Examen de Terminología y Principios Clave de Calidad</h2>\r\n<p data-path-to-node=\"3\">Este espacio ha sido habilitado para resolver cualquier duda relacionada con el examen sobre <strong>Terminología y Principios Clave</strong> en la manufactura de cigarros. Dominar este lenguaje técnico es esencial para la comunicación efectiva dentro de la planta y para garantizar que los criterios de calidad sean uniformes en todas las etapas de producción.</p>\r\n<p data-path-to-node=\"4\">Si necesitas aclarar conceptos fundamentales antes de tomar tu evaluación, este es el lugar indicado.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: EXAMEN Sistema de Gestión de la Calidad (SGC)', '<h2 data-path-to-node=\"2\">Foro de Consultas: EXAMEN Sistema de Gestión de la Calidad (SGC)</h2>\r\n<p data-path-to-node=\"3\">Este espacio está dedicado exclusivamente a resolver dudas sobre el contenido del examen del <strong>Sistema de Gestión de la Calidad (SGC)</strong> aplicado a nuestra industria.</p>\r\n<p data-path-to-node=\"3\">El SGC es el marco que asegura que cada cigarro que sale de la galera cumpla con las especificaciones técnicas y las expectativas del cliente final de manera consistente. Si tienes preguntas sobre la estructura de los procesos, la documentación de calidad o los indicadores de desempeño (KPIs), este es el lugar para aclararlas antes de tu evaluación.</p>\r\n<p data-path-to-node=\"3\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Cálculo de Resistencia Equivalente en Circuitos en Serie y Paralelo', '');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Código de Colores de Resistencias: Función y Aplicaciones', '<p><strong data-start=\"71\" data-end=\"87\">Descripción:</strong> En esta página se explica cómo funciona el sistema de codificación por colores para resistencias, un método utilizado para identificar el valor nominal de las resistencias. También se detalla la diferencia entre resistencias de 4, 5 y 6 bandas y cómo se determina la tolerancia y el coeficiente de temperatura a partir del código de colores.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Análisis de Circuitos Mixtos: Resolución Paso a Paso', '<p><strong data-start=\"66\" data-end=\"82\">Descripción:</strong> Esta página ofrece una guía detallada sobre cómo analizar circuitos mixtos, que combinan resistencias y componentes tanto en serie como en paralelo. Se exploran las técnicas de simplificación y los pasos necesarios para resolver estos circuitos de manera eficiente.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Elementos Activos en Circuitos Eléctricos: Fuentes y Amplificadores', '<p><strong data-start=\"81\" data-end=\"97\">Descripción:</strong> Esta página ofrece una explicación detallada sobre los elementos activos en un circuito eléctrico, como las fuentes de tensión y corriente, generadores y amplificadores, y cómo desempeñan un papel crucial en la operación de los circuitos electrónicos.</p>');
