INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Documentación y Control en Producción', '<h2 data-path-to-node=\"2\">Foro de Consultas: Examen Documentación y Control en Producción</h2>\r\n<p data-path-to-node=\"3\">Este espacio ha sido habilitado para despejar cualquier duda técnica sobre el proceso de registro y control de datos en la planta. La documentación precisa es lo que permite que una liga (blend) se mantenga idéntica a través de los años y que podamos identificar cualquier desviación en la cadena de suministro.</p>\r\n<p data-path-to-node=\"4\">Si tienes preguntas sobre cómo completar los registros de producción, el control de inventarios de tabaco en rama o el manejo de las hojas de inspección de calidad, este es el lugar para consultarlo.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Gestión de Procesos y Producción', '<h2 data-path-to-node=\"2\">Foro de Consultas: Examen Gestión de Procesos y Producción</h2>\r\n<p data-path-to-node=\"3\">Este foro está dedicado a resolver dudas relacionadas con la administración de los flujos de trabajo en la manufactura de cigarros. La gestión eficiente garantiza que el tabaco fluya correctamente desde que sale del almacén de fermentación hasta que llega al área de empaque, minimizando tiempos muertos y optimizando el uso de la materia prima.</p>\r\n<p data-path-to-node=\"4\">Si tienes preguntas sobre balanceo de líneas en la galera, tiempos de reposo en el cuarto de escape o la secuencia lógica de producción, este es el espacio para discutirlas.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Buenas Prácticas de Manufactura (BPM)', '<h2 data-path-to-node=\"2\">Foro: Examen Buenas Prácticas de Manufactura (BPM)</h2>\r\n<p data-path-to-node=\"3\">Este foro ha sido habilitado para asistirles en cualquier duda relacionada con las <strong>BPM</strong> aplicadas a la industria tabacalera. En este sector, las BPM no solo garantizan un producto libre de contaminantes, sino que preservan las propiedades organolépticas (sabor y aroma) que definen a un cigarro premium.</p>\r\n<p data-path-to-node=\"4\">Si necesitan aclarar normativas sobre higiene del personal, mantenimiento de las áreas de trabajo o prevención de plagas, este es el espacio indicado para realizar sus preguntas antes de tomar el examen.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Herramientas de Calidad y SPC', '<h2 data-path-to-node=\"2\">Foro de Consultas: Examen Herramientas de Calidad y SPC</h2>\r\n<p data-path-to-node=\"3\">Este espacio está diseñado para resolver cualquier duda sobre la aplicación de las herramientas estadísticas en la industria del cigarro. El <strong>Control Estadístico de Procesos (SPC)</strong> nos permite identificar variaciones antes de que se conviertan en defectos, asegurando que el tiro, el peso y el cepo de cada unidad se mantengan dentro de los límites de control.</p>\r\n<p data-path-to-node=\"4\">Si tienes dificultades comprendiendo cómo graficar la variabilidad o cómo interpretar las herramientas básicas de calidad en el contexto de la galera, este es el lugar para preguntar.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Mejora Continua y Resolución de Problemas', '<h2 data-path-to-node=\"2\">Foro: Examen Mejora Continua y Resolución de Problemas</h2>\r\n<p data-path-to-node=\"3\">Este espacio está habilitado para resolver dudas relacionadas con las metodologías que nos permiten alcanzar la perfección en el producto final. En la manufactura de cigarros, la <strong>Mejora Continua</strong> no solo busca la eficiencia, sino la preservación de la tradición artesanal a través de procesos optimizados y libres de errores recurrentes.</p>\r\n<p data-path-to-node=\"4\">Si tienes preguntas sobre cómo aplicar ciclos de mejora en la galera de torcido o cómo estructurar una solución ante un problema de calidad en el añejamiento, este es el lugar para aclararlas.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Modelos de Excelencia y Six Sigma', '<h2 data-path-to-node=\"2\">Foro: Examen Modelos de Excelencia y Six Sigma</h2>\r\n<p data-path-to-node=\"3\">Este foro es el espacio designado para resolver dudas sobre los niveles más altos de gestión de calidad: los <strong>Modelos de Excelencia</strong> y la metodología <strong>Six Sigma</strong>. En la manufactura de cigarros de exportación, alcanzar un nivel de \"Seis Sigma\" significa que nuestros procesos de pesaje, rolado y añejamiento son tan precisos que el margen de error es prácticamente inexistente.</p>\r\n<p data-path-to-node=\"4\">Si tienes inquietudes este es el lugar para consultarlo antes de tu evaluación.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
