INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Circuitos en Serie y Paralelo', '<p>En esta página se exploran los conceptos de circuitos en serie y en paralelo, dos configuraciones fundamentales en la electrónica. Los circuitos en <strong data-start=\"233\" data-end=\"242\">serie</strong> son aquellos en los que los componentes están conectados uno tras otro, de manera que la corriente pasa a través de cada uno de ellos. En este tipo de circuito, la <strong data-start=\"407\" data-end=\"424\">tensión total</strong> se divide entre los componentes, pero la <strong data-start=\"466\" data-end=\"479\">corriente</strong> es la misma a través de todos ellos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Cálculo de Resistencia Equivalente en Circuitos en Serie y Paralelo', '');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Supervisión Activa y Gestión del Cambio', '<h2 data-path-to-node=\"2\">Foro: Examen Supervisión Activa y Gestión del Cambio</h2>\r\n<p data-path-to-node=\"3\">Este espacio ha sido habilitado para asistirles en cualquier duda técnica o conceptual sobre el rol del supervisor como motor de la calidad. En la industria tabacalera, la <strong>Supervisión Activa</strong> es el puente entre los objetivos estratégicos de la gerencia y la destreza manual de los artesanos del tabaco.</p>\r\n<p data-path-to-node=\"4\">Si necesitan aclarar estrategias para liderar equipos de torcido, cómo comunicar nuevos estándares de calidad o cómo manejar la resistencia cuando se implementan nuevas tecnologías o ligas, este es el lugar indicado.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Foro', 'Foro: Examen Análisis de Datos para la Calidad', '<h2 data-path-to-node=\"2\">Foro: Examen Análisis de Datos para la Calidad</h2>\r\n<p data-path-to-node=\"3\">Este espacio ha sido creado para resolver cualquier inquietud sobre cómo procesar, interpretar y presentar los datos obtenidos en los controles de calidad de la industria tabacalera. El análisis de datos nos permite pasar de la simple observación a la identificación de tendencias que afectan el sabor, la combustión y la rentabilidad de nuestros cigarros.</p>\r\n<p data-path-to-node=\"4\">Si tienes dudas sobre el cálculo de promedios de tiro, la desviación estándar en el peso de las vitolas o cómo interpretar una tendencia de humedad en los últimos lotes, este es el lugar para aclararlas antes de tu examen.</p>\r\n<p data-path-to-node=\"4\">🔔 Recuerda que este foro es solo para aclarar dudas. No se permite compartir respuestas del cuestionario.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Página Web (Page)', 'Transistores FET (JFET y MOSFET): Características, Funcionamiento y Comparativa', '<p>Los transistores de efecto de campo (FET), como los JFET y MOSFET, son esenciales en la electrónica por su capacidad para controlar la corriente mediante un voltaje aplicado a la puerta. El <strong data-start=\"190\" data-end=\"198\">JFET</strong> tiene una estructura simple y es ideal para amplificación de señales de bajo ruido, mientras que el <strong data-start=\"299\" data-end=\"309\">MOSFET</strong> es más eficiente y rápido, utilizado en control de potencia y aplicaciones de alta velocidad. Ambos se fabrican mediante procesos de fotolitografía y deposición de materiales semiconductores. Aunque comparten principios de operación similares, el MOSFET es más versátil y ampliamente utilizado debido a su mayor rendimiento en diversas aplicaciones.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Código de Colores de Resistencias: Función y Aplicaciones', '<p><strong data-start=\"71\" data-end=\"87\">Descripción:</strong> En esta página se explica cómo funciona el sistema de codificación por colores para resistencias, un método utilizado para identificar el valor nominal de las resistencias. También se detalla la diferencia entre resistencias de 4, 5 y 6 bandas y cómo se determina la tolerancia y el coeficiente de temperatura a partir del código de colores.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Análisis de Circuitos Mixtos: Resolución Paso a Paso', '<p><strong data-start=\"66\" data-end=\"82\">Descripción:</strong> Esta página ofrece una guía detallada sobre cómo analizar circuitos mixtos, que combinan resistencias y componentes tanto en serie como en paralelo. Se exploran las técnicas de simplificación y los pasos necesarios para resolver estos circuitos de manera eficiente.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Elementos Activos en Circuitos Eléctricos: Fuentes y Amplificadores', '<p><strong data-start=\"81\" data-end=\"97\">Descripción:</strong> Esta página ofrece una explicación detallada sobre los elementos activos en un circuito eléctrico, como las fuentes de tensión y corriente, generadores y amplificadores, y cómo desempeñan un papel crucial en la operación de los circuitos electrónicos.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Funcionamiento General de los Transistores', '<p></p>\n<p></p>\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Tipos de Transistores y su Clasificación', '<p data-start=\"0\" data-end=\"333\" class=\"\">Los <strong data-start=\"4\" data-end=\"20\">transistores</strong> son componentes electrónicos fundamentales que amplifican o conmutan señales electrónicas y son esenciales en la mayoría de los dispositivos electrónicos modernos. Existen varios tipos de transistores, y su clasificación se puede hacer de diferentes maneras, principalmente según su construcción y su aplicación.</p>\n<h3 class=\"\" data-start=\"335\" data-end=\"379\"> </h3>');
