INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Transistores BJT: Funcionamiento, Materiales y Aplicaciones', '<p>El objetivo de esta página es proporcionar una explicación exhaustiva sobre los transistores BJT (Bipolar Junction Transistor), cubriendo desde los materiales semiconductores hasta los modos de funcionamiento, configuraciones y aplicaciones.</p>');
