INSERT INTO mdlsv_adminpresets VALUES('Electrónica Básica - Segundo Grupo', 'Página Web (Page)', 'Funcionamiento del MOSFET', '<p>Este documento explora detalladamente el proceso de fabricación del MOSFET, desde la preparación del substrato hasta los procesos de grabado y pasivación. También describe su estructura interna, el mecanismo de conducción, las características eléctricas y las ventajas en comparación con otros tipos de transistores como el BJT. Además, se incluyen modelos de operación, parámetros estáticos y dinámicos, y su uso en diversas aplicaciones electrónicas.</p>');
