INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p><img src=\"@@PLUGINFILE@@/Objectivo.png\" width=\"618\" height=\"158\"></p>\r\n<p></p>\r\n<p dir=\"ltr\">Al finalizar este módulo, los estudiantes comprenderán el funcionamiento de los transistores BJT, FET y MOSFET, sus aplicaciones prácticas e importancia en los circuitos electrónicos. Serán capaces de identificar, analizar y aplicar estos dispositivos en diseños de circuitos.</p>\r\n<p><strong id=\"docs-internal-guid-3de6fc08-7fff-be78-4f9d-03280ffe1125\"></strong></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<h3 dir=\"ltr\">Unidad 1: Introducción a los Transistores</h3>\r\n<p><img src=\"@@PLUGINFILE@@/Objectivo.png\" width=\"446\" height=\"114\"></p>\r\n<p>Comprender el funcionamiento básico de los transistores, cómo surgieron y el cambio que representaron en el mundo industrial y tecnológico.</p>');
