INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<h3 dir=\"ltr\">Unidad 2: Transistor Bipolar de Unión (BJT)</h3>\r\n<p><img src=\"@@PLUGINFILE@@/Objectivo.png\" width=\"446\" height=\"114\"></p>\r\n<p dir=\"ltr\">Comprender la estructura y funcionamiento del transistor BJT, incluyendo sus principios físicos, características eléctricas y aplicaciones prácticas en circuitos electrónicos.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<h3><strong id=\"docs-internal-guid-4d831d03-7fff-c521-f8b6-be25fe28d8eb\">Unidad 4: Transistor MOSFET</strong></h3>\r\n<p></p>\r\n<p><img src=\"@@PLUGINFILE@@/Objectivo.png\" width=\"446\" height=\"114\"></p>\r\n<p dir=\"ltr\">Analizar el funcionamiento del MOSFET y sus aplicaciones tecnológicas, comprendiendo su estructura, características y aplicaciones en circuitos electrónicos modernos.</p>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Electrónica Bàsica', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<h3 dir=\"ltr\"> Unidad 3: Transistor de Efecto de Campo (FET)</h3>\r\n<p><img src=\"@@PLUGINFILE@@/Objectivo.png\" width=\"446\" height=\"114\"></p>\r\n<p dir=\"ltr\">Identificar las características del transistor FET y su diferencia con el BJT, comprendiendo su funcionamiento, aplicaciones y ventajas en circuitos electrónicos.</p>\r\n<p></p>');
