INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\">Comprender la importancia de la calidad en la industria tabacalera, su evolución y beneficios.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Introducción a la calidad</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Objetivos de la calidad</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">La calidad en productos de tabaco</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Evolución y teorías de la calidad</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765910632925\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Pensamiento crítico: ¿Por qué? Para analizar cómo la calidad impacta en cada etapa del proceso.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Comunicación efectiva: ¿Por qué? Para transmitir la importancia de la calidad al equipo de trabajo.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<h3><strong id=\"docs-internal-guid-b21377c9-7fff-ab74-dedc-2a41edcbb566\">Importancia de la calidad en las organizaciones</strong></h3>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<h3><strong id=\"docs-internal-guid-75d68b89-7fff-0071-232f-2004177e0d71\">La calidad en la industria tabacalera </strong></h3>');
