INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p></p>\r\n<p><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p6.png?1765910861817\" alt=\"\" width=\"400\" height=\"96\"></p>\r\n<ul>\r\n<li>Calidad, Evaluación de calidad, Mejora Continua</li>\r\n<li>Planificación estratégica, Benchmarking, Reingeniería de procesos</li>\r\n<li>Análisis FODA, Ciclo PDCA, ISO, 5S</li>\r\n</ul>\r\n<p></p>\r\n<p><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p7.png\" alt=\"\" width=\"400\" height=\"94\"></p>\r\n<ul>\r\n<li dir=\"ltr\" role=\"presentation\">Enfoque al Cliente, Liderazgo, Participación del Personal</li>\r\n<li dir=\"ltr\" role=\"presentation\">Enfoque Basado en Procesos</li>\r\n<li dir=\"ltr\" role=\"presentation\">Toma de Decisiones Basada en Hechos, Relaciones con Proveedores</li>\r\n</ul>');
