INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\">Manejar los conceptos básicos y principios fundamentales de la gestión de la calidad en tabaco.</p>\r\n<p dir=\"ltr\" role=\"presentation\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p6.png?1765975235701\" alt=\"\" width=\"400\" height=\"96\"></p>\r\n<ul>\r\n<li style=\"list-style-type: none;\">\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Calidad, Evaluación de calidad, Mejora Continua</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Planificación estratégica, Benchmarking, Reingeniería de procesos</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis FODA, Ciclo PDCA, ISO, 5S</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ul>\r\n<p><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p7.png?1765975194726\" alt=\"\" width=\"400\" height=\"94\"></p>\r\n<ul>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Enfoque al Cliente, Liderazgo, Participación del Personal</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Enfoque Basado en Procesos</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"2\">\r\n<p dir=\"ltr\" role=\"presentation\">Toma de Decisiones Basada en Hechos, Relaciones con Proveedores</p>\r\n</li>\r\n</ul>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<h3 dir=\"ltr\">Comprender la estructura y aplicación del SGC basado en ISO 9001:2015 en la fabricación de cigarros.</h3>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Conceptos, beneficios y requisitos del SGC</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">ISO 9001:2015 adaptada a cigarros</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Implantación práctica del SGC</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Políticas y Manual de Calidad</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Sistemas Integrados de Gestión (SIG) en la Industria Tabacalera</p>\r\n</li>\r\n</ul>\r\n<p></p>\r\n<p><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765908164500\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Liderazgo: ¿Por qué? Para impulsar la adopción del SGC en todos los niveles.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Trabajo en equipo: ¿Por qué? Porque la implementación exitosa requiere colaboración.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\">Garantizar la correcta gestión documental para la trazabilidad y mejora continua.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Objetivos y beneficios de la documentación</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Sistema documental basado en normas ISO</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Buenas prácticas de documentación en manufactura</p>\r\n</li>\r\n</ul>\r\n<p></p>\r\n<p></p>\r\n<p dir=\"ltr\"><strong><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765913525358\" alt=\"\" width=\"400\" height=\"99\"></strong></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Atención al detalle: ¿Por qué? Para evitar errores en registros que impacten la calidad.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Responsabilidad: ¿Por qué? Porque la trazabilidad depende del compromiso en la documentación.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\"><strong> </strong>Aplicar controles efectivos en procesos críticos para mantener la calidad del producto.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Diseño y provisión de productos</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Control de procesos críticos (humedad, corte, empaquetado)</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Control de calidad en línea:</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Dispositivos Poka-Yoke, Autocomprobación, Jidoka</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Resolución de problemas: ¿Por qué? Para reaccionar ante desviaciones en el proceso.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Proactividad: ¿Por qué? Para prevenir fallos antes de que impacten en la calidad.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
