INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p><img class=\"img-fluid\" style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"@@PLUGINFILE@@/Introducci%C3%B3n%20y%20Prop%C3%B3sito%20del%20Programa%20%289%29.png\" alt=\"hola\" width=\"932\" height=\"466\"></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\"><strong> </strong>Implementar prácticas que garanticen inocuidad, limpieza y control en la producción.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Higiene y sanitización</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Instalaciones y equipos adecuados</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Control de materias primas</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Procesos estándar documentados</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gestión de residuos y medio ambiente</p>\r\n</li>\r\n</ul>\r\n<p></p>\r\n<p dir=\"ltr\" role=\"presentation\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765908785730\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Compromiso con la calidad: ¿Por qué? Porque la BPM depende de la conducta responsable de cada trabajador.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Trabajo colaborativo: ¿Por qué? Para mantener la disciplina en todas las áreas.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\"> Utilizar herramientas estadísticas y gráficas para controlar y mejorar los procesos.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">7 herramientas de calidad (Hoja de datos, Pareto, Causa-efecto, etc.)</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gráficos de control por variables y atributos</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Técnicas de muestreo y análisis de alarmas</p>\r\n</li>\r\n</ul>\r\n<p></p>\r\n<p><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765908713122\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Pensamiento lógico: ¿Por qué? Para interpretar datos y tomar decisiones.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Orientación a resultados: ¿Por qué? Porque el análisis estadístico se enfoca en mejorar la eficiencia.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\"> Aplicar metodologías para identificar, analizar y corregir problemas.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Análisis de causa raíz (Ishikawa, 5 porqués)</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Ciclo PDCA y CAPA</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Técnicas de resolución de problemas</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Reporte A3 para mejoras</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765909403752\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Pensamiento crítico: ¿Por qué? Para cuestionar el origen de los problemas.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Creatividad: ¿Por qué? Para proponer soluciones efectivas e innovadoras.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\"> Introducir modelos de excelencia y metodologías avanzadas de mejora.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Modelo EFQM aplicado a tabaco</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Metodología Six Sigma (DMAIC)</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Aplicación práctica en procesos tabacaleros</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765909581120\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Orientación estratégica: ¿Por qué? Para comprender la mejora continua a nivel organizacional.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Toma de decisiones basada en datos: ¿Por qué? Para sustentar acciones en hechos y análisis.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\">Desarrollar habilidades para liderar equipos y manejar cambios en procesos.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Conceptos de supervisión activa</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Herramientas para gestión del cambio</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Liderazgo en entornos dinámicos</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765909696841\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<p dir=\"ltr\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Liderazgo adaptativo: ¿Por qué? Para guiar al equipo durante cambios en procesos.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Gestión emocional: ¿Por qué? Porque el cambio genera resistencia y requiere empatía.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
