INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p dir=\"ltr\"> Manejar herramientas digitales para análisis y visualización de datos.</p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Excel: herramientas y gráficos para control de calidad</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Power BI para análisis dinámico</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Introducción a Minitab para control estadístico</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\"></p>\r\n<p dir=\"ltr\"><img class=\"img-fluid\" role=\"presentation\" src=\"@@PLUGINFILE@@/p5.png?1765909814195\" alt=\"\" width=\"400\" height=\"99\"></p>\r\n<p dir=\"ltr\"></p>\r\n<ul>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Capacidad de aprendizaje: ¿Por qué? Para adaptarse a herramientas digitales.</p>\r\n</li>\r\n<li dir=\"ltr\" aria-level=\"1\">\r\n<p dir=\"ltr\" role=\"presentation\">Orientación tecnológica: ¿Por qué? Porque el análisis de datos es clave en la toma de decisiones.</p>\r\n</li>\r\n</ul>\r\n<p></p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p>El <strong>\"Programa Integral de Calidad para la Industria de Manufactura de Cigarros, La Aurora\" </strong>es una iniciativa de capacitación diseñada para estandarizar y elevar los niveles de calidad en todas las etapas de la producción de cigarros. Su objetivo primordial es Comprender la importancia de <a class=\"autolink\" title=\"la Calidad en la Industria Tabacalera\" href=\"https://lasaedu.t-ecogroup.net/mod/assign/view.php?id=1112\">la calidad en la industria tabacalera</a>, su evolución y beneficios. El programa busca dotar a los participantes con conocimientos teóricos y, más crucialmente, con habilidades prácticas y blandas necesarias para implementar un Sistema de Gestión de la Calidad (SGC) robusto y una cultura de mejora continua.</p>');
INSERT INTO mdlsv_adminpresets VALUES('Programa Integral de Calidad para la Industria de Manufactura de Cigarros', 'Etiqueta (Texto visible)', '(Sin Título - Texto Directo)', '<p data-path-to-node=\"3\">Estimados colegas y futuros líderes de la calidad,</p>\r\n<p data-path-to-node=\"4\">Es un verdadero placer darles la bienvenida a este <strong>Programa Integral de Calidad</strong>, una iniciativa diseñada específicamente para elevar los estándares de excelencia en cada paso de nuestra producción de cigarros. Nuestro Propósito</p>\r\n<p data-path-to-node=\"6\">En un mercado que valora la tradición, la artesanía y la consistencia, la calidad no es solo una meta, es la base de nuestra reputación.</p>\r\n<p data-path-to-node=\"7\"><strong>El objetivo primordial de este programa es:</strong></p>\r\n<blockquote data-path-to-node=\"8\">\r\n<p data-path-to-node=\"8,0\"><strong>Estandarizar y elevar los niveles de calidad</strong> en todas las etapas de la producción de cigarros, dotándolos a ustedes, nuestros participantes clave, con los conocimientos teóricos, las habilidades prácticas y las competencias blandas necesarias para construir una cultura de <strong>mejora continua</strong>.</p>\r\n</blockquote>\r\n<h3 data-path-to-node=\"9\">Lo que Lograremos Juntos</h3>');
